INSERT INTO `answers` (`answer_id`, `query_id`, `answer_text`, `created_at`, `edited_at`, `deleted_at`) VALUES
(1, 26, 'Berdasarkan **Excerpt 4** dari dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf* (halaman 12), mata kuliah pendukung untuk PBL Semester 1 adalah:\n\n1.  **IF101 – Pengantar Proyek Perangkat Lunak**: Induk PBL yang mengajarkan dasar manajemen proyek, kerja tim, dan keterampilan presentasi.\n2.  **IF102 – Pengantar Teknologi Informasi**: Membantu mahasiswa terbiasa dengan *tools* perkantoran, konsep berpikir komputasional, dan pemahaman dasar perangkat lunak.\n3.  **IF103 – Dasar Pemrograman Web**: Memberikan dasar HTML, CSS, dan JavaScript untuk membangun antarmuka pengguna (*front-end*).\n4.  **IF104 – Dasar Pemrograman**: Melatih logika dan algoritma pemrograman.\n5.  **IF105 – Sistem Komputer**: Mengajarkan instalasi aplikasi, penggunaan sistem operasi, dan perintah dasar di terminal/*command line*.', '2026-06-04 03:43:23', '2026-06-04 03:43:23', NULL),
(2, 27, 'Berdasarkan **Excerpt 1 (BAB 1 PENDAHULUAN DAN KONSEP DASAR PBL, subbab 1.2 Tujuan PBL)**, tujuan akademik dari *Project-Based Learning* (PBL) adalah sebagai berikut:\n\n1. Mengintegrasikan pengetahuan teoritis dari berbagai mata kuliah ke dalam praktik nyata.\n2. Meningkatkan pemahaman mahasiswa terhadap siklus pengembangan perangkat lunak.\n3. Melatih kemampuan analisis dan perancangan sistem.\n4. Membiasakan mahasiswa dengan standar dan praktik terbaik (*best practices*) dalam pengembangan perangkat lunak.', '2026-06-04 03:44:55', '2026-06-04 03:44:55', NULL),
(3, 28, 'Berdasarkan dokumen **Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf**, syarat untuk dapat mengikuti sesi presentasi Asesmen Akhir Semester (AAS) adalah sebagai berikut:\n\n1.  **Kelengkapan Berkas:** Mahasiswa wajib memastikan semua file luaran AAS telah diunggah secara lengkap di platform Siap-PBL sebelum batas waktu yang ditentukan. Kelengkapan berkas ini menjadi prasyarat utama untuk dapat mengikuti sesi presentasi asesmen (halaman 21).\n2.  **Persetujuan Manajer Proyek (Manpro):** Sebelum mengunggah luaran, Manajer Proyek wajib memberikan *review progress* dan *feedback* melalui fitur di Siap-PBL. Menu unggah berkas baru akan aktif setelah Manpro memberikan *review* tersebut (halaman 21).\n3.  **Ketepatan Waktu:** Mahasiswa yang tidak mengumpulkan luaran hingga batas waktu yang ditetapkan tidak akan dijadwalkan untuk presentasi (halaman 21).\n\nSelain itu, secara umum untuk kegiatan asesmen (ATS dan AAS), mahasiswa juga diwajibkan mengenakan pakaian berupa kemeja putih, bawahan gelap, dan almamater (halaman 17).', '2026-06-04 03:53:54', '2026-06-04 03:53:54', NULL),
(4, 29, 'Berdasarkan **Tabel 6. Luaran AAS** pada halaman 19 dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf*, luaran yang wajib dikumpulkan pada Asesmen Akhir Semester (AAS) untuk semester 4 adalah:\n\n1.  **File Presentasi:** Slide presentasi final.\n2.  **Laporan Akhir PBL:** Sesuai template di Learning.\n3.  **Poster:** Ukuran A2, portrait, format PDF, dalam Bahasa Inggris.\n4.  **Manual Book:** Format PDF, Bahasa Indonesia, 5-15 halaman.\n5.  **Berita Acara Serah Terima (BAST):** Menggunakan format FO.5.3.1-V5.\n6.  **Video Presentasi:** Maksimal 10 menit, menggunakan Bahasa Inggris, rekaman langsung dalam satu ruangan, diunggah ke YouTube Public dengan deskripsi yang memuat judul proyek, deskripsi proyek, nama dan NIM seluruh anggota tim, serta alamat email ketua kelompok.\n7.  **Video Demo:** Maksimal 3 menit, kualitas 720p, diunggah ke YouTube.\n8.  **Produk PBL (Source Code):** Disimpan dalam repository di GitHub.\n9.  **Dokumen HKI:** Bersifat opsional, sesuai rekomendasi Manpro.', '2026-06-04 03:59:31', '2026-06-04 03:59:31', NULL),
(5, 30, 'Berdasarkan dokumen yang disediakan, pembatalan atau konsekuensi tidak dijadwalkan untuk presentasi (yang mengakibatkan tidak mendapatkan nilai asesmen) disebabkan oleh hal berikut:\n\nMahasiswa **tidak mengumpulkan luaran hingga batas waktu yang ditetapkan**.\n\nHal ini tercantum dalam **Excerpt 1 (Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf, p.21)** pada bagian \"Hal-hal yang Perlu Diperhatikan\", poin kedua:\n> \"Kedua, mahasiswa yang tidak mengumpulkan luaran hingga batas waktu yang ditetapkan tidak akan dijadwalkan untuk presentasi dan konsekuensinya tidak akan mendapatkan nilai asesmen.\"', '2026-06-04 06:39:21', '2026-06-04 06:39:21', NULL),
(6, 31, 'Berdasarkan **Pedoman Pembelajaran T.A 2025 (Excerpt 1, p.15)**, Pasal 11 ayat (1), penerimaan seorang mahasiswa baru Polibatam akan dibatalkan jika yang bersangkutan terbukti:\n\na. Pernah terdaftar tetapi tidak diperkenankan lagi melanjutkan pendidikan di Polibatam karena melakukan kecurangan atau pelanggaran;\nb. Melakukan pemalsuan dokumen persyaratan seleksi penerimaan mahasiswa baru; atau\nc. Melakukan kecurangan pada saat pelaksanaan ujian saringan masuk.', '2026-06-04 06:55:40', '2026-06-04 06:55:40', NULL),
(7, 32, 'Berdasarkan **Pasal 24** dalam **Bab VII (Cuti Akademik dan Penghentian Studi)** pada dokumen *Pedoman_Pembelajaran_T.A_2025.pdf*, berikut adalah syarat dan ketentuan untuk melakukan cuti akademik:\n\n1.  **Minimal Masa Studi:** Mahasiswa telah menyelesaikan minimal 1 (satu) tahun studi.\n2.  **Jadwal Pengajuan:** Pengajuan dilakukan sesuai dengan jadwal yang telah ditentukan.\n3.  **Waktu Pengajuan:** Pengajuan tidak diperkenankan setelah masa perkuliahan berjalan, kecuali dalam kondisi yang tidak memungkinkan dan telah mendapat persetujuan dari dosen wali serta kepala program studi atau ketua jurusan.\n4.  **Prosedur:** Mahasiswa wajib mengajukan permohonan cuti melalui sistem informasi dan layanan mahasiswa (SILAM) pada laman https://sim.polibatam.ac.id.\n\nSelain itu, perlu diperhatikan bahwa mahasiswa yang sedang mengambil cuti akademik **tidak memenuhi syarat administratif** untuk mengajukan permohonan beasiswa (sebagaimana tercantum dalam Pasal 10 Ayat 2c).', '2026-06-04 06:57:06', '2026-06-04 06:57:06', NULL),
(8, 33, 'Berdasarkan dokumen yang diberikan, penghentian studi di Polibatam dapat disebabkan oleh hal-hal berikut:\n\n1.  **Pengunduran diri:** Mahasiswa dapat mengajukan pengunduran diri, yang mana mekanisme ini dapat dilakukan oleh Polibatam dengan mempertimbangkan kemampuan akademik mahasiswa agar tidak menghambat kemungkinan melanjutkan studi di perguruan tinggi lain (Excerpt 1, Pasal 25 ayat 1).\n2.  **Melewati batas waktu masa studi:** Mahasiswa yang terbukti tidak dapat menyelesaikan studinya pada batas waktu maksimal masa studi tidak diperkenankan melanjutkan studinya di Polibatam (Excerpt 1, Pasal 25 ayat 2).\n3.  **Ketidakhadiran tanpa izin:** Mahasiswa yang telah menerima Surat Peringatan (SP) III dan tidak memberikan tanggapan dalam jangka waktu 3 (tiga) minggu sejak surat dikirimkan akan dianggap mengundurkan diri, dan selanjutnya akan diterbitkan surat pemberhentian (Excerpt 2, Pasal 20 ayat 9).', '2026-06-04 07:27:00', '2026-06-04 07:27:00', NULL),
(9, 34, '', '2026-06-04 08:16:05', '2026-06-04 08:16:05', NULL),
(10, 35, '', '2026-06-04 08:16:58', '2026-06-04 08:16:58', NULL),
(11, 36, 'Berdasarkan **Excerpt 4** pada dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf* (halaman 12), mata kuliah pendukung untuk PBL Semester 1 adalah sebagai berikut:\n\n1.  **IF101 – Pengantar Proyek Perangkat Lunak** (Induk PBL Semester 1)\n2.  **IF102 – Pengantar Teknologi Informasi**\n3.  **IF103 – Dasar Pemrograman Web**\n4.  **IF104 – Dasar Pemrograman**\n5.  **IF105 – Sistem Komputer**', '2026-06-04 08:17:30', '2026-06-04 08:17:30', NULL),
(12, 37, '', '2026-06-04 08:34:43', '2026-06-04 08:34:43', NULL),
(13, 38, 'Berdasarkan **Pedoman Pembelajaran T.A 2025, Pasal 10 (halaman 37)**, syarat untuk mendapatkan beasiswa terdiri dari kriteria mahasiswa dan persyaratan administratif sebagai berikut:\n\n**1. Kriteria Mahasiswa (memenuhi satu atau lebih):**\n*   Berprestasi akademik tinggi;\n*   Tidak ditunjang oleh keadaan ekonomi yang memadai;\n*   Aktif dalam kegiatan kemahasiswaan;\n*   Kriteria lain yang diberikan oleh pemberi beasiswa.\n\n**2. Persyaratan Administratif:**\n*   Terdaftar sebagai mahasiswa aktif pada semester berjalan dan menunjukkan Kartu Tanda Mahasiswa (KTM) yang berlaku;\n*   Memiliki IPK yang memenuhi syarat yang ditetapkan untuk setiap jenis beasiswa;\n*   Tidak sedang atau mengambil cuti akademik;\n*   Tidak terkena kasus atau sanksi akademik dan/atau administratif.\n\nSelain itu, permohonan beasiswa harus dilaksanakan sesuai prosedur dan ketentuan yang berlaku melalui sistem informasi dan layanan mahasiswa (SILAM).', '2026-06-04 08:36:21', '2026-06-04 08:36:21', NULL),
(14, 39, 'Berdasarkan **Pedoman Pembelajaran T.A 2025 (Excerpt 1, Pasal 12)**, penetapan mahasiswa sebagai penerima beasiswa dilakukan melalui tahapan berikut:\n\n1.  **Seleksi:** Pemilihan dan seleksi calon penerima beasiswa dilakukan oleh tim yang ditetapkan oleh Direktur.\n2.  **Pengesahan:** Pemohon beasiswa yang telah terpilih akan disahkan sebagai penerima beasiswa melalui surat keputusan Direktur.', '2026-06-04 09:04:48', '2026-06-04 09:04:48', NULL),
(15, 40, 'Berdasarkan dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf* (halaman 12), mata kuliah pendukung untuk PBL Semester 1 adalah sebagai berikut:\n\n1.  **IF101 – Pengantar Proyek Perangkat Lunak**: Induk PBL Semester 1 yang mengajarkan dasar-dasar manajemen proyek, cara kerja tim, dan keterampilan presentasi.\n2.  **IF102 – Pengantar Teknologi Informasi**: Membantu mahasiswa terbiasa dengan *tools* perkantoran, konsep berpikir komputasional, dan pemahaman dasar perangkat lunak.\n3.  **IF103 – Dasar Pemrograman Web**: Memberikan dasar HTML, CSS, dan JavaScript untuk membangun antarmuka pengguna (*front-end*).\n4.  **IF104 – Dasar Pemrograman**: Melatih logika dan algoritma pemrograman untuk menulis kode aplikasi.\n5.  **IF105 – Sistem Komputer**: Mengajarkan instalasi aplikasi, penggunaan sistem operasi, dan perintah dasar di terminal/command line.', '2026-06-05 08:57:13', '2026-06-05 08:57:13', NULL),
(16, 44, 'Mohon maaf, kata kunci \"tes\" yang Anda berikan tidak memiliki konteks atau pertanyaan yang spesifik. Silakan ajukan pertanyaan terkait dokumen yang tersedia agar saya dapat membantu Anda.', '2026-06-05 09:08:18', '2026-06-05 09:08:18', NULL),
(17, 45, 'Mohon maaf, kata kunci \"tes\" yang Anda berikan tidak memiliki konteks atau pertanyaan spesifik yang dapat saya jawab berdasarkan dokumen yang tersedia. Silakan ajukan pertanyaan terkait isi dokumen tersebut agar saya dapat membantu Anda.', '2026-06-05 09:18:03', '2026-06-05 09:18:03', NULL),
(18, 46, 'Mohon maaf, kata kunci \"tes\" yang Anda berikan tidak memiliki konteks atau pertanyaan spesifik yang dapat saya jawab berdasarkan dokumen yang tersedia.\n\nJika Anda memiliki pertanyaan terkait panduan PBL (Project Based Learning) atau pedoman pembelajaran di Politeknik Negeri Batam, silakan ajukan pertanyaan tersebut agar saya dapat membantu Anda mencarikan informasinya.', '2026-06-05 16:14:36', '2026-06-05 16:14:36', NULL),
(19, 47, 'Berdasarkan dokumen **Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf** (halaman 13, 14, dan 15), mata kuliah yang terdapat pada Semester 3 adalah sebagai berikut:\n\n**Mata Kuliah PBL:**\n*   **IF314 – Proyek Inovasi Agile** (Induk PBL Semester 3)\n\n**Mata Kuliah Pendukung:**\n*   **IF315 – Rekayasa Perangkat Lunak Lanjut**\n*   **IF316 – Mata Kuliah Pilihan 1**\n*   **IF317 – Interaksi Manusia dan Komputer (IMK)**\n*   **IF318 – Statistika**\n*   **PK1IF – Pendidikan Agama**\n*   **PK3IF – Pendidikan Kewarganegaraan**', '2026-06-05 16:50:54', '2026-06-05 16:50:54', NULL),
(20, 48, 'Mohon maaf, pertanyaan Anda tidak jelas. Silakan ajukan pertanyaan spesifik terkait dokumen yang telah disediakan agar saya dapat membantu Anda.', '2026-06-06 06:16:09', '2026-06-06 06:16:09', NULL),
(21, 49, 'Berdasarkan **Excerpt 1 (Pedoman Pembelajaran T.A 2025, Pasal 24)**, syarat dan ketentuan untuk mengajukan cuti akademik adalah sebagai berikut:\n\n1.  **Masa Studi:** Mahasiswa telah menyelesaikan minimal 1 (satu) tahun studi.\n2.  **Jadwal:** Pengajuan dilakukan sesuai dengan jadwal yang telah ditentukan.\n3.  **Prosedur:** Mengajukan permohonan cuti melalui sistem informasi dan layanan mahasiswa (SILAM) pada laman https://sim.polibatam.ac.id.\n4.  **Waktu Pengajuan:** Pengajuan tidak diperkenankan setelah masa perkuliahan berjalan, kecuali dalam kondisi yang tidak memungkinkan dan telah mendapat persetujuan dosen wali serta kepala program studi atau ketua jurusan.\n5.  **Ketentuan Khusus:** Jika mahasiswa mengajukan cuti karena alasan kesulitan ekonomi atau alasan lain yang dapat diterima setelah menerima SP III (terkait ketidakhadiran), maka mahasiswa tersebut dapat mengajukan cuti.\n\nSelain itu, perlu diperhatikan bahwa masa cuti akademik memiliki batas waktu sebagai berikut:\n*   2 (dua) semester untuk program Diploma Tiga;\n*   4 (dua) semester untuk program Sarjana Terapan; dan\n*   1 (satu) semester untuk program Diploma Dua, Profesi, dan Magister Terapan.', '2026-06-06 07:10:19', '2026-06-06 07:10:19', NULL),
(22, 50, 'Berdasarkan dokumen yang disediakan, informasi mengenai mata kuliah hanya tersedia untuk **Semester 2**. Tidak ada informasi mengenai daftar mata kuliah untuk Semester 1 dalam dokumen tersebut.\n\nBerikut adalah mata kuliah pendukung untuk **Semester 2** (PBL: IF207 – Proyek Pembuatan Prototipe) sebagaimana tercantum dalam **Excerpt 1**:\n\n1.  **IF207 – Proyek Pembuatan Prototipe** (Induk PBL Semester 2)\n2.  **IF208 – Dasar Rekayasa Perangkat Lunak**\n3.  **IF210 – Pemrograman Web**\n4.  **IF211 – Basis Data**\n5.  **IF212 – Pemrograman Berorientasi Objek**\n6.  **IF213 – Bahasa Inggris untuk Komunikasi**', '2026-06-06 07:10:39', '2026-06-06 07:10:39', NULL),
(23, 51, 'Berdasarkan dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf* (halaman 12), mata kuliah pendukung untuk PBL Semester 1 adalah:\n\n1. **IF101 – Pengantar Proyek Perangkat Lunak** (Induk PBL)\n2. **IF102 – Pengantar Teknologi Informasi**\n3. **IF103 – Dasar Pemrograman Web**\n4. **IF104 – Dasar Pemrograman**\n5. **IF105 – Sistem Komputer**', '2026-06-06 07:11:04', '2026-06-06 07:11:04', NULL),
(24, 52, 'Berdasarkan dokumen yang disediakan, informasi mengenai mata kuliah hanya tersedia untuk **Semester 2**. Tidak ada informasi mengenai daftar mata kuliah untuk Semester 1 dalam dokumen tersebut.\n\nBerikut adalah mata kuliah pendukung untuk **PBL Semester 2** (sebagaimana tercantum dalam *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf*, p.13):\n\n1.  **IF207 – Proyek Pembuatan Prototipe** (Induk PBL Semester 2)\n2.  **IF208 – Dasar Rekayasa Perangkat Lunak**\n3.  **IF210 – Pemrograman Web**\n4.  **IF211 – Basis Data**\n5.  **IF212 – Pemrograman Berorientasi Objek**\n6.  **IF213 – Bahasa Inggris untuk Komunikasi**', '2026-06-06 07:19:22', '2026-06-06 07:19:22', NULL),
(25, 53, 'Berdasarkan **Pasal 9 ayat (3)** dalam **Pedoman Pembelajaran T.A 2025 (halaman 14)**, rencana mahasiswa tersebut **sesuai** dengan aturan pemenuhan masa dan beban belajar, dengan rincian sebagai berikut:\n\n1.  **Pembelajaran di luar program studi dalam lingkungan Polibatam:** Mahasiswa diperbolehkan mengambil 1 semester atau setara dengan **20 SKS** (Pasal 9 ayat 3 huruf a).\n2.  **Pembelajaran di luar program studi (di perguruan tinggi lain):** Mahasiswa diperbolehkan mengikuti pembelajaran paling lama 2 semester atau setara dengan **40 SKS** (Pasal 9 ayat 3 huruf b).\n\n**Kesimpulan:**\nRencana mahasiswa tersebut memenuhi ketentuan karena total beban belajar yang diakui melalui mekanisme tersebut adalah 60 SKS (20 SKS di lingkungan Polibatam dan 40 SKS di perguruan tinggi lain), yang sesuai dengan batasan maksimal yang diatur dalam Pasal 9 ayat (3) dokumen tersebut.', '2026-06-06 08:30:33', '2026-06-06 08:30:33', NULL),
(26, 54, 'Berdasarkan **Pasal 31** dalam dokumen *Pedoman_Pembelajaran_T.A_2025.pdf* (halaman 24), berikut adalah perbandingan persyaratan kelulusan dan predikat \"Dengan Pujian\" antara Program Sarjana Terapan dan Program Magister Terapan:\n\n### 1. Persyaratan Kelulusan\nUntuk dapat ditetapkan yudisium, mahasiswa dari kedua program harus memenuhi ketentuan umum (seperti lulus semua mata kuliah, bebas masalah administrasi/fasilitas, dan pemutakhiran data), namun terdapat perbedaan pada standar nilai dan IPK:\n\n*   **Nilai Minimal Mata Kuliah:**\n    *   **Sarjana Terapan:** Minimal nilai **D**.\n    *   **Magister Terapan:** Minimal nilai **C**.\n*   **Indeks Prestasi Kumulatif (IPK) Minimal:**\n    *   **Sarjana Terapan:** Minimal **2.00**.\n    *   **Magister Terapan:** Minimal **3.00**.\n\n### 2. Predikat \"Dengan Pujian\"\nPredikat \"Dengan Pujian\" diberikan jika mahasiswa memenuhi syarat IPK tertentu dan menyelesaikan pendidikan tepat waktu sesuai masa tempuh kurikulum. Perbedaannya adalah sebagai berikut:\n\n*   **Syarat IPK untuk \"Dengan Pujian\":**\n    *   **Sarjana Terapan:** IPK **> 3.50**.\n    *   **Magister Terapan:** IPK **> 3.75**.\n*   **Ketentuan Waktu:**\n    *   Kedua program sama-sama mensyaratkan penyelesaian pendidikan sesuai dengan waktu tempuh kurikulum. Jika mahasiswa menyelesaikan pendidikan lebih dari waktu tempuh kurikulum, maka predikat yang diberikan adalah \"Sangat Memuaskan\".\n\n### Ringkasan Perbedaan\n| Kriteria | Sarjana Terapan | Magister Terapan |\n| :--- | :--- | :--- |\n| Nilai Minimal Lulus | D | C |\n| IPK Minimal | 2.00 | 3.00 |\n| IPK untuk \"Dengan Pujian\" | > 3.50 | > 3.75 |', '2026-06-06 09:07:32', '2026-06-06 09:07:32', NULL),
(27, 55, 'Berdasarkan **Pasal 16 ayat (2)** dalam **Excerpt 1 (Pedoman_Pembelajaran_T.A_2025.pdf, p.17)**, mahasiswa yang tidak melakukan daftar ulang lebih dari 2 kali secara berturut-turut, setelah dilakukan verifikasi dengan melibatkan wali akademik, maka mahasiswa yang bersangkutan dinyatakan **mengundurkan diri sebagai mahasiswa** dan akan diterbitkan surat pengunduran diri oleh Polibatam.\n\nStatus nonaktif selama satu semester sebelumnya tidak mengubah ketentuan tersebut, karena aturan pengunduran diri berlaku bagi mahasiswa yang tidak melakukan daftar ulang lebih dari 2 kali secara berturut-turut.', '2026-06-06 09:32:06', '2026-06-06 09:32:06', NULL),
(28, 56, 'Berdasarkan dokumen yang diberikan, hubungan antara CPL, mata kuliah, metode pembelajaran PBL, dan sistem penilaian dalam mendukung pencapaian kompetensi lulusan dapat dijelaskan sebagai berikut:\n\n**1. Hubungan Antar Komponen:**\n*   **CPL dan Mata Kuliah:** Capaian Pembelajaran Lulusan (CPL) disusun ke dalam mata kuliah, di mana setiap mata kuliah memiliki Capaian Pembelajaran Mata Kuliah (CPMK) yang berkontribusi langsung pada pencapaian CPL tersebut (*Pedoman_Pembelajaran_T.A_2025.pdf, Pasal 2, ayat 8-9*).\n*   **PBL sebagai Wahana Pencapaian:** *Project-Based Learning* (PBL) berfungsi sebagai wahana utama untuk mencapai profil lulusan. PBL mengintegrasikan kompetensi teknis dari berbagai mata kuliah (seperti rekayasa perangkat lunak, basis data, dan jaringan) ke dalam satu proyek utuh yang autentik (*Panduan_PBL_Prodi_IF, hal. 8-9*).\n*   **Sistem Penilaian:** Penilaian hasil belajar (termasuk untuk PBL) dilakukan untuk mengukur ketercapaian CPL. Komponen penilaian mencakup penguasaan *personal* dan *interpersonal skills* yang disesuaikan dengan standar program studi, dan hasil akhirnya direkapitulasi untuk menentukan ketercapaian CPL mahasiswa (*Pedoman_Pembelajaran_T.A_2025.pdf, Pasal 27, ayat 6-7*).\n\n**2. Bagaimana Keempat Komponen Saling Mendukung:**\nKeempat komponen tersebut membentuk ekosistem pembelajaran yang saling mendukung untuk membangun kompetensi lulusan melalui pendekatan tiga lapis (*Panduan_PBL_Prodi_IF, hal. 9*):\n\n*   **Landasan Konseptual (Teori):** Memberikan pemahaman \"mengapa\" dan \"apa\" dari suatu materi di kelas.\n*   **Keterampilan Dasar (Praktikum):** Memberikan latihan terstruktur untuk menguasai \"bagaimana\" menerapkan teori secara terkontrol.\n*   **Penerapan Autentik (PBL):** Menjadi wadah integrasi di mana mahasiswa memecahkan masalah nyata yang kompleks. PBL melatih mahasiswa menjadi pembelajar mandiri, mengasah keterampilan interpersonal (kolaborasi, komunikasi, kepemimpinan), dan memberikan simulasi dunia kerja.\n*   **Validasi Kompetensi (Sistem Penilaian):** Melalui instrumen penilaian (seperti rubrik yang mengukur deskripsi spesifik kemampuan mahasiswa), dosen dapat memastikan bahwa proses pembelajaran yang telah dilalui (teori, praktikum, dan PBL) benar-benar menghasilkan kompetensi yang sesuai dengan standar CPL yang telah ditetapkan.\n\nDengan demikian, mata kuliah menjadi wadah kurikulum, PBL menjadi metode untuk mengintegrasikan teori dan praktik ke dalam pengalaman nyata, dan sistem penilaian berfungsi sebagai alat ukur untuk memastikan bahwa seluruh proses tersebut berhasil mencapai CPL yang ditargetkan bagi lulusan.', '2026-06-06 09:33:09', '2026-06-06 09:33:09', NULL),
(29, 57, 'Berdasarkan dokumen yang disediakan, berikut adalah penjelasan terkait status mahasiswa tersebut:\n\n**Status Kelanjutan Studi**\nBerdasarkan **Pasal 31 ayat (1) huruf d** (Excerpt 3), syarat untuk penetapan yudisium (kelulusan) bagi program Sarjana Terapan adalah memiliki **IPK minimal 2.00**. Namun, dokumen tersebut tidak secara eksplisit mengatur mengenai pemberhentian studi mahasiswa aktif berdasarkan IPK di tengah masa studi, melainkan mengatur mengenai sanksi administratif/skorsing atau pengunduran diri akibat ketidakhadiran (Excerpt 4, Pasal 24 ayat 6b dan Pasal 20 ayat 9).\n\n**Mekanisme dan Pihak yang Berwenang**\nMengenai mekanisme dan pihak yang berwenang dalam situasi khusus (seperti evaluasi akademik atau kebijakan kelanjutan studi bagi mahasiswa dengan IPK di bawah standar), dokumen tersebut memberikan panduan sebagai berikut:\n\n1.  **Pihak yang Berwenang:**\n    *   **Ketua Jurusan atau Kepala Program Studi:** Memiliki wewenang dalam memberikan pertimbangan terkait alasan khusus atau keperluan mendesak (Excerpt 4, Pasal 24 ayat 6a).\n    *   **Wakil Direktur bidang Akademik:** Memiliki wewenang untuk memberikan persetujuan akhir atas pertimbangan yang diajukan oleh ketua jurusan atau kepala program studi (Excerpt 4, Pasal 24 ayat 6a).\n\n2.  **Mekanisme:**\n    *   Jika mahasiswa tersebut mengalami kendala akademik atau administratif, mekanisme yang tersedia dalam pedoman ini umumnya melibatkan koordinasi dengan **Dosen Wali** dan **Kepala Program Studi atau Ketua Jurusan** (Excerpt 4, Pasal 24 ayat 4).\n    *   Untuk keputusan yang bersifat pengecualian atau kebijakan khusus di luar ketentuan standar, diperlukan pertimbangan dari **Ketua Jurusan/Kepala Program Studi** dan persetujuan dari **Wakil Direktur bidang Akademik** (Excerpt 4, Pasal 24 ayat 6a).\n\n**Catatan:** Dokumen yang diberikan tidak secara spesifik menyebutkan mekanisme \"evaluasi IPK per semester\" untuk menentukan apakah mahasiswa boleh lanjut studi atau tidak (DO/Drop Out). Anda disarankan untuk merujuk pada peraturan akademik spesifik di Polibatam mengenai evaluasi studi per semester yang mungkin diatur di luar kutipan yang tersedia.', '2026-06-06 09:37:29', '2026-06-06 09:37:29', NULL),
(30, 58, 'Berdasarkan **Excerpt 1 (Pedoman Pembelajaran T.A 2025, p.20)**, berikut adalah konsekuensi dan proses yang berlaku bagi mahasiswa tersebut:\n\n1.  **Penerbitan Surat Peringatan (SP):**\n    *   Mahasiswa yang tidak hadir tanpa izin akan menerima Surat Peringatan (SP) dari jurusan.\n    *   SP I diberikan pada ketidakhadiran 5%, SP II pada 20%, dan SP III pada 40% dari total sesi dalam satu semester. Karena mahasiswa tersebut telah tidak hadir sebanyak 22%, ia telah melewati ambang batas SP II dan sedang dalam proses menuju SP III.\n\n2.  **Konsekuensi atas Ketidaktanggapan terhadap SP III:**\n    *   Jika mahasiswa menerima SP III dan tidak menanggapinya dalam jangka waktu **3 (tiga) minggu** sejak surat dikirimkan, maka mahasiswa tersebut **dianggap mengundurkan diri**.\n    *   Setelah dianggap mengundurkan diri, pihak kampus akan menerbitkan **surat pemberhentian**.\n\n3.  **Pengecualian:**\n    *   Jika dalam jangka waktu 3 minggu tersebut mahasiswa memberikan tanggapan bahwa ketidakhadirannya disebabkan oleh kesulitan ekonomi atau alasan lain yang dapat diterima, maka mahasiswa tersebut dapat mengajukan cuti akademik.\n\n**Catatan tambahan:**\nKetidakhadiran yang tidak dapat diverifikasi kebenarannya dianggap sebagai ketidakhadiran tanpa izin (Pasal 14 ayat 6).', '2026-06-06 09:40:21', '2026-06-06 09:40:21', NULL),
(31, 59, 'Berdasarkan **Excerpt 1 (Pasal 24 ayat 4 dan 5)** dan **Excerpt 5 (Pasal 24 ayat 9)** dari Pedoman Pembelajaran T.A 2025, berikut adalah penjelasannya:\n\n**Apakah permohonan dapat diproses?**\nYa, permohonan cuti setelah masa perkuliahan berjalan dapat diproses jika kondisi mahasiswa tidak memungkinkan untuk mengikuti perkuliahan dan mendapatkan persetujuan dari pihak terkait.\n\n**Syarat dan Pihak yang Memberikan Persetujuan:**\n1. **Syarat:**\n   * Mahasiswa telah menyelesaikan minimal 1 (satu) tahun studi.\n   * Kondisi mahasiswa tidak memungkinkan untuk melanjutkan perkuliahan.\n   * Mendapatkan persetujuan dari dosen wali dan kepala program studi atau ketua jurusan.\n   * Mendapatkan izin dari Wakil Direktur bidang Akademik.\n   * Membayar biaya cuti sesuai dengan aturan yang berlaku.\n   * Mengajukan permohonan cuti melalui sistem informasi dan layanan mahasiswa (SILAM) pada laman https://sim.polibatam.ac.id.\n\n2. **Pihak yang harus memberikan persetujuan:**\n   * Dosen wali.\n   * Kepala program studi atau ketua jurusan.\n   * Wakil Direktur bidang Akademik.', '2026-06-06 09:44:52', '2026-06-06 09:44:52', NULL),
(32, 60, 'Berdasarkan **Pasal 31 ayat (4)** dalam dokumen *Pedoman_Pembelajaran_T.A_2025.pdf* (halaman 24), mahasiswa tersebut akan memperoleh predikat kelulusan **sangat memuaskan**.\n\n**Alasannya:**\n1.  **Kriteria IPK:** Mahasiswa tersebut memiliki IPK 3,62. Untuk program sarjana terapan, predikat \"dengan pujian\" diberikan jika IPK > 3,50, namun ada syarat tambahan berupa waktu tempuh.\n2.  **Syarat Waktu Tempuh:** Predikat \"dengan pujian\" hanya diberikan jika mahasiswa menyelesaikan pendidikan **sesuai dengan waktu tempuh kurikulum**.\n3.  **Ketentuan Tambahan:** Pasal 31 ayat (4) secara spesifik menyatakan: *\"Jika menyelesaikan pendidikan lebih dari waktu tempuh kurikulum mendapat predikat kelulusan dengan sangat memuaskan.\"*\n\nOleh karena mahasiswa tersebut menyelesaikan studinya melebihi masa tempuh kurikulum normal, maka meskipun IPK-nya memenuhi syarat untuk predikat pujian (> 3,50), predikat yang diberikan turun menjadi sangat memuaskan.', '2026-06-06 11:23:50', '2026-06-06 11:23:50', NULL),
(33, 61, 'Berdasarkan dokumen *Pedoman Pembelajaran T.A 2025* yang disediakan, berikut adalah evaluasi terhadap tindakan tersebut:\n\n**1. Mahasiswa menggunakan akun LMS temannya untuk mengakses materi kuliah**\n*   **Evaluasi:** Tindakan ini melanggar ketentuan penggunaan layanan sistem informasi. Pasal 35 ayat (1) menyatakan bahwa layanan sistem informasi disediakan untuk digunakan mahasiswa secara bertanggung jawab, dan pemanfaatannya diarahkan untuk pemenuhan kebutuhan perkuliahan masing-masing.\n*   **Sanksi:** Dokumen tidak merinci sanksi spesifik untuk penyalahgunaan akun LMS, namun secara umum pelanggaran terhadap tata tertib atau aturan penggunaan fasilitas dapat dikenakan sanksi sesuai dengan kebijakan yang berlaku di Polibatam.\n\n**2. Mahasiswa mengunggah tugas kelompok hasil modifikasi karya mahasiswa angkatan sebelumnya tanpa mencantumkan sumber**\n*   **Evaluasi:** Tindakan ini dikategorikan sebagai kecurangan akademik. Berdasarkan **BAB VIII, Bagian Kesatu (Pasal tidak disebutkan secara spesifik di cuplikan)**, kecurangan akademik diatur dalam bab tersebut.\n*   **Sanksi:** Berdasarkan **BAB VIII, Bagian Kedua**, terdapat sanksi bagi pelaku kecurangan akademik, namun rincian jenis sanksinya tidak dijabarkan secara detail dalam cuplikan teks yang diberikan.\n\n**3. Mahasiswa meminjam KTM milik temannya untuk menggunakan fasilitas kampus**\n*   **Evaluasi:** Tindakan ini melanggar aturan identitas mahasiswa. **Pasal 18 ayat (1)** menyatakan bahwa identitas resmi mahasiswa Polibatam adalah Kartu Tanda Mahasiswa (KTM). Penggunaan KTM milik orang lain merupakan penyalahgunaan identitas resmi. Selain itu, **Pasal 34 ayat (2)** mewajibkan pengguna fasilitas (seperti laboratorium/workshop) untuk mengikuti peraturan yang ditetapkan pengelola.\n*   **Sanksi:** \n    *   Jika penggunaan fasilitas tersebut terkait dengan *workspace*, laboratorium, *workshop*, atau studio, maka berdasarkan **Pasal 34 ayat (6)**, sanksi yang dapat diberikan meliputi: teguran, surat peringatan, suspensi (skorsing) 1 bulan hingga 2 semester, atau pencabutan status kemahasiswaan secara permanen.\n    *   Jika terkait dengan layanan perpustakaan, **Pasal 17 (Excerpt 5)** menyatakan sanksi berupa teguran lisan, surat peringatan tertulis, atau pencabutan hak sebagai pengguna jasa perpustakaan.\n\n*Catatan: Untuk detail sanksi spesifik mengenai kecurangan akademik (poin 2), dokumen yang diberikan hanya menyebutkan adanya \"Bagian Kedua Sanksi Kecurangan Akademik\" pada halaman 23, namun isi pasal tersebut tidak disertakan dalam cuplikan.*', '2026-06-06 11:28:02', '2026-06-06 11:28:02', NULL),
(34, 62, 'Berdasarkan **Pedoman Pembelajaran T.A 2025 (Excerpt 4, Pasal 35)**, pelanggaran yang dilakukan oleh mahasiswa tersebut adalah sebagai berikut:\n\n**1. Identifikasi Pelanggaran:**\n*   **Penyebaran konten SARA:** Melanggar Pasal 35 ayat (3) huruf b, yang melarang penggunaan layanan dan jaringan untuk mengakses atau menyebarkan konten yang mengarah pada SARA atau konten lain sejenis yang melanggar norma kesopanan dan norma hukum.\n*   **Membagikan password kepada orang lain:** Melanggar Pasal 35 ayat (3) huruf e, yang melarang memberikan akses akun pengguna dan kata kunci (*password*) yang dimilikinya kepada orang lain.\n\n**2. Rentang Sanksi:**\nBerdasarkan Pasal 35 ayat (4), pelanggaran terhadap tata tertib layanan sistem informasi tersebut dapat dikenakan sanksi oleh jurusan atau kelompok kerja akademik dan kemahasiswaan dalam bentuk:\n*   Surat peringatan;\n*   Suspensi (skorsing), dengan durasi minimal 1 bulan dan maksimal 2 semester (cuti). Selama masa suspensi, tidak ada penggantian layanan akademik dan pembelajaran pada waktu lain; atau\n*   Pencabutan status kemahasiswaan secara permanen.', '2026-06-06 11:39:46', '2026-06-06 11:39:46', NULL),
(35, 63, 'Berdasarkan dokumen *Pedoman Pembelajaran T.A 2025*, berikut adalah pelanggaran yang dilakukan mahasiswa tersebut beserta sanksinya:\n\n### Pelanggaran yang Dilakukan:\n1.  **Tidak menggunakan alat keselamatan kerja:** Melanggar Pasal 34 ayat (4), yang mewajibkan pengguna *workspace*, laboratorium, *workshop*, atau studio menggunakan peralatan keselamatan kerja sesuai ketentuan perundangan yang berlaku.\n2.  **Meninggalkan laboratorium dalam keadaan berantakan:** Melanggar Pasal 34 ayat (3) dan (5), yang mewajibkan pengguna menjaga kerapian dan kebersihan, serta membersihkan fasilitas sebelum meninggalkan ruangan.\n3.  **Merusak peralatan laboratorium dan tidak melaporkannya:** Melanggar Pasal 39 ayat (3), yang mewajibkan mahasiswa untuk segera melapor kepada dosen, laboran, teknisi, atau petugas unit layanan apabila merusak barang milik Polibatam.\n\n### Sanksi:\nSanksi atas pelanggaran tata tertib penggunaan *workspace*, laboratorium, *workshop*, atau studio diatur dalam **Pasal 34 ayat (6)**. Jurusan dapat memberikan sanksi berupa:\n*   Teguran oleh pengelola *workspace*, laboratorium, *workshop*, atau studio;\n*   Surat peringatan;\n*   Suspensi (skorsing) minimal 1 bulan hingga maksimal 2 semester (cuti);\n*   Pencabutan status kemahasiswaan secara permanen.\n\nSelain itu, terkait kerusakan barang, berdasarkan **Pasal 39 ayat (4)**, mahasiswa yang merusak barang milik Polibatam bertanggung jawab untuk memperbaiki atau mengganti barang tersebut sesuai dengan ketentuan pengelolaan barang milik negara maksimal 1 tahun setelah ditetapkan.', '2026-06-06 11:40:42', '2026-06-06 11:40:42', NULL),
(36, 64, 'Berdasarkan dokumen **Pedoman_Pembelajaran_T.A_2025.pdf**, berikut adalah penjelasannya:\n\n**1. Ketentuan Masa Studi Maksimum**\nBerdasarkan **Pasal 7 ayat (2)**, masa studi program pendidikan Sarjana Terapan tidak boleh melebihi 2 (dua) kali Masa Tempuh Kurikulum. Karena masa tempuh kurikulum Sarjana Terapan adalah 8 semester, maka masa studi maksimumnya adalah:\n*   2 x 8 semester = **16 semester**.\n\n**2. Perhitungan Masa Studi Mahasiswa**\nBerdasarkan **Pasal 24 ayat (7)**, cuti akademik **tidak dihitung** sebagai bagian dari masa studi.\n\nJika mahasiswa tersebut lulus pada semester ke-11 sejak pertama kali masuk dan telah mengambil cuti akademik selama 2 semester, maka perhitungan masa studinya adalah:\n*   Total waktu sejak masuk: 11 semester\n*   Dikurangi masa cuti akademik: 2 semester\n*   **Masa studi yang dihitung: 9 semester**\n\n**Kesimpulan:**\nMahasiswa tersebut **masih memenuhi ketentuan masa studi maksimum**, karena masa studi yang dihitung (9 semester) masih jauh di bawah batas maksimum 16 semester.', '2026-06-06 11:44:32', '2026-06-06 11:44:32', NULL),
(37, 65, 'Berdasarkan **Pedoman Pembelajaran T.A 2025**, berikut adalah ketentuan untuk mahasiswa Program Pendidikan Diploma Tiga (D3):\n\n*   **Total minimal SKS yang harus ditempuh:** Minimal 108 (seratus delapan) SKS (tercantum dalam Pasal 7 ayat 1 huruf b).\n*   **Masa tempuh kurikulum:** Dirancang selama 6 (enam) semester (tercantum dalam Pasal 7 ayat 1 huruf b).\n*   **SKS minimal dari kegiatan magang:** Minimal 40 (empat puluh) SKS (tercantum dalam Pasal 8 ayat 7).', '2026-06-06 11:46:40', '2026-06-06 11:46:40', NULL),
(38, 66, 'Berdasarkan dokumen yang disediakan, berikut adalah jawaban atas pertanyaan Anda:\n\n**Identifikasi Ruang Belajar (RB)**\nBerdasarkan [Excerpt 2 — Pedoman_Pembelajaran_T.A_2025.pdf, p.10], ruang belajar yang disebutkan secara spesifik adalah:\n*   **RB1 – Tatap muka:** Pembelajaran antara dosen dan mahasiswa terjadi pada waktu dan ruang yang sama (sinkron luring), contohnya di laboratorium.\n\n*Catatan:* Dokumen yang disediakan **tidak memuat informasi atau definisi mengenai RB2, RB3, dan RB4**. Oleh karena itu, saya tidak dapat mengidentifikasi ruang belajar tersebut berdasarkan konteks yang diberikan.\n\n**Prinsip Fleksibilitas Pembelajaran**\nMengenai prinsip fleksibilitas pembelajaran, dokumen [Excerpt 3 — Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf, p.2] menjelaskan bahwa *Project-Based Learning* (PBL) merupakan metode pembelajaran yang membekali mahasiswa dengan pengalaman nyata melalui proyek riil yang relevan dengan kebutuhan industri. Fleksibilitas dalam pelaksanaan PBL di Program Studi Teknik Informatika didukung oleh:\n\n1.  **Infrastruktur Platform Digital:** Mahasiswa diberikan fleksibilitas untuk mengelola proyek, berkolaborasi, dan mengumpulkan luaran melalui berbagai platform seperti Siap-PBL, E-Learning, GitHub, YouTube, dan Google Drive ([Excerpt 1, p.22]).\n2.  **Tools Pendukung:** Tersedia berbagai *tools* pendukung untuk manajemen proyek (Trello/Jira), desain (Figma), hingga pengujian (Postman) yang dapat diakses melalui tautan referensi yang disediakan ([Excerpt 4, p.23]).\n3.  **Fleksibilitas Lokasi Kerja:** Selain menggunakan *workspace* kampus (Gedung Utama, Technopreneur Center, Gedung Tower A), mahasiswa diperbolehkan mengerjakan proyek di luar kampus, seperti di rumah anggota kelompok, tempat umum, atau lokasi mitra/klien ([Excerpt 4, p.23]).\n\nInformasi mengenai bagaimana model pembelajaran tersebut memenuhi prinsip fleksibilitas secara eksplisit dalam konteks RB2, RB3, dan RB4 tidak ditemukan dalam dokumen yang diberikan.', '2026-06-06 11:48:20', '2026-06-06 11:48:20', NULL),
(39, 67, 'Berdasarkan dokumen yang disediakan, kebijakan-kebijakan tersebut membentuk ekosistem pembelajaran yang fleksibel dan terintegrasi untuk mendukung konsep \"Merdeka Belajar\". Berikut adalah analisis keterhubungan antar kebijakan tersebut:\n\n### 1. Fleksibilitas Ruang dan Metode (Hybrid Learning RB1–RB4)\nKebijakan **Hybrid Learning (RB1–RB4)** yang diatur dalam *Pedoman Pembelajaran T.A 2025 (p.10-11)* menjadi fondasi teknis bagi seluruh kebijakan lainnya. Dengan adanya variasi ruang belajar—mulai dari tatap muka (RB1), daring (RB2), mandiri (RB3), hingga kolaboratif (RB4)—mahasiswa memiliki fleksibilitas untuk menempuh pendidikan kapan saja dan di mana saja. Hal ini memfasilitasi pendidikan berkelanjutan sepanjang hayat (*Pasal 5 ayat 5 dan 7*) dan menjadi infrastruktur utama bagi mahasiswa yang melakukan pembelajaran di luar program studi atau di luar perguruan tinggi.\n\n### 2. Perluasan Akses dan Pengakuan (RPL dan Pembelajaran Lintas Program/Luar PT)\nKebijakan **Rekognisi Pembelajaran Lampau (RPL)** (*Pasal 9 ayat 2*) dan **Pembelajaran di luar program studi/perguruan tinggi** (*Pasal 9 ayat 1-3*) saling terhubung untuk memecah batasan kurikulum tradisional.\n*   **RPL** memungkinkan mahasiswa mengakui capaian pembelajaran yang diperoleh dari pengalaman atau pendidikan sebelumnya, sehingga mempercepat masa studi.\n*   **Pembelajaran lintas program studi dan di luar perguruan tinggi** (hingga 2 semester atau 40 SKS) memberikan keleluasaan bagi mahasiswa untuk memperkaya kompetensi di luar disiplin ilmu utamanya. Keterhubungan ini didukung oleh *Pasal 5 ayat 7*, yang memberikan hak kepada mahasiswa untuk menyelesaikan pendidikan melalui mekanisme RPL dan mengikuti tahapan kurikulum yang fleksibel.\n\n### 3. Pengayaan Kompetensi melalui Kompetensi Mikro (Micro-credential)\nKebijakan **Kompetensi Mikro** (*Pasal 8 ayat 14-15*) berfungsi sebagai pelengkap kurikulum formal. Materi pembelajaran dapat diisi dengan program kompetensi mikro, termasuk pembelajaran daring dari institusi lain (*massive open online courses*). Hal ini terhubung langsung dengan metode **RB2 (daring)** dan **RB3 (mandiri)**, di mana mahasiswa dapat mengambil sertifikasi atau keahlian spesifik yang relevan dengan kebutuhan industri tanpa harus terikat pada struktur mata kuliah konvensional.\n\n### 4. Integrasi dalam Proyek (PBL) sebagai Muara\nSeluruh kebijakan di atas bermuara pada **Pembelajaran Berbasis Proyek (PBL)**. Sebagaimana dijelaskan dalam *Panduan PBL Prodi IF (p.8)*, PBL menjadi wahana untuk mengintegrasikan kompetensi teknis dan membangun profesional mandiri.\n*   Hasil dari pembelajaran lintas program studi, magang, atau kompetensi mikro dapat diintegrasikan ke dalam proyek nyata (seperti *Capstone Project*).\n*   Proses ini didukung oleh pendekatan **RB4 (Kolaboratif)**, di mana mahasiswa berinteraksi dengan praktisi dan narasumber lain untuk menyelesaikan masalah nyata, yang pada akhirnya memenuhi capaian pembelajaran lulusan secara efektif (*Pedoman Pembelajaran T.A 2025, p.11*).\n\n### Kesimpulan\nKeterhubungan kebijakan ini menciptakan alur yang sistematis:\n1.  **Akses:** RPL dan fleksibilitas kurikulum membuka pintu masuk dan jalur studi yang beragam.\n2.  **Proses:** *Hybrid learning* (RB1-RB4) dan kompetensi mikro menyediakan metode dan konten yang adaptif.\n3.  **Implementasi:** Pembelajaran lintas program studi dan di luar perguruan tinggi (termasuk magang) memberikan pengalaman praktis.\n4.  **Output:** PBL mengintegrasikan seluruh pengalaman tersebut menjadi kompetensi profesional yang utuh, sesuai dengan profil lulusan yang diharapkan.', '2026-06-06 11:49:47', '2026-06-06 11:49:47', NULL),
(40, 68, 'Berdasarkan dokumen yang diberikan, berikut adalah kondisi dan konsekuensi terkait status mahasiswa:\n\n### 1. Kondisi Penyebab Status\n*   **Dianggap Mengundurkan Diri:**\n    *   Terjadi jika mahasiswa tidak menanggapi Surat Peringatan (SP) III terkait ketidakhadiran tanpa izin dalam jangka waktu 3 minggu sejak surat dikirimkan (Excerpt 1, Pasal 20 ayat 9).\n    *   Melalui mekanisme pengajuan pengunduran diri oleh mahasiswa sendiri (Excerpt 4, Pasal 25 ayat 1).\n*   **Diberhentikan:**\n    *   Diterbitkan surat pemberhentian setelah mahasiswa dianggap mengundurkan diri karena tidak menanggapi SP III (Excerpt 1, Pasal 20 ayat 9).\n    *   Mahasiswa yang terbukti tidak dapat menyelesaikan studi pada batas waktu maksimal masa studi (Excerpt 4, Pasal 25 ayat 2).\n*   **Dicabut Status Kemahasiswaannya (Secara Permanen):**\n    *   Merupakan salah satu bentuk sanksi atas pelanggaran kecurangan akademik (Excerpt 2, Pasal 41 ayat 2 poin e).\n*   **Berstatus Nonaktif:**\n    *   Dokumen tidak menyebutkan secara spesifik kondisi apa yang menyebabkan mahasiswa menjadi \"nonaktif\", namun disebutkan bahwa status nonaktif akan mengurangi masa studi (Excerpt 1, Pasal 24 ayat 8).\n\n---\n\n### 2. Perbedaan Konsekuensi Akademik\nBerdasarkan konteks yang tersedia, berikut adalah perbedaan konsekuensi dari status-status tersebut:\n\n| Status | Konsekuensi Akademik |\n| :--- | :--- |\n| **Cuti Akademik** | Pembebasan kewajiban mengikuti kegiatan akademik selama jangka waktu tertentu. Cuti **tidak dihitung** sebagai bagian dari masa studi (Excerpt 1, Pasal 24 ayat 1 & 7). |\n| **Status Nonaktif** | Berbeda dengan cuti, status nonaktif **mengurangi masa studi** (Excerpt 1, Pasal 24 ayat 8). |\n| **Pengunduran Diri / Pemberhentian** | Mahasiswa tidak dapat melanjutkan studinya di Polibatam (Excerpt 4, Pasal 25 ayat 2). |\n| **Pencabutan Status Permanen** | Mahasiswa kehilangan status kemahasiswaannya secara permanen sebagai sanksi atas kecurangan akademik (Excerpt 2, Pasal 41 ayat 2 poin e). |\n\n*Catatan: Dokumen tidak memberikan perincian lebih lanjut mengenai perbedaan teknis antara \"pengunduran diri\" dan \"pemberhentian\" selain mekanisme penyebabnya.*', '2026-06-06 11:50:12', '2026-06-06 11:50:12', NULL),
(41, 69, 'Berdasarkan dokumen *Pedoman Pembelajaran T.A 2025*, berikut adalah analisis untuk mahasiswa program Sarjana Terapan tersebut:\n\n### 1. Apakah masa studinya masih valid?\n**Ya, masih valid.**\n*   Masa tempuh kurikulum Sarjana Terapan adalah 8 semester (Pasal 7 ayat 1c).\n*   Masa studi maksimal adalah 2 kali masa tempuh kurikulum, yaitu 16 semester (Pasal 7 ayat 2).\n*   Cuti akademik tidak dihitung sebagai bagian dari masa studi (Pasal 24 ayat 7).\n*   Mahasiswa menyelesaikan studi dalam 10 semester kalender. Jika dikurangi 2 semester cuti, masa studi efektifnya adalah 8 semester, yang berarti tepat waktu.\n\n### 2. Apakah kewajiban magang terpenuhi?\n**Tidak dapat dipastikan.**\nDokumen tidak secara spesifik mengatur kewajiban \"magang industri\" sebagai syarat kelulusan, namun menyebutkan penyerahan \"laporan magang\" sebagai salah satu persyaratan yudisium (Pasal 31 ayat 1f). Selama mahasiswa telah memenuhi beban SKS yang disyaratkan kurikulum dan menyerahkan laporan magang, maka kewajiban tersebut terpenuhi.\n\n### 3. Apakah pemenuhan beban belajar di luar program studi sesuai aturan?\n**Sesuai.**\n*   Mahasiswa mengikuti MBKM 1 semester (20 SKS) di lingkungan Polibatam (sesuai Pasal 9 ayat 3a).\n*   Mahasiswa mengikuti magang industri 2 semester (40 SKS) di lembaga di luar perguruan tinggi (sesuai Pasal 9 ayat 3b).\n*   Total pembelajaran di luar program studi adalah 3 semester (60 SKS), yang memenuhi ketentuan Pasal 9 ayat 3.\n\n### 4. Predikat kelulusan apa yang diperoleh?\n**Predikat \"Dengan Pujian\".**\n*   IPK mahasiswa adalah 3,55 (di atas 3,50).\n*   Mahasiswa menyelesaikan pendidikan sesuai dengan waktu tempuh kurikulum (8 semester efektif).\n*   Berdasarkan Pasal 31 ayat 4, predikat \"Dengan Pujian\" diberikan jika IPK > 3,50 dan menyelesaikan pendidikan sesuai waktu tempuh kurikulum.\n\n### 5. Pasal yang digunakan:\n*   **Masa Studi:** Pasal 7 ayat (1) huruf c, Pasal 7 ayat (2), dan Pasal 24 ayat (7).\n*   **Status Nonaktif/Daftar Ulang:** Pasal 16 ayat (1).\n*   **Cuti Akademik:** Pasal 24 ayat (5) huruf b dan Pasal 24 ayat (7).\n*   **Pemenuhan Beban Belajar Luar Prodi:** Pasal 9 ayat (3) huruf a dan b.\n*   **Predikat Kelulusan:** Pasal 31 ayat (1) huruf f dan Pasal 31 ayat (4).\n\n***Catatan tambahan:** Mahasiswa yang tidak daftar ulang selama 1 semester dinyatakan nonaktif (Pasal 16 ayat 1). Perlu diperhatikan bahwa status nonaktif mengurangi masa studi (Pasal 24 ayat 8), namun karena total masa studi efektif (10 semester kalender - 2 semester cuti = 8 semester) masih memenuhi masa tempuh kurikulum, mahasiswa tersebut tetap dianggap lulus tepat waktu.*', '2026-06-06 11:51:44', '2026-06-06 11:51:44', NULL),
(42, 70, 'Berdasarkan dokumen yang tersedia, nilai **A** didefinisikan sebagai nilai angka ≥85.00 yang setara dengan nilai 4.00.\n\nInformasi ini dapat ditemukan pada **Pedoman_Pembelajaran_T.A_2025.pdf, halaman 22**.', '2026-06-06 17:58:59', '2026-06-06 17:58:59', NULL),
(43, 71, 'Berdasarkan **Excerpt 1 (halaman 16)** dari dokumen *Panduan_PBL_Prodi_IF_-_sem_1-2-3-4.pdf*, mata kuliah pendukung di semester 4 adalah sebagai berikut:\n\n1.  **IF419 – Proyek Perangkat Lunak Industri** (Induk PBL Semester 4)\n2.  **IF420 – Mata Kuliah Pilihan 2** (Pendalaman bidang: Web, Mobile, IoT, AI, atau Infrastruktur IT)\n3.  **IF421 – Instalasi dan Perawatan Perangkat Lunak**\n4.  **IF422 – Pengujian Perangkat Lunak**\n5.  **IF424 – Bahasa Inggris untuk Bisnis**\n6.  **PK4IF – Pendidikan Bahasa Indonesia**', '2026-06-06 17:59:22', '2026-06-06 17:59:22', NULL);

