INSERT INTO `chunks` (`chunk_id`, `document_id`, `chunk_text`, `created_at`, `edited_at`, `deleted_at`) VALUES
(88, 12, 'Tim Kurikulum \nPROGRAM STUDI D3 TEKNIK INFORMATIKA \nPOLITEKNIK NEGERI BATAM \nPANDUAN PBL \nProgram Studi D3 Teknik Informatika \nPoliteknik Negeri Batam', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(89, 12, 'KATA PENGANTAR \n \nPuji syukur kami panjatkan ke hadirat Tuhan Yang Maha Esa atas tersusunnya Panduan Project-Based \nLearning (PBL) Program Studi D3 Teknik Informatika ini. Panduan ini disusun sebagai acuan bagi \nmahasiswa, dosen, Manajer Proyek, dan seluruh pemangku kepentingan dalam melaksanakan \npembelajaran berbasis proyek yang menjadi ciri khas pendidikan vokasi di Politeknik Negeri Batam. \nPBL merupakan metode pembelajaran unggulan yang dirancang untuk membekali mahasiswa dengan \npengalaman nyata dalam mengembangkan perangkat lunak. Melalui PBL, mahasiswa tidak hanya \nbelajar teori di kelas, tetapi juga langsung mempraktikkannya dalam proyek -proyek riil yang relevan \ndengan kebutuhan industri. Proses ini diharapkan mampu menghasilkan lulusan yang kompeten, \nprofesional, dan siap berkontribusi di dunia kerja. \nPanduan ini mencakup seluruh aspek pelaksanaan PBL mulai dari Semester 1 hingga Semester 4, \ntermasuk konsep dasar, tahapan setiap semester, panduan asesmen, serta infrastruktur pendukung. \nDengan adanya panduan ini, diharapkan seluruh pihak memiliki pemaham an yang sama tentang \nmekanisme PBL sehingga pelaksanaannya dapat berjalan lancar, terstruktur, dan mencapai target \ncapaian pembelajaran yang diharapkan. \nKami menyadari bahwa panduan ini masih memiliki kekurangan. Oleh karena itu, kritik dan saran yang \nmembangun sangat kami harapkan untuk perbaikan di masa mendatang. Semoga panduan ini \nbermanfaat bagi seluruh civitas akademika Program Studi D3 Teknik Informatika. \n \nBatam, 2026 \nTim Kurikulum \nProgram Studi D3 Teknik Informatika \nPoliteknik Negeri Batam', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(90, 12, 'DAFTAR ISI \n \nKATA PENGANTAR ................................ ................................ ................................ .................. 1 \nDAFTAR ISI ................................ ................................ ................................ ............................... 2 \nDAFTAR TABEL................................ ................................ ................................ ........................ 3 \nDAFTAR GAMBAR ................................ ................................ ................................ ................... 3 \nBAB 1 PENDAHULUAN DAN KONSEP DASAR PBL ................................ .............................. 4 \n1.1 Pengantar PBL .............................................................................................................................. 4 \n1.2 Tujuan PBL ................................................................................................................................... 4 \n1.3 Framework CDIO dalam Pembelajaran ........................................................................................ 5 \n1.4 Profil Lulusan dan Relevansi PBL ................................................................................................ 7 \n1.5 Integrasi Teori, Praktikum, dan PBL ............................................................................................. 8 \n1.6 Peran dan Tanggung Jawab dalam PBL ........................................................................................ 9 \nBAB 2 TAHAPAN PBL TIAP SEMESTER ................................ ................................ ............... 10 \n2.1 PBL Semester 1 – Proyek Pengantar Perangkat Lunak .............................................................. 10 \n2.2 PBL Semester 2 – Proyek Pembuatan Prototipe ......................................................................... 12 \n2.3 PBL Semester 3 – Proyek Inovasi Agile ..................................................................................... 13 \n2.4 PBL Semester 4 – Proyek Perangkat Lunak Industri .................................................................. 14 \nBAB 3 PANDUAN ASESMEN PBL ................................ ................................ .......................... 16 \n3.1 Mekanisme Asesmen PBL .......................................................................................................... 16 \n3.2 Luaran Asesmen Tengah Semester (ATS) ................................................................................... 16', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(91, 12, '3.2 Luaran Asesmen Tengah Semester (ATS) ................................................................................... 16 \n3.3 Luaran Asesmen Akhir Semester (AAS) .................................................................................... 17 \n3.4 Format Asesmen (Informasi Detail di Learning) ........................................................................ 19 \n3.5 Pengumpulan Luaran .................................................................................................................. 20 \nBAB 4 INFRASTRUKTUR DAN PENDUKUNG ................................ ................................ ..... 21 \n4.1 Platform dan Tools Pendukung ................................................................................................... 21 \n4.2 Workspace dan Fasilitas .............................................................................................................. 22 \nBAB 5 PENUTUP ................................ ................................ ................................ ..................... 23', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(92, 12, 'DAFTAR TABEL \n \nTabel 1. Tahapan CDIO ........................................................................................................................... 5 \nTabel 2. Tahapan PBL dengan Pendekatan Progressive CDIO ............................................................... 6 \nTabel 3. Klaster PBL dan Relevansi dengan Profil Lulusan ................................................................... 7 \nTabel 4. Peran dan Tanggung Jawab Aktor PBL ..................................................................................... 9 \nTabel 5. Gambaran Umum Tahapan PBL ............................................................................................. 10 \nTabel 6. Luaran AAS ............................................................................................................................. 18 \n \nDAFTAR GAMBAR \n \nGambar 1. Integrasi Teori, Praktikum, dan PBL ..................................................................................... 8', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(93, 12, 'BAB 1 PENDAHULUAN DAN KONSEP DASAR PBL \n \n1.1 Pengantar PBL \nPBL adalah metode pembelajaran yang memberikan pengalaman nyata kepada mahasiswa dengan \ncara terlibat langsung dalam sebuah proyek riil. Berbeda dengan metode pembelajaran \nkonvensional yang berpusat pada dosen, PBL berpusat pada peserta didik ( student-centered \nlearning). Mahasiswa berperan aktif melakukan investigasi mendalam terhadap suatu topik atau \npermasalahan yang nyata dan relevan dengan dunia kerja. \nDalam PBL, mahasiswa tidak hanya belajar teori, tetapi langsung mempraktikkannya dalam bentuk \nproyek yang menghasilkan produk nyata. Proses mengerjakan dan menyelesaikan proyek inilah \nyang menjadi wahana bagi mahasiswa untuk memperoleh pengetahuan sekaligu s keterampilan \nsecara terintegrasi. \nInti PBL: “Belajar dengan mengerjakan, bukan belajar untuk mengerjakan.” \n \nPBL bukan sekadar tugas kuliah biasa. Ini adalah kesempatan untuk membangun portofolio, \nmengasah keterampilan, dan mempersiapkan diri menghadapi dunia profesional. \n \n1.2 Tujuan PBL \nTujuan Akademik: \n1. Mengintegrasikan pengetahuan teoritis dari berbagai mata kuliah ke dalam praktik nyata \n2. Meningkatkan pemahaman mahasiswa terhadap siklus pengembangan perangkat lunak \n3. Melatih kemampuan analisis dan perancangan sistem \n4. Membiasakan mahasiswa dengan standar dan praktik terbaik ( best practices ) dalam \npengembangan perangkat lunak \n \nTujuan Keterampilan (Skills): \n1. Kemampuan Teknis (Technical Skills): Kemampuan membangun produk perangkat lunak \nmenggunakan teknologi yang relevan \n2. Penyelesaian Masalah ( Problem Solving ): Kemampuan mengidentifikasi masalah dan \nmerancang solusi yang tepat \n3. Komunikasi ( Communication): Kemampuan menyampaikan ide, proses, dan hasil kerja \nsecara lisan maupun tulisan', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(94, 12, '4. Kolaborasi ( Collaboration): Kemampuan bekerja dalam tim, berbagi peran, dan \nmenyelesaikan konflik \n5. Manajemen Proyek (Project Management): Kemampuan mengelola waktu, sumber daya, \ndan target capaian \n6. Presentasi ( Presentation Skills ): Kemampuan presentasi dan mempertahankan ide di \nhadapan reviewer \n \nTujuan Profesional: \n1. Membangun portofolio proyek sebagai bekal memasuki dunia kerja \n2. Membiasakan mahasiswa dengan etos kerja profesional (disiplin, tanggung jawab, \nintegritas) \n3. Menyiapkan lulusan yang siap berkontribusi di industri perangkat lunak \n \n1.3 Framework CDIO dalam Pembelajaran \nProgram Studi D3 Teknik Informatika mengadopsi framework CDIO ( Conceive-Design-\nImplement-Operate) sebagai kerangka utama dalam merancang dan melaksanakan pembelajaran, \nkhususnya dalam PBL. CDIO adalah pendekatan pendidikan teknik inovatif yang membekali \nmahasiswa dengan kemampuan untuk memahami dan menjalani seluruh siklus hidup \npengembangan suatu sistem, produk, atau proses. \nFramework CDIO terdiri dari empat tahapan utama yang merepresentasikan siklus lengkap \npengembangan, seperti terlihat pada Tabel 1. \nTabel 1. Tahapan CDIO \nTahapan Aktivitas Utama Deskripsi Singkat \nConceive \n(Konsepsi) \nAnalisis Kebutuhan, Studi \nKelayakan, Spesifikasi Awal \nMahasiswa belajar mengidentifikasi kebutuhan \npengguna, mendefinisikan masalah, merumuskan solusi \nkonseptual, serta memahami konteks bisnis dan teknis \ndari proyek. \nDesign \n(Perancangan) \nPerancangan Arsitektur, \nDesain Basis Data, Desain \nAntarmuka \nFokus pada perancangan solusi secara detail. Ini \nmencakup pembuatan diagram, pemodelan data, \nperancangan antarmuka pengguna, dan perencanaan \nstruktur sistem. \nImplement \n(Implementasi) \nPengkodean, Integrasi \nKomponen, Pengujian Unit \nMewujudkan desain menjadi produk nyata melalui \npenulisan kode program, integrasi berbagai modul, dan \npengujian untuk memastikan setiap bagian berfungsi \ndengan baik. \nOperate \n(Operasi) \nPengujian Fungsional, \nDeployment, Pemeliharaan, \nEvaluasi \nMenjalankan dan menguji produk dalam skenario nyata \n(atau simulasi), melakukan deployment, serta \nmengevaluasi kinerja dan proses pengembangan untuk \npembelajaran di masa depan.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(95, 12, 'Mahasiswa tidak dituntut langsung menguasai semua tahapan CDIO sekaligus. Penerapannya \ndilakukan secara bertahap dan progresif selama 4 semester, dengan tingkat kemandirian dan \nkompleksitas yang meningkat. Pendekatan ini dikenal dengan \"Progressive CDIO\", seperti terlihat \npada Tabel 2 berikut. \nTabel 2. Tahapan PBL dengan Pendekatan Progressive CDIO \nSemester Fokus \nTahapan \nMata Kuliah \nPBL Penjelasan dan Target Capaian \nSemester \n1 \nI-O \n(Implement -\nOperasi) \nPengantar \nProyek \nPerangkat \nLunak \nMahasiswa diperkenalkan pada proses implementasi dan \noperasi sederhana. Mereka bekerja berdasarkan \nspesifikasi dan desain yang sudah disediakan oleh \ndosen/Manpro. Target: Mampu menulis kode sesuai \nspesifikasi dan menjalankan produk sederhana. \nSemester \n2 \nd-I-O \n(Desain - \nImplement - \nOperasi) \nProyek \nPembuatan \nPrototipe \nMahasiswa mulai belajar merancang ( design) solusi \nsederhana, lalu mengimplementasikan dan \nmengoperasikannya. Desain masih dalam tahap belajar (d \nkecil). Target: Mampu membuat desain antarmuka dan \nbasis data sederhana, lalu mewujudkannya menjadi \nprototipe yang berfungsi. \nSemester \n3 \nc-D-I-O \n(Konsepsi - \nDesain - \nImplement - \nOperasi) \nProyek Inovasi \nAgile \nMahasiswa belajar melalui seluruh siklus CDIO, mulai \ndari konsepsi hingga operasi. Mereka mulai merumuskan \nide sendiri (c kecil) namun masih dalam konteks proyek \nyang terstruktur dan dengan bimbingan intensif. Target: \nMampu merumuskan ide, merancang, mengimplementasi, \ndan menguji proyek secara berkelompok dengan \nmetodologi Agile. \nSemester \n4 \nC-D-I-O \n(Konsepsi - \nDesain - \nImplement - \nOperasi) \nProyek \nPerangkat \nLunak Industri \nMahasiswa diharapkan mampu menjalankan seluruh \ntahapan CDIO secara mandiri dan profesional, layaknya \nsebuah proyek di industri. Mereka berinteraksi dengan \nklien riil dan bekerja dengan standar profesional. Target: \nMampu bekerja dengan klien riil, merancang solusi sesuai \nstandar industri, mengimplementasi, melakukan \ndeployment, dan memelihara produk. \nSemester \n5 \nC-D-I-O \n(Capstone \nProject - \nPerencanaan) \nProposal Proyek \nAkhir + Magang \nIndustri \nMahasiswa mempersiapkan Capstone Project (Proyek \nAkhir) yang merupakan integrasi seluruh kompetensi. \nPada semester ini, mereka menyusun proposal yang \nmatang, melakukan studi literatur mendalam, dan \nmenganalisis kebutuhan secara komprehensif. Magang \nindustri memberikan pengalaman nyata yang \nmemperkaya persiapan proyek. Target: Menghasilkan \nproposal proyek akhir yang berkualitas, teruji deng an', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(96, 12, 'matang, melakukan studi literatur mendalam, dan \nmenganalisis kebutuhan secara komprehensif. Magang \nindustri memberikan pengalaman nyata yang \nmemperkaya persiapan proyek. Target: Menghasilkan \nproposal proyek akhir yang berkualitas, teruji deng an \npengalaman magang, dan siap diimplementasikan. \nSemester \n6 \nC-D-I-O \n(Capstone \nProject - \nImplementasi) \nProyek Akhir + \nMagang Industri \nMahasiswa mengimplementasikan Capstone Project \nsecara penuh dan mandiri. Proyek ini merupakan puncak \ndari seluruh pembelajaran PBL selama 5 semester \nsebelumnya, dengan tingkat kompleksitas dan \nprofesionalisme tinggi. Mereka harus mendemonstrasikan \npenguasaan seluruh tahapan CDIO secara utuh. Target: \nMenghasilkan produk perangkat lunak yang inovatif, \nlengkap dengan dokumentasi profesional, serta mampu \nmempresentasikan dan mempertahankan karya di \nhadapan penguji.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(97, 12, '1.4 Profil Lulusan dan Relevansi PBL \nUntuk mencapai profil lulusan tersebut, kurikulum dirancang dengan sistem klaster bidang yang dipilih \nmahasiswa mulai Semester 3 dan didalami hingga Semester 4, yang kemudian menjadi fondasi untuk \nCapstone Project di Semester 5-6. Pemetaannya adalah sebagai berikut: \nTabel 3. Klaster PBL dan Relevansi dengan Profil Lulusan \nKlaster PBL Profil Lulusan yang Dituju Fokus Pengembangan \nWeb & Mobile Software Developer, Front-End \nDeveloper, Back-End Developer, \nDesainer Web \nPengembangan aplikasi berbasis \nweb dan/atau mobile, mencakup \naspek front -end, back -end, dan \ndesain antarmuka. \nInternet of Things (IoT) Software Developer (dengan \nspesialisasi embedded systems), \nSystem Administrator (untuk \nbackend IoT) \nPengembangan sistem terintegrasi \ndengan perangkat keras, sensor, \ndan konektivitas, serta pengelolaan \ndata dari perangkat IoT. \nArtificial Intelligence (AI) Software Developer (AI/ML \nEngineer) \nPengembangan aplikasi dengan \nkomponen kecerdasan buatan, \nmachine learning, dan analisis \ndata. \nInfrastruktur IT IT Help Desk, System \nAdministrator \nPengelolaan infrastruktur \nteknologi informasi, termasuk \njaringan, server, layanan dukungan \nteknis, keamanan, dan \ndokumentasi sistem. \nPBL adalah wahana utama untuk mencapai profil lulusan tersebut. Relevansinya dapat dijabarkan \nsebagai berikut: \n▪ Mengintegrasikan Kompetensi Teknis: PBL memungkinkan mahasiswa untuk secara langsung \nmempraktikkan dan mengintegrasikan semua kompetensi utama yang diajarkan di mata kuliah, \nseperti rekayasa perangkat lunak, pengembangan aplikasi, basis data, dan jaringan. Seorang \nmahasiswa di klaster Web & Mobile, misalnya, akan merancang basis data (kompetensi 4), \nmengembangkan aplikasi web (kompetensi 2), dan menerapkan prinsip rekayasa perangkat \nlunak (kompetensi 1) dalam satu proyek utuh. \n▪ Membangun Profesional Mandiri: Melalui PBL, mahasiswa dilatih untuk menjadi pembelajar \nmandiri. Mereka harus mengidentifikasi sendiri kesenjangan pengetahuan (Sikap), mencari \nsolusi (Keterampilan Umum), dan bertanggung jawab atas hasil kerja (Sikap). Proses ini sejalan \ndengan profil profesional mandiri yang terus belajar dan berinovasi. \n▪ Mengasah Keterampilan Interpersonal dan Manajerial: Bekerja dalam tim PBL melatih \nkemampuan kolaborasi, komunikasi efektif (lisan dan tulisan), manajemen konflik, dan \nkepemimpinan. Keterampilan ini mutlak diperlukan untuk berfungsi efektif sebagai anggota', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(98, 12, 'tim teknis (Keterampilan Khusus) dan untuk berkomunikasi dengan pemangku kepentingan \n(Keterampilan Umum). \n▪ Memberikan Pengalaman Nyata (Simulasi Dunia Kerja): PBL, terutama di semester 4 (Proyek \nPerangkat Lunak Industri) dan semester 5-6 (Proyek Akhir), memberikan simulasi nyata \ntentang tuntutan dunia kerja. Mahasiswa belajar bekerja dengan \"klien\", mengelola proyek dari \nide hingga produk jadi (siklus CDIO), dan menyusun laporan profesional. Hal ini secara \nlangsung mempersiapkan mereka u ntuk berperan sebagai Software Developer, System \nAdministrator, atau IT Help Desk di industri. \n▪ Membangun Portofolio Profesional: Setiap proyek PBL yang diselesaikan dengan baik menjadi \nbagian dari portofolio mahasiswa. Portofolio ini adalah bukti konkret penguasaan kompetensi \ndan menjadi nilai jual utama saat melamar pekerjaan, baik sebagai Develope r, Desainer, \nmaupun Administrator. \n1.5 Integrasi Teori, Praktikum, dan PBL \nPembelajaran di Prodi D3 Teknik Informatika menggunakan pendekatan 3 lapis penguasaan \nkompetensi yang saling terkait. \n \nGambar 1. Integrasi Teori, Praktikum, dan PBL \nTeori yang disampaikan di ruang kelas melalui kuliah, diskusi, dan studi kasus bertujuan memberikan \npemahaman landasan konseptual, yaitu \"mengapa\" dan \"apa\" dari suatu materi. Praktikum di \nlaboratorium memberikan latihan terstruktur dengan panduan atau modul untuk mengaplikasikan teori \ndalam tugas -tugas spesifik, sehingga mahasiswa menguasai keterampilan dasar atau \"bagaimana\" \nsecara terkontrol. Selanjutnya, PBL di workshop atau ruang proyek menjadi wadah penerapan dalam \nproyek nyata dengan masalah tidak terstruk tur dan kompleksitas meningkat, yang bertujuan \nmengintegrasikan semua kompetensi secara autentik untuk memecahkan masalah nyata.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(99, 12, '1.6 Peran dan Tanggung Jawab dalam PBL \nKeberhasilan PBL sangat bergantung pada pemahaman dan pelaksanaan peran serta tanggung jawab \nsetiap pihak yang terlibat. Setiap pihak memiliki kontribusi unik yang saling melengkapi, mulai dari \nmahasiswa sebagai pelaksana utama proyek, dosen dan Manajer Pr oyek sebagai pembimbing, hingga \ntenaga kependidikan yang mendukung kelancaran operasional. Dengan memahami peran masing -\nmasing secara jelas, diharapkan kolaborasi dapat berjalan efektif dan tujuan pembelajaran dapat tercapai \nsecara optimal. \nBerikut adalah ringkasan peran dan tanggung jawab setiap pihak dalam ekosistem PBL di Program \nStudi D3 Teknik Informatika. \nTabel 4. Peran dan Tanggung Jawab Aktor PBL \nPihak Peran Utama Aktivitas Kunci Bertanggung \nJawab Kepada \nMahasiswa \n(Individu) \nPelaksana Proyek Hadir tepat waktu, berkontribusi aktif, \nberkomunikasi terbuka, mendokumentasikan \npekerjaan di logbook, belajar mandiri \nKetua Tim dan \nManpro \nKetua Tim Koordinator Tim Memimpin rapat, membagi tugas, melapor progres \nke Manpro, memeriksa kualitas pekerjaan, \nmemastikan kelengkapan dokumen \nManpro dan \nDosen MK \nProyek \nDosen Mata \nKuliah Proyek \nPengelola & \nSupervisor Utama \nMengelola perkuliahan proyek, memonitor progres \nmingguan, mengkoordinasi Manpro, mengelola \nasesmen (ATS/AAS), menentukan nilai akhir \nKaprodi \nManajer \nProyek \n(Manpro) \nPembimbing \nTeknis Utama \nMembimbing 1 -3 tim secara intensif, memeriksa \nlogbook rutin, verifikasi dokumen, memberikan \nmasukan teknis, memberi input penilaian \nDosen MK \nProyek \nCo-Manajer \nProyek (Co-\nManpro) \nPembimbing \nTeknis \nPendamping \nMembantu Manpro membimbing tim (sesuai \npembagian tugas/keahlian), memeriksa logbook, \nmemberi masukan teknis spesifik, hadir bergantian \ndengan Manpro \nManpro dan \nDosen MK \nProyek \nDosen Mata \nKuliah \nPendukung \nFasilitator \nKeilmuan \nMengajar teori & praktikum, mengaitkan materi \ndengan PBL, membuka konsultasi keilmuan sesuai \nbidangnya \nKoordinator MK \nKlien / Owner \nProyek \nPemberi \nKebutuhan \n(Semester 4-6) \nMenyampaikan kebutuhan, menguji hasil proyek, \nmemberikan umpan balik, mengesahkan produk (via \nBAST) \nManpro dan \nDosen MK \nProyek \nReviewer Penilai Asesmen Menilai presentasi dan luaran saat ATS/AAS, \nmemberikan umpan balik konstruktif, melakukan \nbenchmarking \nDosen MK \nProyek \nLaboran & \nTenaga \nKependidikan \nFasilitator Sarana Menyiapkan workspace, mengelola peminjaman \nruang/alat, membantu administrasi laboratorium \nKaprodi / Kepala \nLab', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(100, 12, 'BAB 2 TAHAPAN PBL TIAP SEMESTER \n \nPBL di Program Studi D3 Teknik Informatika dilaksanakan secara bertahap selama 4 semester, dengan \ntingkat kompleksitas dan kemandirian yang meningkat setiap semesternya. Setiap semester dirancang \nuntuk mencapai target capaian tertentu sesuai dengan kerangka CDIO yang diadaptasi secara progresif. \nPada Semester 1, mahasiswa berfokus pada implementasi dan operasi (I-O) dengan bimbingan penuh. \nSemester 2, mereka mulai belajar merancang (d -I-O) solusi sederhana. Semester 3, mahasiswa \nmenjalani seluruh siklus CDIO dengan konsepsi mandiri (c-D-I-O) serta memilih klaster bidang sesuai \nminat. Semester 4 menjadi puncak PBL akademik dengan proyek industri (C-D-I-O) bersama klien riil. \nTabel 5 berikut adalah gambaran umum tahapan PBL selama 4 semester. \nTabel 5. Gambaran Umum Tahapan PBL \nSem \nMata \nKuliah \nPBL \nFokus CDIO Target Capaian Keterkaitan dengan \nProfil Lulusan \n1 \nPengantar \nProyek \nPerangkat \nLunak \nI-O \n(Implementasi - \nOperasi) \nMampu menulis kode sesuai \nspesifikasi dan menjalankan \nproduk sederhana \nPengenalan awal terhadap \nperan Software Developer, \nFront-End, Back-End \n2 \nProyek \nPembuatan \nPrototipe \nd-I-O \n(Desain - \nImplementasi - \nOperasi) \nMampu membuat desain \nantarmuka dan basis data \nsederhana, lalu mewujudkannya \nmenjadi prototipe yang berfungsi \nPenguatan peran sebagai \nDeveloper dan Desainer \n3 \nProyek \nInovasi \nAgile \nc-D-I-O \n(Konsepsi - \nDesain - \nImplementasi - \nOperasi) \nMampu merumuskan ide, \nmerancang, mengimplementasi, \ndan menguji proyek secara \nberkelompok dengan metodologi \nAgile \nPemilihan jalur (klaster) \nsesuai minat: Web/Mobile, \nIoT, AI, Infrastruktur IT \n4 \nProyek \nPerangkat \nLunak \nIndustri \nC-D-I-O \n(Konsepsi - \nDesain - \nImplementasi - \nOperasi) \nMampu bekerja dengan klien riil, \nmerancang solusi sesuai standar \nindustri, mengimplementasi, \nmelakukan deployment, dan \nmemelihara produk \nPendalaman klaster dengan \nstandar profesional \n \n2.1 PBL Semester 1 – Proyek Pengantar Perangkat Lunak \nSemester 1 merupakan tahap awal pengenalan PBL bagi mahasiswa baru. Pada semester ini, mahasiswa \nakan merasakan pengalaman pertama mengembangkan perangkat lunak secara berkelompok. Fokus \nutama adalah pada kemampuan implementasi dan operasi, di mana mahasis wa bekerja berdasarkan \nspesifikasi dan desain yang telah disediakan. Setiap anggota tim akan mendapatkan kesempatan untuk', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(101, 12, 'merasakan peran di sisi front-end maupun back-end, membangun fondasi awal sebagai calon fullstack \ndeveloper. \n▪ Mata Kuliah PBL : IF101 – Pengantar Proyek Perangkat Lunak \n▪ Fokus CDIO : I-O (Implementasi - Operasi) \n▪ Target Capaian : Mampu menulis kode sesuai spesifikasi dan menjalankan produk \n sederhana \n▪ Jumlah Anggota Tim : 3-4 mahasiswa \n▪ Sumber Topik : 8 judul standar yang digunakan bersama antar kelas \nMata Kuliah Pendukung dan Perannya: \n1. IF101 – Pengantar Proyek Perangkat Lunak \nMata kuliah ini adalah induk PBL itu sendiri. Di sini mahasiswa belajar dasar-dasar manajemen \nproyek, cara kerja tim, dan keterampilan presentasi. Semua panduan mingguan PBL ada di \nLearning mata kuliah ini. \n2. IF102 – Pengantar Teknologi Informasi \nMembantu mahasiswa terbiasa dengan tools perkantoran (Word, Excel) untuk membuat \nlaporan. Juga mengenalkan konsep berpikir komputasional dan pemahaman dasar tentang \nperangkat lunak. \n3. IF103 – Dasar Pemrograman Web \nMemberikan dasar HTML, CSS, dan JavaScript untuk membuat halaman web. Ini bekal utama \nuntuk membangun antarmuka pengguna (front-end) di proyek. \n4. IF104 – Dasar Pemrograman \nMelatih logika dan algoritma pemrograman. Mahasiswa belajar menulis kode sederhana \nsebagai fondasi membuat aplikasi. \n5. IF105 – Sistem Komputer \nMengajarkan cara instalasi aplikasi, penggunaan sistem operasi, dan perintah dasar di \nterminal/command line. Bekal untuk menyiapkan lingkungan coding di laptop masing-masing. \nKarakteristik Proyek Semester 1: \n▪ Desain dan spesifikasi telah disediakan sepenuhnya oleh dosen/Manpro, mahasiswa fokus pada \nimplementasi \n▪ Setiap anggota merasakan kedua sisi front -end dan back -end melalui pembagian tugas yang \nbergantian \n▪ Proyek bersifat individu dalam tim, setiap anggota memiliki tanggung jawab pada modul \ntertentu \n▪ Produk yang dihasilkan berupa program sederhana yang berfungsi sesuai spesifikasi \n▪ Pengenalan tools seperti GitHub untuk manajemen kode dan Siap-PBL untuk pelaporan', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(102, 12, '2.2 PBL Semester 2 – Proyek Pembuatan Prototipe \nMemasuki Semester 2, mahasiswa mulai diberikan tanggung jawab lebih dalam proses pengembangan. \nMereka tidak hanya mengimplementasikan, tetapi juga belajar merancang solusi sendiri. Fokus pada \ntahap design (d kecil) menjadikan semester ini sebagai momen pen ting untuk melatih kemampuan \nanalisis dan perancangan. Mahasiswa akan membuat use case diagram, ERD, wireframe, dan \nmewujudkannya menjadi prototipe yang berfungsi. Setiap tim juga didorong untuk menambahkan fitur \nunik sebagai bentuk kreativitas. \n▪ Mata Kuliah PBL : IF207 – Proyek Pembuatan Prototipe \n▪ Fokus CDIO : d-I-O (Desain - Implementasi - Operasi) \n▪ Target Capaian : Mampu membuat desain antarmuka dan basis data sederhana, lalu \n mewujudkannya menjadi prototipe yang berfungsi \n▪ Jumlah Anggota Tim : 2-3 mahasiswa \n▪ Sumber Topik : 10 judul standar yang digunakan bersama antar kelas \n \nMata Kuliah Pendukung dan Perannya: \n1. IF207 – Proyek Pembuatan Prototipe \nMata kuliah ini adalah induk PBL Semester 2. Memberikan waktu khusus di kelas untuk \nmengerjakan proyek, memantau kerja tim, dan presentasi hasil. Semua panduan mingguan ada \ndi Learning. \n2. IF208 – Dasar Rekayasa Perangkat Lunak \nMengajarkan cara menganalisis kebutuhan pengguna, membuat model sistem (use case), dan \ndasar-dasar pengujian perangkat lunak. \n3. IF210 – Pemrograman Web \nMelatih membuat aplikasi web dengan framework Laravel dan Tailwind. Mahasiswa belajar \nmembuat front-end, back-end, dan menghubungkan ke database lewat API. \n4. IF211 – Basis Data \nMemberikan kemampuan menganalisis kebutuhan data, merancang database, dan \nmengimplementasikannya dalam bentuk tabel relasional. \n5. IF212 – Pemrograman Berorientasi Objek \nMengajarkan konsep OOP (class, object, inheritance) dan cara menerapkannya dalam \npemrograman web. \n6. IF213 – Bahasa Inggris untuk Komunikasi \nMelatih kemampuan komunikasi lisan dan tulisan dalam bahasa Inggris, termasuk persiapan \npresentasi proyek dalam bahasa Inggris.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(103, 12, 'Karakteristik Proyek Semester 2: \n▪ Deskripsi masalah desain umum diberikan, namun desain solusi detailnya dibuat sepenuhnya \noleh mahasiswa \n▪ Mahasiswa belajar membuat use case diagram, ERD, dan wireframe secara mandiri \n▪ Implementasi dilakukan sesuai desain sendiri, menguji konsistensi antara rancangan dan hasil \nakhir \n▪ Fitur unik wajib ditambahkan setiap tim untuk mendorong kreativitas dan membedakan antar \nkelompok \n▪ Produk yang dihasilkan berupa prototipe fungsional dengan desain original \n \n2.3 PBL Semester 3 – Proyek Inovasi Agile \nSemester 3 menjadi titik penting dalam perjalanan PBL mahasiswa. Pada tahap ini, mereka mulai \nmerumuskan ide sendiri ( conceive) dan menjalani seluruh siklus CDIO dengan pendekatan Agile. \nMahasiswa juga memilih klaster bidang sesuai minat dan rencana karir, yaitu Web & Mobile, IoT, AI, \natau Infrastruktur IT. Proyek dikerjakan untuk klien internal seperti dosen, institusi, atau keb utuhan \nlomba, sehingga mahasiswa belajar berinteraksi dengan pengguna nyata meskipun masih dalam \nlingkungan kampus. \n▪ Mata Kuliah PBL : IF314 – Proyek Inovasi Agile \n▪ Fokus CDIO : c-D-I-O (Konsepsi - Desain - Implementasi - Operasi) \n▪ Target Capaian : Mampu merumuskan ide, merancang, mengimplementasi, dan \n menguji proyek secara berkelompok dengan metodologi Agile \n▪ Jumlah Anggota Tim : 3-4 mahasiswa \n▪ Sumber Topik : Klien internal/external (dosen, institusi, lomba mahasiswa, DUDI) \n \nMata Kuliah Pendukung dan Perannya: \n1. IF314 – Proyek Inovasi Agile \nInduk PBL Semester 3. Wadah utama mengerjakan proyek dengan metode Agile. Ada sesi \nmonitoring progres, presentasi, dan diskusi dengan dosen. Detail mingguan ada di Learning. \n2. IF315 – Rekayasa Perangkat Lunak Lanjut \nMembekali kemampuan merancang arsitektur software, menggunakan design pattern, dan \ndokumentasi teknis tingkat lanjut. \n3. IF316 – Mata Kuliah Pilihan 1', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(104, 12, 'Mahasiswa memilih bidang sesuai minat. Pilihan ini akan menentukan judul PBL yang \ndikerjakan. Bidang yang tersedia: Web Development, Mobile Application, IoT, AI, dan \nInfrastruktur IT. \n4. IF317 – Interaksi Manusia dan Komputer (IMK) \nMengajarkan cara merancang antarmuka yang ramah pengguna, mengatur interaksi, dan \nmelakukan pengujian agar aplikasi mudah dipakai. \n5. IF318 – Statistika \nMemberikan pengetahuan statistika untuk mendukung analisis data, pengolahan data, dan \npengujian dalam pengembangan software. \n6. PK1IF – Pendidikan Agama \nMata kuliah umum wajib. Dilaksanakan daring sesuai agama masing-masing. \n7. PK3IF – Pendidikan Kewarganegaraan \nMata kuliah umum wajib. Ada tugas proyek kewarganegaraan yang relevan dengan isu \nkebangsaan. \nKarakteristik Proyek Semester 3: \n▪ Mahasiswa dapat merumuskan ide sendiri untuk keperluan lomba atau sejenisnya, mengerjakan \nproyek dari klien internal atau external. \n▪ Menggunakan metodologi Agile dengan sprint, backlog, daily standup, dan sprint review \n▪ Produk dikembangkan secara iteratif dengan melibatkan feedback dari klien dan Manpro \n▪ Klaster bidang mulai diterapkan sesuai pilihan minat mahasiswa \n \n2.4 PBL Semester 4 – Proyek Perangkat Lunak Industri \nSemester 4 merupakan puncak dari rangkaian PBL akademik sebelum mahasiswa menjalani magang \ndan capstone project. Pada tahap ini, mahasiswa bekerja dengan klien eksternal (industri, instansi, atau \nmasyarakat) dan dituntut untuk menghasilkan produk dengan standar profesional. Tim diperkecil \nmenjadi 2 orang sebagai simulasi capstone project yang akan datang di Semester 5-6. Seluruh tahapan \nCDIO dijalankan secara mandiri, mulai dari analisis kebutuhan, desain, implementasi, deployment, \nhingga serah terima produk kepada klien. \n▪ Mata Kuliah PBL : IF419 – Proyek Perangkat Lunak Industri \n▪ Fokus CDIO : C-D-I-O (Konsepsi - Desain - Implementasi - Operasi) \n▪ Target Capaian : Mampu bekerja dengan klien riil, merancang solusi sesuai standar \n industri, mengimplementasi, melakukan deployment, dan \n memelihara produk \n▪ Jumlah Anggota Tim : 2 mahasiswa (simulasi capstone project) \n▪ Sumber Topik : Klien eksternal (industri, instansi, masyarakat)', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(105, 12, 'Mata Kuliah Pendukung dan Perannya: \n1. IF419 – Proyek Perangkat Lunak Industri \nInduk PBL Semester 4. Monitoring progres dan presentasi proyek ke dosen. Mahasiswa \nmelanjutkan bidang yang sama seperti Semester 3. \n2. IF420 – Mata Kuliah Pilihan 2 \nPendalaman lebih lanjut sesuai bidang yang dipilih di Semester 3. Tersedia pilihan: Web, \nMobile, IoT, AI, Infrastruktur IT. \n3. IF421 – Instalasi dan Perawatan Perangkat Lunak \nMengajarkan cara deployment aplikasi ke server, konfigurasi server, maintenance, dan \nmenggunakan version control (Git). \n4. IF422 – Pengujian Perangkat Lunak \nMelatih pengujian fungsional (black box, UAT) dan non-fungsional (load test, stress test) untuk \nmemastikan kualitas software. \n5. IF424 – Bahasa Inggris untuk Bisnis \nMempersiapkan mahasiswa untuk magang di Semester 5. Fokus pada komunikasi bisnis dan \npresentasi proyek dalam bahasa Inggris. Presentasi ATS dan AAS Semester 4 dilakukan dalam \nbahasa Inggris. \n6. PK4IF – Pendidikan Bahasa Indonesia \nMata kuliah umum wajib. Mengajarkan penggunaan bahasa Indonesia yang baik dan benar, \nterutama untuk menyusun laporan teknis. \nKarakteristik Proyek Semester 4: \n▪ Proyek dengan permasalahan riil. \n▪ Tim kecil (2 orang) mensimulasikan kondisi capstone project yang akan datang \n▪ Produk wajib di-deploy dan dapat digunakan langsung oleh pengguna \n▪ Menjadi fondasi untuk capstone project di Semester 5-6', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(106, 12, 'BAB 3 PANDUAN ASESMEN PBL \n \n3.1 Mekanisme Asesmen PBL \nAsesmen dalam PBL dilaksanakan untuk mengevaluasi capaian pembelajaran mahasiswa, baik dari sisi \nproses maupun hasil proyek. Melalui asesmen ini, mahasiswa tidak hanya dinilai berdasarkan kualitas \nproduk yang dihasilkan, tetapi juga kemampuan dalam menyampaikan ide, mempertanggungjawabkan \nhasil karya, serta menjawab pertanyaan reviewer. Kegiatan asesmen menjadi sarana penting untuk \nmelatih keterampilan presentasi dan komunikasi profesional yang akan sangat berguna di dunia kerja. \nTujuan : Mengevaluasi capaian proyek, melatih presentasi, dan mempertanggungjawabkan \n hasil karya \nWaktu : Minggu ATS dan AAS (sesuai kalender akademik) \nPrasyarat : Semua luaran sudah diunggah di Siap-PBL \nPakaian : Kemeja putih + bawahan gelap + almamater \nReviewer : 2 orang (dosen/Manpro/praktisi) \n \n3.2 Luaran Asesmen Tengah Semester (ATS) \nAsesmen Tengah Semester (ATS) bertujuan untuk memantau perkembangan pengerjaan proyek serta \nmengevaluasi pemahaman mahasiswa terhadap tahapan yang telah dilalui. Setiap kelompok wajib \nmengumpulkan luaran ATS melalui Siap-PBL yang terdiri dari: \n1. File Presentasi \nSlide presentasi capaian proyek dalam format bebas (PDF/PPT). Konten slide disusun secara \nkomunikatif dan bertanggungjawab untuk menjelaskan progres yang telah dicapai. \n2. Tautan Video Presentasi \nTautan YouTube video presentasi yang diunggah dengan mode Public dan komentar aktif. \nVideo berisi penjelasan berdasarkan slide yang telah dibuat. \n3. Link Tambahan \nTautan Google Drive folder yang berisi dokumen pendukung. Akses folder diatur sehingga \nsiapa pun yang memiliki link dapat melihat. Dokumen yang wajib disertakan dalam folder ini \nmeliputi: \n▪ Laporan kemajuan sesuai template yang tersedia \n▪ Link kode implementasi front-end (untuk Semester 1) atau dokumen pendukung \nlainnya sesuai ketentuan tiap semester', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(107, 12, '▪ Dokumen tambahan lainnya jika ada permintaan khusus dari dosen mata kuliah \npendukung \nIsi folder tautan tambahan dapat berbeda setiap semester sesuai dengan tahapan PBL dan \nkebutuhan asesmen. Informasi lebih detail mengenai isi folder akan diumumkan melalui \nLearning mata kuliah proyek masing-masing. \n \n3.3 Luaran Asesmen Akhir Semester (AAS) \nAsesmen Akhir Semester (AAS) merupakan puncak evaluasi proyek yang bertujuan untuk menilai hasil \nakhir dari seluruh rangkaian pengerjaan PBL. Pada tahap ini, mahasiswa diharapkan mampu \nmenunjukkan produk jadi yang lengkap, didukung dengan dokumentasi profe sional, serta mampu \nmempresentasikan dan mempertanggungjawabkan hasil karyanya di hadapan reviewer. Kelengkapan \ndan kualitas luaran AAS menjadi penentu utama keberhasilan proyek di setiap semester. Tabel 6 berikut \nadalah daftar luaran yang wajib dikumpulkan pada AAS di setiap semester.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(108, 12, 'Tabel 6. Luaran AAS \nNo Luaran AAS Sem 1 Sem 2 Sem 3 Sem 4 Keterangan \n1 File Presentasi ✓ ✓ ✓ ✓ Slide presentasi final \n2 Laporan Akhir PBL ✓ ✓ ✓ ✓ Sesuai template di Learning \n3 Poster ✓ ✓ ✓ ✓ A2, portrait, PDF, Bahasa Inggris \n4 Manual Book ✓ ✓ ✓ ✓ PDF, Bahasa Indonesia, 5-15 halaman \n5 Berita Acara Serah \nTerima (BAST) \n✓ ✓ ✓ ✓ Format FO.5.3.1-V5 \n6 Video Presentasi ▪ Maks: 10\' \n▪ B.Indonesia \n▪ Zoom / Google Meet \n/ OBS / Handphone \n(thumbnail wajah di \npojok kanan bawah) \n▪ Maks: 7\' \n▪ B.Inggris \n▪ Zoom / Google \nMeet / OBS / \nHandphone \n(thumbnail wajah di \npojok kanan bawah) \n▪ Maks: 7\' \n▪ B.Indonesia \n▪ Rekaman \nlangsung \ndalam satu \nruangan \n▪ Maks: 10\' \n▪ B.Inggris \n▪ Rekaman \nlangsung \ndalam \nsatu \nruangan \n▪ YouTube Public, \n▪ Komentar aktif \n▪ Deskripsi YouTube berisi: judul \nproyek, deskripsi proyek, nama dan \nNIM seluruh anggota tim, serta \nalamat email ketua kelompok \n7 Video Demo ✓ ✓ ✓ ✓ Maks 3 menit, 720p, YouTube \n8 Produk PBL (Source \nCode) \n✓ ✓ ✓ ✓ Repository di GitHub \n9 Dokumen HKI - - Opsional Opsional Sesuai rekomendasi Manpro', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(109, 12, '3.4 Format Asesmen (Informasi Detail di Learning) \nFormat pelaksanaan asesmen (ATS dan AAS) tidak ditetapkan secara kaku dalam panduan ini agar \ndapat disesuaikan dengan kebutuhan dan kondisi setiap tahun ajaran. Informasi lengkap mengenai \nteknis pelaksanaan akan diumumkan melalui Learning mata kuliah proyek masing-masing, mencakup: \n▪ Bentuk Kegiatan Asesmen \nKegiatan asesmen dapat bervariasi setiap tahunnya, disesuaikan dengan capaian pembelajaran \nyang ingin dievaluasi serta situasi dan kondisi yang ada. Beberapa bentuk kegiatan yang \nmungkin dilaksanakan antara lain presentasi formal di hadapan reviewer, gallery walk di mana \nreviewer berkeliling menilai setiap tim, client review yang melibatkan klien langsung, podcast \nsebagai media presentasi alternatif, expo atau pameran karya, serta bentuk kegiatan lain yang \nrelevan. \n▪ Jadwal dan Mekanisme Pelaksanaan \nJadwal pelaksanaan asesmen akan diinformasikan secara rinci melalui Learning, meliputi hari \ndan tanggal pelaksanaan, pembagian sesi atau shift untuk setiap tim, alur kegiatan selama \nasesmen berlangsung, serta durasi yang dialokasikan untuk setiap tim. Maha siswa wajib \nmemperhatikan jadwal yang telah ditetapkan dan hadir tepat waktu sesuai sesi masing-masing. \n▪ Pembagian Ruangan dan Reviewer \nInformasi mengenai pembagian ruangan akan diumumkan sebelum pelaksanaan asesmen, \ntermasuk pengelompokan tim berdasarkan judul proyek atau kelas, serta penempatan di ruang-\nruang yang telah disediakan. Identitas reviewer yang akan menilai juga akan diinforma sikan, \nsehingga mahasiswa dapat mempersiapkan diri dengan baik. \n▪ Hal-hal Teknis yang Perlu Dipersiapkan \nMahasiswa wajib mempersiapkan berbagai kebutuhan teknis sesuai bentuk asesmen yang akan \ndilaksanakan, seperti perlengkapan presentasi (laptop, adaptor, pointer), materi pendukung \n(poster, booklet, atau alat peraga), koneksi internet jika asesmen dilaksanak an secara daring, \nserta dokumen fisik yang mungkin diperlukan. Informasi lebih rinci akan disampaikan melalui \nLearning mendekati hari pelaksanaan. \nDengan demikian, setiap angkatan dapat memiliki pengalaman asesmen yang variatif dan sesuai \nkonteks, tanpa terikat pada format yang kaku dari tahun ke tahun. Mahasiswa diharapkan secara aktif \nmemantau Learning mata kuliah proyek untuk mendapatkan informasi terbaru mengenai pelaksanaan \nasesmen.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(110, 12, '3.5 Pengumpulan Luaran \nPengumpulan semua luaran ATS dan AAS dilakukan melalui platform Siap -PBL. Untuk luaran ATS, \nmahasiswa mengunggah berkas pada menu Berkas ATS, sedangkan untuk luaran AAS diunggah pada \nmenu Berkas AAS. \n▪ Prasyarat Pengumpulan Luaran \nSebelum dapat mengunggah luaran, Manajer Proyek (Manpro) wajib memberikan review \nprogress dan feedback terlebih dahulu melalui fitur yang tersedia di Siap -PBL. Review ini \nmenjadi tanda bahwa tim telah mendapatkan persetujuan dan masukan atas progres yang telah \ndicapai. Setelah review diberikan, barulah menu unggah berkas akan aktif dan tim dapat \nmengumpulkan luaran asesmen. \nMengingat seringnya kendala teknis terkait hal ini, mahasiswa diimbau untuk secara proaktif \nmengingatkan Manpro untuk memberikan review progress minimal 3 -4 hari sebelum batas \nakhir pengumpulan. Komunikasi yang baik antara ketua tim dan Manpro sangat diperlukan agar \nproses pengumpulan luaran berjalan lancar dan tidak mepet dengan tenggat waktu. \n \n▪ Batas Waktu Pengumpulan \nBatas waktu pengumpulan mengikuti pengumuman yang disampaikan melalui Learning mata \nkuliah proyek masing-masing. \n \n▪ Hal-hal yang Perlu Diperhatikan \nTerdapat beberapa hal penting yang perlu diperhatikan dalam pengumpulan luaran. \no Pertama, pastikan semua file telah diunggah secara lengkap sebelum batas waktu yang \nditentukan. Kelengkapan berkas menjadi prasyarat utama untuk dapat mengikuti sesi \npresentasi asesmen. \no Kedua, mahasiswa yang tidak mengumpulkan luaran hingga batas waktu yang \nditetapkan tidak akan dijadwalkan untuk presentasi dan konsekuensinya tidak akan \nmendapatkan nilai asesmen. \no Ketiga, untuk luaran yang dikumpulkan dalam bentuk tautan tambahan (Google Drive), \npastikan akses folder diatur menjadi \"siapa pun yang memiliki link dapat melihat\" \nagar reviewer dapat membuka dan menilai dokumen tersebut. \nDengan mematuhi ketentuan pengumpulan ini serta menjaga komunikasi yang baik dengan Manpro, \nmahasiswa telah memenuhi prasyarat utama untuk mengikuti rangkaian asesmen dan memperoleh \npenilaian atas capaian proyeknya.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(111, 12, 'BAB 4 INFRASTRUKTUR DAN PENDUKUNG \n \n4.1 Platform dan Tools Pendukung \nDalam pelaksanaan PBL, mahasiswa wajib menggunakan beberapa platform digital yang telah \ndisediakan oleh kampus maupun platform umum yang telah ditetapkan. Platform-platform ini berfungsi \nuntuk mengelola proyek, menyimpan kode program, mempublikasikan video, serta mengumpulkan \nluaran asesmen. \nSiap-PBL merupakan aplikasi utama untuk mengelola seluruh kegiatan PBL. Platform ini dapat diakses \nmelalui laman https://pbl.polibatam.ac.id menggunakan akun SSO Polibatam (sama dengan akun \nLearning). Melalui Siap-PBL, dosen dapat membentuk tim dan menunjuk ketua kelompok. Ketua tim \nkemudian dapat menambahkan anggota timnya. Fitur logbook kegiatan memungkinkan setiap anggota \nmencatat aktivitas harian atau mingguan selama pengerjaan proyek. Platform ini juga digunakan untuk \nmengumpulkan semua luaran ATS dan AAS melalui menu Berkas ATS dan Berkas AAS. Tutorial \npenggunaan Siap-PBL dapat dilihat di https://www.youtube.com/watch?v=ij4uUrRiUp4. \nE-Learning (https://learning -if.polibatam.ac.id) menjadi sumber informasi utama untuk setiap mata \nkuliah proyek. Di sini mahasiswa dapat mengakses materi perkuliahan, pengumuman terkait PBL, \ntemplate laporan, serta informasi detail mengenai format asesmen setiap semester. Mahasiswa wajib \nmemantau Learning secara rutin karena semua informasi penting akan diumumkan melalui platform \nini. \nGitHub digunakan sebagai tempat penyimpanan source code proyek. Setiap tim wajib membuat \nrepository dengan status private untuk menjaga kerahasiaan kode. Dosen pembimbing harus \nditambahkan sebagai kolaborator agar dapat melakukan peninjauan. Repository harus memiliki struktur \nyang rapi, mencakup folder src untuk menyimpan kode program, file database dalam bentuk .sql, dan \nfile README.md yang menjelaskan cara instalasi dan penggunaan aplikasi. Tautan repository GitHub \nini kemudian dikumpulkan melalui Siap-PBL. \nYouTube menjadi platform untuk mempublikasikan video presentasi dan video demo. Semua video \nharus diunggah dengan mode Public dan komentar wajib diaktifkan. Deskripsi video harus memuat \njudul proyek, deskripsi singkat proyek, nama dan NIM seluruh anggota t im, serta alamat email ketua \nkelompok. Video presentasi dan video demo yang telah diunggah tautannya dikumpulkan melalui Siap-\nPBL. \nGoogle Drive digunakan untuk menyimpan file-file pendukung yang tidak dapat diunggah langsung ke \nSiap-PBL. Mahasiswa harus membuat folder khusus untuk proyek, mengatur akses folder menjadi', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(112, 12, 'PBL. \nGoogle Drive digunakan untuk menyimpan file-file pendukung yang tidak dapat diunggah langsung ke \nSiap-PBL. Mahasiswa harus membuat folder khusus untuk proyek, mengatur akses folder menjadi \n\"siapa pun yang memiliki link dapat melihat\", kemudian mengisi fold er dengan dokumen pendukung', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(113, 12, 'seperti laporan kemajuan, link kode implementasi, atau dokumen lain sesuai ketentuan tiap semester. \nTautan folder Google Drive ini kemudian diunggah ke Siap-PBL. \nSelain platform utama tersebut, terdapat beberapa tools pendukung lain yang dapat digunakan \nmahasiswa. Draw.io atau Lucidchart untuk membuat diagram use case dan ERD. Figma untuk \nmendesain antarmuka dan membuat prototipe. XAMPP atau Laragon sebagai server lokal untuk \npengembangan. OBS Studio atau Bandicam untuk merekam layar saat membuat video presentasi. \nCanva untuk mendesain poster. Postman untuk menguji API. Trello atau Jira untuk manajemen proyek \nAgile. \nInformasi lebih lengkap tentang tools ini dapat diakses melalui https://polibatam.id/referensiTools. \n \n4.2 Workspace dan Fasilitas \nProgram studi menyediakan berbagai ruang kerja dan fasilitas yang dapat digunakan mahasiswa untuk \nmengerjakan proyek PBL, baik secara individu maupun berkelompok. Workspace utama berada di \nGedung Utama Lantai 7. Area ini dilengkapi dengan meja, kursi, akses Wi-Fi, dan stop kontak. Selain \nitu, tersedia juga ruang kerja tambahan di Gedung Technopreneur Center dan Gedung Tower A. \nUntuk kebutuhan praktikum dan akses perangkat keras, tersedia beberapa laboratorium komputer. Lab \nPemrograman 1 dan 2 di Gedung Utama Lantai 6 , 7, dan 8 yang digunakan untuk praktikum \npemrograman terstruktur. Lab Jaringan di lantai yang sama dilengkapi dengan perangkat jaringan untuk \npraktikum jaringan komputer. Lab IoT di Gedung Tower A menyediakan perangkat seperti Raspberry \nPi dan berbagai sensor untuk pengembangan proyek IoT. \nMahasiswa dapat melakukan peminjaman ruang dan alat melalui portal \nhttps://peminjaman.polibatam.ac.id. Prosedur peminjaman dilakukan dengan login menggunakan akun \nSSO Polibatam, memilih ruang atau alat yang tersedia, mengajukan permohonan, dan menunggu \npersetujuan dari admin. Peminjaman dilakukan minimal H -2 dan wajib mengembalikan tepat waktu. \nMahasiswa bertanggung jawab penuh atas kerusakan atau kehilangan alat yang dipinjam. \nUntuk peminjaman laptop, kamera, alat IoT, atau perangkat jaringan, dapat dikoordinasikan langsung \ndengan laboran melalui prosedur yang sama di portal peminjaman. Lama peminjaman laptop dan \nkamera maksimal 1-2 hari, sementara alat IoT dan perangkat jaringan dapat dipinjam sesuai kebutuhan \ndengan koordinasi lebih lanjut. \nSelain workspace kampus, mahasiswa juga diperbolehkan mengerjakan proyek di luar kampus seperti \ndi rumah anggota kelompok, tempat umum (kafe, perpustakaan umum), atau lokasi mitra/klien. Namun', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(114, 12, 'dengan koordinasi lebih lanjut. \nSelain workspace kampus, mahasiswa juga diperbolehkan mengerjakan proyek di luar kampus seperti \ndi rumah anggota kelompok, tempat umum (kafe, perpustakaan umum), atau lokasi mitra/klien. Namun \ndemikian, mahasiswa wajib tetap menjaga etika, mematuhi aturan tempat yang dikunjungi, \nmemprioritaskan keamanan, serta mendokumentasikan kegiatan sebagai bukti pengisian logbook.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL);
INSERT INTO `chunks` (`chunk_id`, `document_id`, `chunk_text`, `created_at`, `edited_at`, `deleted_at`) VALUES
(115, 12, 'BAB 5 PENUTUP \n \nPBL merupakan metode pembelajaran inti di Program Studi D3 Teknik Informatika yang dirancang \nuntuk menghasilkan lulusan yang kompeten, profesional, dan siap kerja. Melalui PBL yang \ndilaksanakan secara bertahap selama 4 semester, mahasiswa dibangun kemampuannya secara progresif \nmulai dari kemampuan implementasi dasar di Semester 1, kemampuan merancang di Semester 2, \nkemampuan bekerja dengan metodologi Agile di Semester 3, hingga kemampuan profesional bersama \nklien riil di Semester 4. Semua tahapan ini dirancang dalam kerangka CDIO yang diadaptasi sesuai \ntingkat kemandirian mahasiswa. \nDukungan dari berbagai mata kuliah pendukung, keterlibatan Manajer Proyek dan Co-Manajer Proyek, \nserta ketersediaan infrastruktur dan platform digital menjadi faktor penting keberhasilan PBL. Integrasi \nantara teori, praktikum, dan PBL memastikan bahwa mahasiswa tidak hanya memahami konsep, tetapi \njuga terampil mengaplikasikannya dalam proyek nyata. \nKepada seluruh mahasiswa Program Studi D3 Teknik Informatika, beberapa pesan penting perlu selalu \ndiingat dalam menjalani PBL: \n• Pertama, pahami alur PBL di setiap semester. Setiap semester memiliki fokus dan target capaian \nberbeda. Jalani setiap tahap dengan sungguh -sungguh karena semuanya dirancang untuk \nmembangun kompetensi Anda secara bertahap. \n• Kedua, kenali dan jalankan peran Anda dengan baik. Sebagai mahasiswa, Anda adalah \npelaksana utama proyek. Hadir tepat waktu, berkontribusi aktif, berkomunikasi terbuka dengan \ntim, dan dokumentasikan setiap pekerjaan di logbook. \n• Ketiga, manfaatkan mata kuliah pendukung sebaik mungkin. Setiap mata kuliah teori dan \npraktikum yang Anda pelajari memiliki keterkaitan langsung dengan PBL. Jangan anggap \nremeh praktikum karena di sanalah Anda membangun keterampilan teknis yang akan \nditerapkan di proyek. \n• Keempat, jaga komunikasi dengan Manpro dan dosen pembimbing. Konsultasikan setiap \nkendala yang dihadapi, mintalah masukan secara rutin, dan tindak lanjuti feedback yang \ndiberikan. \n• Kelima, bangun portofolio sejak dini. Setiap proyek PBL yang Anda kerjakan adalah aset \nberharga yang dapat ditunjukkan kepada calon pemberi kerja. Dokumentasikan dengan baik, \nsimpan source code, dan buat video demo yang menarik.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(116, 12, 'Program Studi D3 Teknik Informatika berkomitmen untuk terus meningkatkan kualitas pelaksanaan \nPBL melalui: \n• Peningkatan kapasitas Manajer Proyek melalui pelatihan dan workshop secara berkala \n• Pengembangan repository topik proyek yang relevan dengan kebutuhan industri \n• Peningkatan infrastruktur dan fasilitas pendukung PBL \n• Evaluasi berkelanjutan terhadap pelaksanaan PBL setiap semester \n• Penguatan kerjasama dengan industri untuk penyediaan proyek dan kesempatan magang \nDemikian panduan ini disusun. Semoga dapat menjadi acuan yang jelas bagi seluruh pihak dalam \nmelaksanakan PBL di Program Studi D3 Teknik Informatika. Dengan komitmen bersama antara \nmahasiswa, dosen, Manajer Proyek, dan tenaga kependidikan, kami yakin PBL akan menghasilkan \nlulusan yang berkualitas, kompetitif, dan siap berkontribusi di dunia industri.', '2026-06-02 13:08:55', '2026-06-02 13:08:55', NULL),
(117, 13, 'No.FO.21.1.1-V3 Format Pedoman Pembelajaran Mahasiswa \nPoliteknik Negeri Batam \n8 September 2021 \n \n \n \n \n \n \n \n \n \n \n \n \n \nDaftar Isi \n \n \n \n \n \nKata Pengantar\nJanji Mahasiswa \nPeraturan Akademik\nPeraturan Kemahasiswaan', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(118, 13, 'No.FO.21.1.1-V3 Format Pedoman Pembelajaran Mahasiswa \nPoliteknik Negeri Batam \n8 September 2021 \n \n \n \n \nPENGANTAR \n \n \nPertama, mari kita sambut tahun ajaran 2025/2026 dengan rasa syukur dan suka \ncita atas berbagai capaian selama ini. \n \nKedua, Politeknik Negeri Batam senantiasa siap menyambut masa depan yang \nlebih baik. Dunia berubah dan demikian pula teknologi serta lingkungan industri \nkita semakin dinamis. Sebagai institusi pendidikan yang berorientasi pada \npemenuhan kebutuhan industri, Politeknik Negeri Batam harus mampu \nberadaptasi dan menjawab berbagai dinamika tersebut. Oleh karena itu, Panduan \nPembelajaran Politeknik Negeri Batam tahun 2025 dan beberapa kebijakan lain \nyang diterbitkan tahun ini memuat instrumen baru untuk megantisipasi berbagai \nperubahan, di antaranya pola pembelajaran kombinasi , rekognisi pembelajaran \nlampau, merdeka belajar, pembelajaran berbasis masalah/proyek/produk, dan \naktifitas kemahasiswaan. \n \nKetiga, Panduan Pembelajaran Politeknik Negeri Batam tahun 202 5 disusun \nutamanya sebagai panduan bagi mahasiswa dalam menjalani kehidupan \nakademik dan kemahasiswaan di kampus. Selain itu, panduan ini ditetapkan agar \ntenaga kependidikan, dosen, dan seluruh civitas akademika dapat melaksanakan \nproses pembelajaran dan mengembangkan aktifitas kemahasiswaan dengan baik \ndan selaras dengan tujuan Politeknik Negeri Batam. Harapannya, panduan ini \nsemakin selaras dengan tujuan Politeknik Negeri Batam untuk menghasilkan \nlulusan yang relevan dengan kebutuhan seluruh pemangku kepentingan. \n \nSemoga Allah selalu memberkati setiap langkah kita.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(119, 13, 'No.FO.21.1.1-V3 Format Pedoman Pembelajaran Mahasiswa \nPoliteknik Negeri Batam \n8 September 2021 \n \n \n \nJANJI MAHASISWA POLIBATAM \n \nKami, segenap Mahasiswa Polibatam, \ndemi Nusa dan Bangsa, \nberjanji akan bersungguh-sungguh \nmenuntut ilmu dan keterampilan \nagar dapat menjadi tenaga kompeten \nberwawasan dan berpotensi belajar tinggi \n \nKami, segenap Mahasiswa Polibatam, \nberjanji akan bersungguh-sungguh \nmeningkatkan kemampuan dan keterampilan \nagar dapat menjadi tenaga kompeten \nberkemampuan berkembang, tangguh, ulet dan mandiri \n \nKami, segenap Mahasiswa Polibatam, \nberjanji akan menegakkan dan menjunjung tinggi \nkejujuran, keluhuran pendidikan, \nserta susila mahasiswa \nagar dapat menjadi tenaga kompeten \nberbudi pekerti luhur, berakhlak mulia, \ndan berdasarkan Pancasila \n \nKami berjanji akan setia pada almamater Polibatam \nserta bangsa dan negara Republik Indonesia \n \nDemi itu, kami mohon Tuhanku, \nRahmat serta tuntunan Mu', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(120, 13, 'DAFTAR ISI \n \nBAB I PROGRAM PENDIDIKAN DAN STANDAR KOMPETENSI LULUSAN ............ 1 \nBagian Kesatu Program Pendidikan .................................................................................... 1 \nBagian Kedua Standar Kompetensi Lulusan .................................................................... 1 \nBagian Ketiga Kompetensi Utama Lulusan ....................................................................... 2 \nBAB II KURIKULUM DAN PEMBELAJARAN ....................................................................... 3 \nBagian Kesatu Kurikulum ....................................................................................................... 3 \nBagian Kedua Proses Pembelajaran ..................................................................................... 4 \nBAB III MASA DAN BEBAN BELAJAR .................................................................................. 6 \nBagian Kesatu Masa Tempuh Kurikulum dan Masa Studi ......................................... 6 \nBagian Kedua Beban Belajar .................................................................................................. 7 \nBagian Ketiga Pemenuhan Masa dan Beban Belajar ..................................................... 8 \nBAB IV MAHASISWA BARU ....................................................................................................... 8 \nBagian Kesatu Penerimaan Mahasiswa Baru ................................................................... 8 \nBagian Kedua Pembatalan Penerimaan .............................................................................. 9 \nBagian Ketiga Keabsahan Sebagai Mahasiswa ................................................................ 9 \nBagian Keempat Mahasiswa Khusus ................................................................................ 10 \nBagian Kelima Mahasiswa Asing ........................................................................................ 10 \nBAB V DAFTAR ULANG ............................................................................................................ 10 \nBagian Kesatu Proses Daftar Ulang ................................................................................... 10 \nBagian Kedua Mahasiswa Tidak Daftar Ulang ............................................................... 11 \nBagian Ketiga Pindah Kelas .................................................................................................. 11 \nBAB VI IDENTITAS MAHASISWA DAN KEGIATAN AKADEMIK .............................. 11', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(121, 13, 'Bagian Ketiga Pindah Kelas .................................................................................................. 11 \nBAB VI IDENTITAS MAHASISWA DAN KEGIATAN AKADEMIK .............................. 11 \nBagian Kesatu Identitas Mahasiswa .................................................................................. 11 \nBagian Kedua Kegiatan Akademik ..................................................................................... 12 \nBagian Ketiga Kalender Akademik ..................................................................................... 12 \nBagian Keempat Perwalian Akademik ............................................................................... 12 \nBagian Kelima Perkuliahan dan Layanan Mahasiswa ................................................. 13 \nBAB VII CUTI AKADEMIK DAN PENGHENTIAN STUDI .............................................. 14 \nBagian Kesatu Cuti Akademik ............................................................................................. 14 \nBagian Kedua Penghentian Studi ....................................................................................... 15 \nBAB VIII EVALUASI AKADEMIK MAHASISWA ............................................................... 15 \nBagian Kesatu Penilaian Hasil Belajar .............................................................................. 15 \nBagian Kedua Peserta Penilaian Hasil Belajar ............................................................... 17 \nBagian Ketiga Yudisium dan Predikat Kelulusan ......................................................... 18 \nBagian Kelima Laporan Kinerja Akademik dan Ijazah ................................................ 18 \nBAB VII SARANA DAN PRASARANA.................................................................................... 19 \nBagian Kesatu Pengelolaan Fasilitas Perkuliahan ........................................................ 19 \nBagian Kedua Pemanfaatan Workspace, Laboratorium,Workshop, atau Studio 20 \nBagian Ketiga Layanan Sistem Informasi ........................................................................ 20 \nBagian Keempat Layanan Perpustakaan ......................................................................... 21 \nBagian Kelima Pemeliharaan Kebersihan dan Kesehatan Lingkungan ................. 21 \nBagian Keenam Penggunaan Fasilitas Umum ............................................................... 22 \nBagian Ketujuh Pertanggungjawaban terhadap Barang Milik Polibatam ............. 22', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(122, 13, 'Bagian Keenam Penggunaan Fasilitas Umum ............................................................... 22 \nBagian Ketujuh Pertanggungjawaban terhadap Barang Milik Polibatam ............. 22 \nBAB VIII KECURANGAN AKADEMIK DAN SANKSINYA .............................................. 23 \nBagian Kesatu Kecurangan Akademik .............................................................................. 23 \nBagian Kedua Sanksi Kecurangan Akademik ................................................................ 23', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(123, 13, '1 \nBAB I \nPROGRAM PENDIDIKAN DAN STANDAR KOMPETENSI LULUSAN \n \nBagian Kesatu \nProgram Pendidikan \n \nPasal 1 \n \n(1) Politeknik Negeri Batam (Polibatam) menyelenggarakan program pendidikan \nvokasi yang terdiri dari: \na. Program pendidikan Diploma Dua. \nb. Program Pendidikan Diploma Tiga. \nc. Program Pendidikan Sarjana Terapan. \nd. Program Pendidikan Profesi. \ne. Program Pendidikan Magister Terapan. \n \n \nBagian Kedua \nStandar Kompetensi Lulusan \n \nPasal 2 \n \n(1) Standar kompetensi lulusan merupakan kriteria minimal mengenai kesatuan \nkompetensi sikap, keterampilan, dan pengetahuan yang menunjukkan \ncapaian mahasiswa dari hasil pembelajarannya pada akhir program \npendidikan tinggi di Polibatam. \n(2) Standar kompetensi lulusan sebagaimana dimaksud pada ayat (1) digunakan \nuntuk menyiapkan mahasiswa menjadi anggota masyarakat yang beriman, \nbertakwa, berakhlak mulia, berkarakter sesuai dengan nilai -nilai Pancasila, \nmampu dan mandiri untuk menerapkan, mengembangkan, menemukan ilmu \npengetahuan dan teknologi yang bermanfaat bagi masyarakat, serta secara \naktif mengembangkan potensinya. \n(3) Standar kompetensi lulusan sebagaimana dimaksud pada ayat (1) \ndirumuskan dalam capaian pembelajaran lulusan (CPL) untuk setiap \nprogram studi. \n(4) CPL untuk setiap program studi, sebagaimana dimaksud dalam ayat (3) \nmencakup kompetensi yang meliputi: \na. penguasaan ilmu pengetahuan dan teknologi, kecakapan/keterampilan \nspesifik dan aplikasinya untuk 1 (satu) atau sekumpulan bidang keilmuan \ntertentu; \nb. kecakapan umum yang dibutuhkan sebagai dasar untuk penguasaan \nilmu pengetahuan dan teknologi serta bidang kerja yang relevan; \nc. pengetahuan dan keterampilan yang dibutuhkan untuk dunia kerja \ndan/atau melanjutkan studi pada jenjang yang lebih tinggi ataupun \nuntuk mendapatkan sertifikat profesi; dan \nd. kemampuan intelektual untuk berpikir secara mandiri dan kritis sebagai \npembelajar sepanjang hayat.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(124, 13, '2 \n(5) CPL sebagaimana dimaksud dalam ayat (3) disusun oleh unit pengelola \nprogram studi dengan melibatkan: \na. pemangku kepentingan; dan/atau \nb. dunia usaha, dunia industri, dan dunia kerja. \n(6) CPL sebagaimana dimaksud pada ayat (3) memperhatikan: \na. visi dan misi perguruan tinggi; \nb. kerangka kualifikasi nasional Indonesia; \nc. perkembangan ilmu pengetahuan dan teknologi; \nd. kebutuhan kompetensi kerja dari dunia kerja; \ne. ranah keilmuan program studi; \nf. kompetensi utama lulusan program studi; dan \ng. kurikulum program studi sejenis. \n(7) CPL sebagaimana dimaksud pada ayat ( 3) diinformasikan kepada seluruh \nmahasiswa pada program studi tersebut. \n(8) CPL sebagaimana dimaksud pada ayat (3) disusun ke dalam mata kuliah pada \nsetiap program studi. \n(9) Mata kuliah sebagaimana dimaksud pada ayat ( 8) memiliki capaian \npembelajaran mata kuliah yang berkontribusi pada CPL. \n \n \nBagian Ketiga \nKompetensi Utama Lulusan \n \nPasal 3 \n \n(1) Penyelenggaraan program Dip loma Dua diarahkan untuk membangun \nkompetensi utama lulusan, minimal: \na. menguasai prinsip dasar pengetahuan serta keterampilan pada bidang \nkeahlian tertentu; dan \nb. mampu menyelesaikan tugas berlingkup luas serta kasus spesifik dengan \nmemilih metode baku yang tepat; \n(2) Penyelenggaraan program Diploma Tiga diarahkan untuk membangun \nkompetensi utama lulusan, minimal: \na. menguasai konsep teoretis bidang pengetahuan dan keterampilan tertentu \nsecara umum; \nb. mampu menyelesaikan pekerjaan berlingkup luas; dan \nc. mampu memilih metode yang sesuai dari beragam pilihan yang sudah \nmaupun belum baku berdasarkan analisis data; \n(3) Penyelenggaraan program Sarjana Terapan diarahkan untuk membangun \nkompetensi utama lulusan, minimal: \na. mampu menerapkan konsep teoretis bidang pengetahuan dan \nketerampilan tertentu secara umum dan khusus untuk menyelesaikan \nmasalah prosedural sesuai dengan lingkup pekerjaannya; dan \nb. mampu beradaptasi terhadap situasi perubahan yang dihadapi; \n(4) Penyelenggaraan program Profesi diarahkan untuk membangun kompetensi \nutama lulusan, minimal: \na. menguasai teori aplikasi bidang pengetahuan dan keterampilan tertentu \ndengan memanfaatkan ilmu pengetahuan dan teknologi pada bidang \nprofesi tertentu; dan', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(125, 13, '3 \nb. mampu mengelola sumber daya, menerapkan standar profesi, \nmengevaluasi, dan mengembangkan strategi organisasi; \n(5) Penyelenggaraan program Magister Terapan diarahkan untuk membangun \nkompetensi utama lulusan, minimal mampu mengembangkan keahlian \ndengan landasan pemahaman ilmu pengetahuan dan teknologi melalui riset \natau penciptaan karya inovatif yang dapat diterapkan di lingkup pekerjaan \ntertentu; \n \n \nBAB II \nKURIKULUM DAN PEMBELAJARAN \n \nBagian Kesatu \nKurikulum \n \nPasal 4 \n \n(1) Kurikulum adalah seperangkat rencana dan pengaturan mengenai tujuan, \nisi, dan bahan pelajaran serta cara yang digunakan sebagai pedoman \npenyelenggaraan kegiatan pembelajaran program studi. \n(2) Kurikulum program studi disusun, diselenggarakan dan dievaluasi mengacu \nkepada standar nasional pendidikan untuk mendukung pemenuhan \nstandar kompetensi lulusan yang mencakup pengembangan sikap, \nketerampilan, dan pengetahuan yang dinyatakan dalam rumusan capaian \npembelajaran lulusan. \n(3) Kurikulum program studi dinyatakan minimal mencakup capaian \npembelajaran lulusan, Masa Tempuh Kurikulum, metode pembelajaran, \nmodalitas pembelajaran, syarat kompetensi dan/atau kualifikasi calon \nmahasiswa, penilaian hasil belajar, materi pembelajaran yang harus \nditempuh, dan tata cara pene rimaan mahasiswa pada berbagai tahapan \nkurikulum. \n(4) Kurikulum program studi dievaluasi relevansinya terhadap kebutuhan \npemangku kepentingan dengan mengacu pada standar nasional pendidikan, \nmeliputi: standar luaran pendidikan, standar proses pendidikan, dan \nstandar masukan pendidikan. \n(5) Kurikulum hasil evaluasi atau kurikulum baru berlaku untuk mahasiswa di \nseluruh angkatan. \n(6) Kurikulum sebelum di evaluasi atau kurikulum lama tidak berlaku lagi \nsetelah kurikulum baru ditetapkan. \n(7) Mekanisme transisi kurikulum ditetapkan oleh program studi/jurusan \ndengan mengikuti ketentuan perundangan yang berlaku. \n(8) Ukuran pengakuan s etiap mata kuliah dinyatakan dalam satuan kredit \nsemester (sks), yaitu takaran waktu kegiatan belajar yang dibebankan pada \nmahasiswa per minggu per semester dalam proses pembelajaran melalui \nberbagai bentuk pembelajaran atau besarnya pengakuan atas keberhasilan \nusaha mahasiswa dalam mengikuti kegiatan kurikuler di suatu Program \nStudi.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(126, 13, '4 \nBagian Kedua \nProses Pembelajaran \n \nPasal 5 \n \n(1) Proses pembelajaran yaitu kegiatan kurikuler wajib dilakukan secara \nsistematis dan terstruktur melalui berbagai mata kuliah dan dengan beban \nbelajar yang terukur dan dilakukan dengan metode pembelajaran tertentu \nyang dilaksanakan dengan sks. \n(2) Pelaksanaan proses pembelajaran merupakan pelaksanaan kegiatan \npembelajaran secara terstruktur sesuai dengan arahan dosen dan/atau tim \ndosen pengampu dengan bentuk, strategi, dan metode pembelajaran \ntertentu. \n(3) Pelaksanaan proses pembelajaran sebagaimana dimaksud pada ayat ( 2) \nmengacu pada perencanaan proses pembelajaran yang dituangkan dalam \nRencana Pembelajaran Semester (RPS) dengan memanfaatkan sumber \npembelajaran yang tepat. \n(4) Pelaksanaan proses pembelajaran dapat diselenggarakan dalam sistem blok, \nmodul, atau bentuk lain ditetapkan sesuai dengan kebutuhan dalam \nmemenuhi capaian pembelajaran. \n(5) Pelaksanaan proses pembelajaran diselenggarakan dengan: \na. menciptakan suasana belajar yang menyenangkan, inklusif, kolaboratif, \nkreatif, dan efektif; \nb. memberikan kesempatan belajar yang sama tanpa membedakan latar \nbelakang pendidikan, sosial, ekonomi, budaya, bahasa, jalur penerimaan \nmahasiswa, dan kebutuhan khusus mahasiswa; \nc. menjamin keamanan, kenyamanan, dan kesejahteraan hidup sivitas \nakademika; dan \nd. memberikan fleksibilitas dalam proses pendidikan untuk memfasilitasi \npendidikan berkelanjutan sepanjang hayat. \n(6) Penjaminan keamanan, kenyamanan, dan kesejahteraan hidup sivitas \nakademika sebagaimana dimaksud pada ayat ( 5) huruf c termasuk \npencegahan dan penanganan tindak kekerasan dan diskriminasi terhadap \nsivitas akademika sesuai dengan ketentuan peraturan perundang -\nundangan. \n(7) Fleksibilitas dalam proses pendidikan sebagaimana dimaksud pada ayat (5) \nhuruf d diberikan dalam bentuk: \na. proses pembelajaran yang dapat dilakukan secara tatap muka, jarak \njauh termasuk daring, atau kombinasi tatap muka dengan jarak jauh; \nb. keleluasaan kepada mahasiswa untuk mengikuti pendidikan dari \nberbagai tahapan kurikulum atau studi sesuai dengan kurikulum \nprogram studi; dan \nc. keleluasaan kepada mahasiswa untuk menyelesaikan pendidikan \nmelalui rekognisi pembelajaran lampau sesuai dengan ketentuan \nperaturan perundang-undangan. \n(8) Pelaksanaan Proses pembelajaran diselenggarakan dengan memanfaatkan \nvariasi ruang belajar (RB), meliputi: \na. RB1 – Tatap muka: Pembelajaran antara dosen dan mahasiswa terjadi \npada waktu dan ruang yang sama (sinkron luring), contoh:', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(127, 13, '(8) Pelaksanaan Proses pembelajaran diselenggarakan dengan memanfaatkan \nvariasi ruang belajar (RB), meliputi: \na. RB1 – Tatap muka: Pembelajaran antara dosen dan mahasiswa terjadi \npada waktu dan ruang yang sama (sinkron luring), contoh: \nkelas/workspace/laboratorium/workshop;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(128, 13, '5 \nb. RB2 – Tatap maya (daring): Pembelajaran antara dosen dan mahasiswa \nterjadi pada waktu yang bersamaan, tapi ruang yang berbeda satu sama \nlain (sinkron daring), contoh media: Video Conference, Audio Conference; \nText-based Conference (Chatting), dan teknologi lainnya yang relevan; \nc. RB3 – Mandiri: Belajar mandiri kapan saja dan di mana saja sesuai \ndengan kondisi dan kecepatan belajar masing -masing mahasiswa \n(asinkron), contoh media: video, audio, animasi, simulasi, dan media \nlainnya yang relevan; dan \nd. RB4 – Kolaboratif: Belajar kapan saja dan di mana saja bersama \nnarasumber lain, antara: mahasiswa, dosen, praktisi, dan lain -lain \n(asinkron), contoh: Milist, Blog, Chat e -Learning, Project Management \nTools, dan teknologi lainnya yang relevan. \n(9) Pelaksanaan proses pembelajaran menggunakan materi ajar dan referensi, \nbaik berupa buku, handout, video pembelajaran, simulasi, animasi, dan \nmedia lainnya yang relevan dapat menjadi rujukan bagi dosen dan \nmahasiswa. \n(10) Proses pembelajaran dilaksanakan melalui metode pembelajaran berbasis \nproduk/proyek/masalah (PBL), atau metode pembelajaran lain yang \ndipadukan secara hybrid dengan pendekatan ruang belajar RB1, RB2, RB3, \ndan RB4, yang dapat secara efektif memfasilitasi pe menuhan capaian \npembelajaran lulusan. \n(11) Materi pembelajaran pada program diploma, sarjana terapan, dan magister \nterapan diutamakan untuk menyiapkan lulusan agar mampu \nmengembangkan keterampilan dan penalaran melalui penerapan ilmu \npengetahuan dan teknologi u ntuk melakukan pekerjaan dengan keahlian \nterapan tertentu. \n(12) Materi pembelajaran pada pendidikan profesi diutamakan untuk \nmenyiapkan lulusan agar mampu melakukan pekerjaan yang memerlukan \npersyaratan keahlian khusus. \n(13) Materi pembelajaran sebagaimana dimaksud dalam ayat (11) disusun dalam \nkurikulum program studi dan dapat dinyatakan secara terpisah maupun \nterintegrasi dalam bentuk: \na. mata kuliah; \nb. modul; \nc. blok tematik; dan/atau \nd. bentuk lain. \n(14) Materi pembelajaran dalam kurikulum sebagaiman dimaksud pada ayat (11) \ndapat diisi dengan program kompetensi mikro. \n(15) Program kompetensi mikro sebagaimana dimaksud pada ayat (14) berupa: \na. kredensial mikro; \nb. pembelajaran secara daring dari institusi lain yang \nc. bersifat terbuka (massive open online courses); dan/atau \nd. bentuk lain. \n(16) Pengelolaan pembelajaran matakuliah secara digital dilakukan melalui \nsistem informasi pengelolaan pembelajaran (Learning Management System)', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(129, 13, 'c. bersifat terbuka (massive open online courses); dan/atau \nd. bentuk lain. \n(16) Pengelolaan pembelajaran matakuliah secara digital dilakukan melalui \nsistem informasi pengelolaan pembelajaran (Learning Management System) \nyang dapat diakses melalui laman: https://learning.polibatam.ac.id. \n(17) Pengelolaan pembelajaran berbasis proyek/produk/permasalahan secara \ndigital dilakukan melalui sistem info rmasi pengelolaan proyek yang dapat \ndiakses melalui laman: https://pbl.polibatam.ac.id.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(130, 13, '6 \nBAB III \nMASA DAN BEBAN BELAJAR \n \nBagian Kesatu \nMasa Tempuh Kurikulum dan Masa Studi \n \nPasal 6 \n \n(1) Proses pembelajaran sebagaimana dimaksud pada Pasal (5) ayat (1) \ndilaksanakan dengan Masa Tempuh Kurikulum 2 (dua) semester untuk 1 \n(satu) tahun akademik. \n(2) Selain 2 (dua) semester sebagaimana dimaksud pada ayat (1), program studi \ndapat menyelenggarakan 1 (satu) semester antara sesuai dengan kebutuhan. \n(3) Semester antara akan diselenggarakan jika dibutuhkan, dengan ketentuan \nsebagai berikut: \na. paling sedikit 8 (delapan) minggu; \nb. beban belajar mahasiswa paling banyak 9 (sembilan) sks; dan \nc. sesuai beban belajar mahasiswa untuk memenuhi capaian pembelajaran \nyang telah ditetapkan. \n(4) Proses pembelajaran di Polibatam dilaksanakan dalam minimal 16 (enam \nbelas) minggu, termasuk asesmen tengah semester dan asesmen akhir \nsemester, sesuai dengan kalender akademik yang telah ditetapkan. \n \n \nPasal 7 \n \n(1) Beban belajar dan Masa Tempuh Kurikulum pada: \na. Program pendidikan Diploma Dua dapat diselesaikan oleh mahasiswa \nberkemampuan normal secara tepat waktu, minimal 72 (tujuh puluh dua) \nsks yang dirancang dengan masa tempuh kurikulum selama 4 (empat) \nsemester. \nb. Program Pendidikan Diploma Tiga dapat diselesai kan oleh mahasiswa \nberkemampuan normal secara tepat waktu, minimal 108 (seratus delapan) \nsks yang dirancang dengan masa tempuh kurikulum selama 6 (enam) \nsemester. \nc. Program Pendidikan Sarjana Terapan dapat diselesaikan oleh mahasiswa \nberkemampuan normal seca ra tepat waktu, minimal 144 (seratus empat \npuluh empat) sks yang dirancang dengan masa tempuh kurikulum selama \n8 (delapan) semester, \nd. Program Pendidikan Profesi dapat diselesaikan oleh mahasiswa \nberkemampuan normal secara tepat waktu, minimal 36 (tiga puluh enam) \nsks yang dirancang dengan masa tempuh kurikulum selama 2 (dua) \nsemester. \ne. Program Pendidikan Magister Terapan dapat di selesaikan oleh Mahasiswa \nberkemampuan normal secara tepat waktu, minimal 54 (lima puluh empat) \nsampai 72 (tujuh puluh dua) sks yang dirancang sesuai dengan masa \ntempuh kurikulum selama 3 (tiga) sampai 4 (empat) semester. \n(2) Masa studi program pendidikan sebagaimana pada ayat (1) huruf (a)-(e) tidak \nmelebihi 2 (dua) kali Masa Tempuh Kurikulum.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(131, 13, '7 \n \nBagian Kedua \nBeban Belajar \n \nPasal 8 \n \n(1) Beban belajar dalam proses pembelajaran sebagaimana dimaksud pada ayat \n(1) dinyatakan dalam sks. \n(2) Beban belajar 1 (satu) sks setara dengan 45 (empat puluh lima) jam per \nsemester. \n(3) Beban belajar 1 (satu) sks setara 170 menit per minggu bagi program studi \nyang menyelenggarakan proses pembelajarannya 16 minggu per semester. \n(4) Distribusi beban belajar sebagaimana dimaksud pada ayat (1): \na. pada semester satu dan semester dua paling banyak 20 (dua puluh) sks; \ndan \nb. pada semester tiga dan seterusnya paling banyak 24 (dua puluh empat) \nsks. \n(5) Pemenuhan beban belajar, seperti yang dimaksud dalam ayat (1), dilakukan \ndalam bentuk pembelajaran matakuliah dari metode yang telah ditetapkan \ndapat berupa: \na. kuliah; \nb. responsi dan tutorial; \nc. seminar; \nd. praktikum, praktik studio, praktik bengkel, praktik lapangan, praktik \nkerja; \ne. proyek penelitian, perancangan, pengembangan, tugas akhir; \nf. pelatihan bela negara; \ng. pertukaran mahasiswa; \nh. magang; \ni. studi independent; \nj. wirausaha; \nk. membangun desa/kuliah kerja nyata tematik ( pengabdian kepada \nmasyarakat); \nl. Proyek kemanusiaan; dan/atau \nm. bentuk lain yang ditetapkan direktur. \n(6) Bentuk pembelajaran sebagaimana dimaksud pada ayat (5) dilakukan \nmelalui kegiatan: \na. belajar terbimbing; \nb. penugasan terstruktur; dan/atau \nc. mandiri. \n(7) Mahasiswa pada program diploma tiga, dan sarjana terapan wajib \nmelaksanakan kegiatan magang di dunia usaha, dunia industri, dan dunia \nkerja yang relevan minimal 2 (dua) semester atau setara 40 (empat puluh) \nsks, kecuali pada program diploma dua minimal 1 (satu) semester atau \nsetara 20 (dua puluh) sks. \n(8) Mahasiswa pada program diploma tiga dapat diberikan tugas akhir dalam \nbentuk prototipe, proyek, atau bentuk tugas akhir lainnya yang sejenis, baik \nsecara individu maupun berkelompok.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(132, 13, '8 \n(9) Mahasiswa pada program sarjana terapan dapat diberikan tugas akhir \ndalam bentuk skripsi, prototipe, proyek, atau bentuk tugas akhir lainnya \nyang sejenis baik secara individu maupun berkelompok. \n(10) Mahasiswa pada program magister terapan wajib diberikan tugas akhir \ndalam bentuk tesis, prototipe, proyek, atau bentuk tugas akhir lainnya yang \nsejenis. \n \nBagian Ketiga \nPemenuhan Masa dan Beban Belajar \n \nPasal 9 \n \n(1) Pemenuhan masa dan beban belajar bagi mahasiswa program sarjana \nterapan sebagaimana dimaksud dalam Pasal 7 ayat (3) dapat dilaksanakan \ndengan cara: \na. mengikuti seluruh proses pembelajaran di dalam program studi di \nPolibatam sesuai masa dan beban belajar; atau \nb. mengikuti proses pembelajaran di dalam program studi untuk \nmemenuhi sebagian masa dan beban belajar dan sisanya mengikuti \nproses pembelajaran di luar program studi baik di dalam atau di luar \nPolibatam. \n(2) Pembelajaran di luar program studi dapat dilakukan di program studi lain \ndi Polibatam, program studi yang sama di perguruan tinggi lain, program \nstudi lain di perguruan tinggi lain, pembelajaran di lembaga non perguruan \ntinggi, atau pembelajaran lain yang ditetapkan direktur dan pengakuannya \ndilakukan melalui mekanisme rekognisi pembelajaran lampau (RPL). \n(3) Pelaksanaan pemenuhan masa dan beban belajar sebagaimana dimaksud \ndalam ayat (1) huruf b dengan cara sebagai berikut: \na. 1 (satu) semester atau setara dengan 20 (dua puluh) sks merupakan \npembelajaran di luar program studi dalam lingkungan Polibatam; dan \nb. paling lama 2 (dua) semester atau setara dengan 40 (empat puluh) sks \nmerupakan pembelajaran: \ni. dalam program studi yang berbeda pada perguruan tinggi yang sama; \nii. dalam program studi yang sama atau program studi yang berbeda \npada perguruan tinggi lain; dan \niii. pada lembaga di luar perguruan tinggi. \n \n \nBAB IV \nMAHASISWA BARU \n \nBagian Kesatu \nPenerimaan Mahasiswa Baru \n \nPasal 10 \n \n(1) Penerimaan mahasiswa baru Polibatam diselenggarakan melalui jalur \nundangan, jalur ujian, jalur kerjasama, dan jalur Rekognisi Pembelajaran \nLampau (RPL).', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(133, 13, '9 \n(2) Jalur undangan sebagaimana dimaksud dalam ayat (1) adalah jalur \npenerimaan mahasiswa baru yang kelulusannya mempertimbangkan \nprestasi akademik dan non akademik selama menempuh pendidikan formal \nsebelumnya. \n(3) Jalur ujian sebagaimana dimaksud dalam ayat (1) adalah jalur penerimaan \nmahasiswa baru dengan ujian t ulis dan kelulusannya mempertimbangkan \nnilai hasil ujian tulis. \n(4) Jalur undangan dan jalur ujian sebagaimana dimaksud dalam ayat (1) \ndilaksanakan secara nasional maupun mandiri. \n(5) Jalur kerjasama sebagaimana dimaksud dalam ayat (1) adalah jalur \npenerimaan mahasiswa baru melalui kerjasama antara Polibatam dengan \npihak lain, baik pemerintah maupun swasta, dalam rangka pengembangan \nsumber daya manusia. \n(6) Jalur RPL sebagaimana dimaksud dalam ayat (1) adalah jalur penerimaan \nmahasiswa bar u dengan melakukan rekognisi atau pengakuan terhadap \ncapaian pembelajaran yang sudah dimiliki seseorang dari pengalaman \npendidikan formal, non -formal, informal, dan/atau pengalaman kerja \nsebelumnya sesuai peraturan perundangan yang berlaku. \n \nBagian Kedua \nPembatalan Penerimaan \n \nPasal 11 \n \n(1) Penerimaan seorang mahasiswa baru Polibatam akan dibatalkan jika \nternyata yang bersangkutan: \na. terbukti pernah terdaftar tetapi tidak diperkenankan lagi melanjutkan \npendidikan di Polibatam karena melakukan kecurangan atau \npelanggaran; \nb. terbukti melakukan pemalsuan dokumen persyaratan seleksi penerimaan \nmahasiwa baru; atau \nc. terbukti melakukan kecurangan pada saat pelaksanaan ujian saringan \nmasuk. \n(2) Mahasiswa Polibatam yang pada suatu saat diketahui ternyata term asuk \npada ayat (1) pasal ini, maka statusnya sebagai mahasiswa Polibatam akan \ndicabut. \n \nBagian Ketiga \nKeabsahan Sebagai Mahasiswa \n \nPasal 12 \n \n(1) Mahasiswa Polibatam wajib melengkapi semua persyaratan yang ditetapkan \noleh Polibatam. \n(2) Mahasiswa yang tidak melengkapi persyaratan yang telah ditetapkan oleh \nPolibatam, maka statusnya sebagai mahasiswa Polibatam adalah tidak sah. \n(3) Mahasiswa yang memberikan keterangan palsu atau keterangan tidak benar, \ndapat dikenakan sanksi sesuai ketentuan yang berlaku.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(134, 13, '10 \nBagian Keempat \nMahasiswa Khusus \n \nPasal 13 \n \n(1) Mahasiswa khusus adalah mahasiswa yang penerimaannya tidak mengikuti \njalur penerimaan mahasiswa baru seperti pada Pasal 10. \n(2) Penerimaan mahasiswa khusus ditentukan oleh Direktur berdasarkan hasil \npenilaian terhadap beberapa kriteria yang ditentukan Polibatam. \n \nBagian Kelima \nMahasiswa Asing \n \nPasal 14 \n \n(1) Calon mahasiswa asing dapat mengajukan permohonan kepada Direktur \nuntuk mengikuti pendidikan di Polibatam dengan melengkapi persyaratan: \na. daftar riwayat hidup dan riwayat pendidikan; \nb. fotokopi ijazah dan transkrip akademik pendidikan terakhir yang telah \nditempuh; \nc. Surat pernyataan jaminan keuangan; dan \nd. Surat permohonan dari sponsor \n(2) Calon mahasiswa asing mengajukan permohonan visa dan ijin tinggal \nterbatas melalui Kedutaan Besar Republik Indonesia setempat dengan \nsyarat dan ketentuan yang telah ditetapkan oleh Direktorat Jenderal \nImigrasi Republik Indonesia. \n(3) Calon mahasiswa asing mengurus Surat Izin Belajar dari Sekretariat \nJenderal Kementerian Pendidikan, Kebudayaan, Riset dan Teknologi melalui \nDirektur Polibatam, sebagai persyaratan utama untuk melakukan \npendaftaran ulang di Polibatam \n(4) Penerimaan mahasiswa warga negara asing dilakukan melalui seleksi dan \nujian masuk yang berlaku atau seleksi khusus yang dibuat Polibatam. \n \nBAB V \nDAFTAR ULANG \n \nBagian Kesatu \nProses Daftar Ulang \n \nPasal 15 \n \n(1) Datar ulang adalah urutan prosedur administrasi yang wajib dijalani oleh \nmahasiswa dan calon mahasiswa Polibatam agar diakui sebagai mahasiswa \nPolibatam. \n(2) Mahasiswa Polibatam wajib melakukan proses daftar ulang sebelum \nmengikuti kegiatan akademik pada setiap semester sesuai dengan waktu \nyang telah dijadwalkan di dalam kalender akademik yang dapat di akses \nmelalui laman https://learning.polibatam.ac.id dan \nhttps://sim.polibatam.ac.id.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(135, 13, '11 \n(3) Ketentuan dan proses pendaftaran ulang sesuai dengan pengumuan daftar \nulang yang berlaku. \n \nBagian Kedua \nMahasiswa Tidak Daftar Ulang \n \nPasal 16 \n \n(1) Mahasiswa yang tidak melakukan daftar ulang sampai dengan batas akhir \npendaftaran sesuai dengan jadwal yang telah ditetapkan dan diumumkan, \ndinyatakan nonaktif selama satu semester. \n(2) Mahasiswa yang tidak melakukan daftar ulang lebih dari 2 kali secara \nberturut, setelah dilakukan verifikasi dengan melibatkan wali akademik, \nmaka mahasiswa yang bersangkutan dinyatakan mengundurkan diri \nsebagai mahasiswa dan akan diterbitkan surat pengunduran diri oleh \nPolibatam. \n(3) Mahasiswa semester 2 yang tidak melakukan daftar ulang dianggap \nmengundurkan diri \n \nBagian Ketiga \nPindah Kelas \n \nPasal 17 \n \n(1) Pindah kelas adalah pengalihan mahasiswa dari kelas regular pagi ke reguler \nmalam atau sebaliknya pada program studi yang sama di dalam Polibatam. \n(2) Pindah kelas diperbolehkan apabila memenuhi ketentuan sebagai berikut: \na. masih tersedia kapasitas daya tampung; \nb. mendapatkan persetujuan kepala program studi , jurusan, dan wakil \ndirektur bidang akademik; dan \nc. telah memenuhi semua kewajiban administrasi akademik dan \nkeuangan. \n(3) Tahun angkatan untuk mahasiswa pindah kelas tidak berubah. \n \n \nBAB VI \nIDENTITAS MAHASISWA DAN KEGIATAN AKADEMIK \n \nBagian Kesatu \nIdentitas Mahasiswa \n \nPasal 18 \n \n(1) Identitas resmi mahasiswa Polibatam adalah berupa Kartu Tanda \nMahasiswa (KTM). \n(2) KTM berlaku untuk mengikuti kegiatan akademik dan non akademik di \nPolibatam. \n(3) KTM berlaku selama masih berstatus sebagai mahasiswa Polibatam.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(136, 13, '12 \n(4) Pengurusan kehilangan KTM mengacu pada prosedur yang berlaku di \naplikasi Sistem Informasi dan Layanan Mahasiswa (SILAM) pada laman \nhttps://sim.polibatam.ac.id. \n \nBagian Kedua \nKegiatan Akademik \n \nPasal 19 \n \n(1) Kegiatan akademik adalah semua kegiatan yang harus dilakukan oleh setiap \nmahasiswa untuk memenuhi syarat k elulusan sesuai dengan ketentuan \nyang berlaku. \n(2) Mahasiswa berhak dan wajib mengikuti kegiatan akademik setelah terdaftar \nsebagai mahasiswa aktif di Sistem Informasi Akademik Polibatam. \n \n \n \nBagian Ketiga \nKalender Akademik \n \nPasal 20 \n \n(1) Kalender akademik adalah jadwal layanan dan kegiatan akademik tahunan \nPolibatam sebagai acuan bagi seluruh sivitas akademik. \n(2) Mahasiswa wajib mempelajari dan mematuhi jadwal dalam kalender \nakademik. \n(3) Melalaikan kalender akademik tidak dapat digunakan sebagai alasan untuk \nmengubah jadwal layanan dan kegiatan akademik. \n \n \nBagian Keempat \nPerwalian Akademik \n \nPasal 21 \n \n(1) Perwalian akademik adalah interaksi antara wali akademik dengan \nmahasiswa, baik secara tatap muka atau dengan bantuan teknologi \ninformasi, untuk berkonsultasi segala sesuatu yang berhubungan dengan \nakademik atau yang mempengaruhi kinerja akademik mahasiswa. \n(2) Wali akademik adalah dosen Polibatam yang ditunjuk oleh Ketua Jurusan \ndan berkewajiban untuk: \na. memberikan bimbingan terkait kegiatan aka demik dan non akademik \nkepada mahasiswa selama masa pendidikannya minimal dua kali dalam \nsetiap semester; \nb. menumbuhkan kreativitas dan kebiasaan belajar efektif; dan \nc. membantu mahasiswa dalam menyusun rencana studi guna menunjang \nkeberhasilannya. \n(3) Jadwal perwalian tertulis dalam kalender akademik harus ditaati oleh setiap \nmahasiswa.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(137, 13, '13 \n(4) Mahasiswa harus memperhatikan informasi wali akademik mengenai \nprestasi akademik dan batas waktu studi. \n \nBagian Kelima \nPerkuliahan dan Layanan Mahasiswa \n \nPasal 22 \n \n(1) Perkuliahan adalah proses pembelajaran sebagaimana dimaksud pada Pasal \n5 Ayat (1)-(16). \n(2) Peserta perkuliahan adalah mahasiswa yang terdaftar dalam sebuah mata \nkuliah. \n(3) Perkuliahan dilaksanakan pada hari Senin sampai Jum’at di antara rentang \nwaktu pukul 07.00 WIB sampai dengan pukul 23.00 WIB. \n(4) Layanan akademik dan Kemahasiswaan dibuka pada hari Senin sampai \nJum’at yang dimulai pada pukul 08:00 – 22:00 WIB. \n(5) Jika diperlukan, perkuliahan dapat diselenggarakan di luar jadwal seperti \npada Ayat (3) berdasarkan kesepakatan antara mahasiswa atau \nperwakilannya dengan dosen. \n(6) Setiap peserta perkuliahan wajb mengikuti norma, aturan dan ketentuan \nyang berlaku, baik yang telah ditetapkan melalui pedoman pembelajaran \nmaupun kesepakatan yang ditetapkan dengan dosen pengajar, sepanjang \ntidak bertentangan dengan peraturan akademik yang lebih tinggi. \n(7) Mahasiswa mengikuti perkuliahan sesuai jadwal dan metode pembelajaran \nyang telah ditetapkan. \n(8) Setiap mahasiwa wajib mengisi kuesioner umpan balik proses belaja r \nmengajar sebelum asesmen tengah semester dan asesmen akhir semester. \nKelalaian tidak mengisi kuesioner dapat berakibat mahasiswa tidak dapat \nmengakses nilai akhir. \n(9) Setiap mahasiwa wajib memperbaharui protofolio pelaksanakaan PBL dan \naktivitas lainnya setiap semester melalui tallent hub Polibatam yang dapat \ndiakses melalui laman: https://talent-hub.id. Kelalaian tidak \nmemperbaharui portofolio dapat berakibat mahasiswa tidak dapat \nmengakses nilai akhir. \n \nPasal 23 \n \n(1) Ketidakhadiran dalam kegiatan perkuliahan hanya diizinkan karena alasan \nsakit, mendapat kecelakaan, atau disebabkan keperluan penting yang amat \nmendesak yang keabsahannya akan diverifikasi. \n(2) Ketidakhadiran wajib diinfo rmasikan kepada Tata Usaha (TU) , Wali \nAkademik atau Dosen Pengajar sesuai kebijakan dari jurusan. \n(3) Informasi ketidakhadiran ke TU wajib berbentuk surat maksimal 1 minggu \nsetelah ketidakhadiran. \n(4) Ketidakhadiran harus disertai keterangan surat dokter, surat tugas , atau \nbukti lain yang dapat dibuktikan kebenarannya. \n(5) Bukti ketidakhadiran dalam bentuk lain dapat dibuat sendiri dengan \nmemuat informasi : Nama, NIM, dosen wali, mata kuliah dan periode \nketidakhadiran, penyebab ketidakhadiran, pernyataan kebenaran informasi \nyang ditulis, dan nomor kontak pihak lain yang bisa dikonfirmasi.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(138, 13, '14 \n(6) Ketidakhadiran tidak dapat diverifikasi kebenarannya dianggap sebagai \nketidakhadiran tanpa izin. \n(7) Ketidakhadiran tanpa izin sampai jumlah sesi tertentu, jurusan \nmenerbitkan Surat Peringatan (SP) I, II, III yang ditujukan kepada orang \ntua/wali mahasiswa. \n(8) SP I, II, III masing-masing untuk ketidakhadiran tanpa izin sebesar 5%, 20% \ndan 40% dari total jumlah sesi dalam satu semester yang telah \ndirencanakan. \n(9) SP III yang tidak ditangg api oleh mahasiswa dalam jangka waktu 3 (tiga) \nminggu sejak surat dikirimkan menyebabkan mahasiswa dianggap \nmengundurkan diri, dan selanjutnya akan diterbitkan surat pemberhentian. \nJika ternyata tanggapannya adalah kesulitan ekonomi atau karena alasan \nyang dapat diterima, maka mahasiswa dapat mengajukan cuti. \n \n \nBAB VII \nCUTI AKADEMIK DAN PENGHENTIAN STUDI \n \nBagian Kesatu \nCuti Akademik \n \nPasal 24 \n \n(1) Cuti akademik adalah pembebasan mahasiswa dari kewajiban mengikuti \nkegiatan akademik selama jangka waktu tertentu. \n(2) Pengajuan cuti akademik dilakukan sesuai dengan jadwal yang telah \nditentukan. \n(3) Pengajuan cuti akademik hanya dapat dilakukan oleh mahasiswa yang telah \nmenyelesaikan minimal 1 (satu) tahun studi \n(4) Pengajuan cuti tidak diperkenankan setelah masa perku liahan berjalan, \nkecuali kondisi mahasiswa yang tidak memungkinkan dan mendapat \npersetujuan dosen wali dan kepala program studi atau ketua jurusan. \n(5) Masa cuti akademik berdasarkan pengajuan mahasiswa memiliki ketentuan \nbatas waktu sebagai berikut: \na. 2 (dua) semester untuk program Diploma Tiga; \nb. 4 (empat) semester untuk program Sarjana Terapan; dan \nc. 1 (satu) semester untuk program Diploma Dua , Profesi dan Magister \nTerapan; \n(6) Masa cuti yang melebihi batas waktu yang tersebut di atas, diperbolehkan \ndengan ketentuan: \na. memiliki alasan khusus atau keperluan yang sangat mendesak dan \nharus mendapat pertimbangan dari ketua jurusan atau kepala program \nstudi dan disetujui oleh Wakil Direktur bidang Akademik; atau \nb. dicutikan otomatis karena mendapatkan sanksi administratif/skorsing \n(7) Cuti akademik tidak dihitung sebagai bagian dari masa studi. \n(8) Status nonaktif mengurangi masa studi \n(9) Cuti akademik harus mengikuti prosedur berikut: \na. mengajukan permohonan cuti di sistem informasi dan layanan \nmahasiswa (SILAM) pada laman https://sim.polibatam.ac.id;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(139, 13, '15 \nb. mendapatkan izin dari Wali, kepala program studi atau ketua jurusan \ndan Wakil Direktur bidang Akademik; dan \nc. membayar biaya cuti sesuai dengan aturan yang berlaku. \n \n \nBagian Kedua \nPenghentian Studi \n \nPasal 25 \n \n(1) Dengan mempertimbangkan kemampuan akademik mahasiswa, dan untuk \ntidak menghambat kemungkinan melanjutkan studi di perguruan tinggi \nlain, Polibatam dapat menghentikan studi mahasiswa melalui mekanisme \nmahasiwa mengajukan pengunduran diri. \n(2) Mahasiswa yang terbukti tidak dapat menyelesaikan studinya pada batas \nwaktu maksimal masa studi seperti ketentuan pada Pasal 7, tida k \ndiperkenankan melanjutkan studinya di Polibatam. \n \n \nBAB VIII \nEVALUASI AKADEMIK MAHASISWA \n \nBagian Kesatu \nPenilaian Hasil Belajar \n \nPasal 26 \n \n(1) Standar penilaian merupakan kriteria minimal mengenai penilaian hasil \nbelajar mahasiswa untuk mencapai standar kompetensi lulusan. \n(2) Penilaian hasil belajar mahasiswa sebagaimana dimaksud pada ayat (1) \ndilakukan secara valid, reliabel, transparan, akuntabel, berkeadilan, \nobjektif, dan edukatif \n(3) Penilaian hasil belajar adalah pengukuran dan penilaian kinerja \npembelajaran mahasiswa yang diselenggarakan selama satu semester \nsebagai dasar penentuan prestasi akademik mahasiswa. \n(4) Penilaian hasil belajar dilakukan untuk mengukur kinerja pembelajaran \nmatakuliah dan/atau ketercapaian capaian pembelajaran lulusan (CPL) \nprogram studi yang ditetapkan. \n(5) Penilaian hasil belajar mahasiswa berbentuk penilaian formatif dan \npenilaian sumatif. \n(6) Penilaian formatif sebagaimana dimaksud pada ayat (5) bertujuan untuk: \na. memantau perkembangan belajar mahasiswa; \nb. memberikan umpan balik agar mahasiswa memenuhi capaian \npembelajarannya; dan \nc. memperbaiki proses pembelajaran. \n(7) Penilaian sumatif sebagaimana dimaksud pada ayat ( 5) bertujuan untuk \nmenilai pencapaian hasil belajar mahasiswa sebagai dasar penentuan \nkelulusan mata kuliah dan kelulusan program studi, dengan mengacu pada \npemenuhan capaian pembelajaran lulusan.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(140, 13, '16 \n(8) Penilaian sumatif sebagaimana dimaksud pada ayat ( 5) dilakukan dalam \nbentuk ujian tertulis, ujian lisan, penilaian proyek, penilaian tugas, uji \nkompetensi, dan/ atau bentuk lainnya yang ditetapkan oleh \njurusan/program studi/dosen. \n(9) Penilaian sumatif sebagaimana dimaksud dalam ayat (5) dapat dilakukan \nsecara kuantitatif dengan menghitung jawaban benar dan salah. \n(10) Penilaian sumatif sebagaimana dimaksud dalam ayat (5) dapat juga \ndilakukan dengan menggunakan rubrik. \n(11) Rubrik sebagaimana yang dimaksud dalam ayat (10) adalah \ninstrumen penilaian yang digunakan dosen dalam mengukur kinerja \nmahasiswa berdasarkan deskripsi spesifik yang menggambarkan \nkemampuan mahasiswa untuk suatu level tertentu pada suatu aspek. \n \nPasal 27 \n \n(1) Penilaian hasil belajar yang terjadwal secara kalender akademik adalah \nasesmen tengah semester, dan asesmen akhir semester. \n(2) Asesmen tengah semester, asesmen akhir semester, atau bentuk lain \npenilaian hasil pembelajaran untuk PBL dilaksanakan berdasarkan pada \nstandar yang telah di tetapkan oleh program studi, antar program studi \ndalam satu jurusan, atau antar program studi lintas jurusan dengan jadwal \nmenyesuaikan dengan kegiatan asesmen PBL. \n(3) Penilaian hasil belajar bagi matakuliah yang tidak bisa dilibatkan dalam \nPBL, dilaksanakan sesuai dengan kalender akademik atau sesuai dengan \nRencana Pembelajaran Semester (RPS) yang telah ditetapkan. \n(4) Jadwal penilaian hasil belajar secara rinci disusun dan diterbitkan oleh \njurusan, program studi, atau dosen minimal 1 minggu sebelum pelaksanaan \nevaluasi dilaksanakan. \n(5) Kesalahan membaca jadwal atau tempat pelaksanaan penilaian hasil belajar \ntidak dapat digunakan sebagai alasan untuk meminta tambahan layanan, \ntermasuk ujian khusus. \n(6) Komponen penguasaan personal dan interpersonal skills masuk dalam \npenilaian akhir matakuliah sesuai dengan standar penilaian yang \nditetapkan oleh program studi, jurusan, pemerintah, dan/atau kesepakatan \nantar program studi atau jurusan. \n(7) Keseluruhan hasil penilaian direkapitulasi menjadi satu nilai akhir bagi \nsetiap mahasiswa dalam mengikuti mata kuliah dan ketercapaian CPL \nprogram studi. \n \nPasal 28 \n \n(1) Penilaian hasil belajar mahasiswa dalam suatu mata kuliah dinyatakan \ndalam: \na. indeks prestasi; atau \nb. keterangan lulus atau tidak lulus. \n(2) Atas dasar data evaluasi keseluruhan, setiap dosen harus menentukan nilai \nakhir setiap mata kuliah dalam bentuk huruf dan angka sebagai berikut: \nA nilai angka ≥85.00 sama dengan 4.00', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(141, 13, 'a. indeks prestasi; atau \nb. keterangan lulus atau tidak lulus. \n(2) Atas dasar data evaluasi keseluruhan, setiap dosen harus menentukan nilai \nakhir setiap mata kuliah dalam bentuk huruf dan angka sebagai berikut: \nA nilai angka ≥85.00 sama dengan 4.00 \nA- nilai angka 80.00 – 84.99 sama dengan 3.70 \nB+ nilai angka 75.00 – 79.99 sama dengan 3.40', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL);
INSERT INTO `chunks` (`chunk_id`, `document_id`, `chunk_text`, `created_at`, `edited_at`, `deleted_at`) VALUES
(142, 13, '17 \nB nilai angka 70.00 – 74.99 sama dengan 3.00 \nB- nilai angka 65.00 – 69.99 sama dengan 2.70 \nC+ nilai angka 60.00 – 64.99 sama dengan 2.40 \nC nilai angka 55.00 – 59.99 sama dengan 2.00 \nC- nilai angka 50.00 – 54.99 sama dengan 1.70 \nD+ nilai angka 45.00 – 49.99 sama dengan 1.40 \nD nilai angka 40.00 – 44.99 sama dengan 1.00 \nE nilai angka <40.00 sama dengan 0.00 \n \n(1) Nilai akhir dari semua mata kuliah yang telah diambil digunakan untuk \nmenghitung Indeks Prestasi (IP) guna menentukan keberhasilan mahasiswa, \ndengan rumus: \nIP = (n1k1 + n2k2 +...+ nmkm) / (k1 + k2 +...+ km) \ndimana: \nk1, k2,.....km adalah besarnya sks mata kuliah \nsubskrip 1, 2, .....m adalah mata kuliah yang diambil \nn1, n2,.....nm adalah nilai angka mata kuliah \n(2) Khusus untuk mahasiswa tahun pertama, Indeks Prestasi Kumulatif ( IPK) \nharus lebih besar atau sama dengan 1.50. Jika IPK kurang dari 1.50, \nmahasiswa tidak diperkenankan melanjutkan studi lagi di Polibatam. \n(3) Merujuk pada ayat (2), u ntuk kasus khusus akan dipertimba ngkan \nkeberlanjutan melanjutkan studi di Polibatam melalui kebijakan Wakil \nDirektur Bidang Akademik setelah berkoordinasi dengan berbagai \npemangku kepentingan Polibatam. \n \nPasal 29 \n \n(1) Pengukuran ketercapaian CPL program studi dilakukan dan digunakan \nsebagai b ukti kepada pemangku kepentingan tentang tingkat kinerja \nmahasiswa terkait dengan pemenuhan CPL yang telah ditetapkan bersama. \n(2) Setiap bentuk penilaian hasil belajar sebagaimana dimaksud dalam Pasal \n26 ayat (5) harus memperhatikan CPL yang akan dinilai. \n(3) Data hasil asesmen CPL dianalisis dan sajikan dalam bentuk yang informatif \nuntuk pengambilan keputusan, seperti: radar chart , bar chart, pie, dan \nbentuk penyajian lainnya yang relevan.. \n \n \nBagian Kedua \nPeserta Penilaian Hasil Belajar \n \nPasal 30 \n \n(1) Mahasiswa dinyatakan sah dan diperkenankan mengikuti penilaian hasil \nbelajar apabila: \na. tidak sedang dikenakan sanksi kecurangan akademik; dan \nb. terdaftar pada matakuliah yang ditempuh. \n(2) Selama penilaian berlangsung, peserta diwajibkan mentaati semua \nperaturan, ketentuan, dan tata tertib asesmen yang berlaku. \n(3) Segala bentuk kecurangan dapat dikenakan sanksi sesuai ketentuan yang \nberlaku.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(143, 13, '18 \n \n \nBagian Ketiga \nYudisium dan Predikat Kelulusan \n \nPasal 31 \n \n(1) Penetapan yudisium kepada setiap mahasiswa dilaksanakan setelah \nmahasiswa tersebut memenuhi ketentuan sebagai berikut: \na. telah dinyatakan lulus dari semua mata kuliah dengan jumlah beban sks \nyang disyaratkan oleh kurikulum; \nb. matakuliah dinyatakan lulus dengan nilai minimal D untuk program \ndiploma dan sarjana terapan; \nc. matakuliah dinyatakan lulus dengan nilai minimal C untuk program \nprogram profesi dan magister terapan; \nd. IPK minimal 2.00 untuk program diploma dan sarjana terapan; \ne. IPK minimal 3.00 untuk program profesi dan magister terapan; \nf. telah memenuhi semua persyaratan yang ditetapkan, diantaranya: \npenyerahan buku tugas akhir /skripsi dan laporan magang, bebas \nmasalah workspace, laboratorium , workshop, studio , perpustakaan, \ndan/atau administrasi lainnya yang berlaku di masing-masing prodi; dan \ng. telah dimutakhirkan data status kelulusannya. \n(2) Predikat kelulusan pada saat penetapan yudisium ditentukan berdasarkan \nIPK dan/atau kriteria lainnya. \n(3) Predikat kelulusan yang diberikan kepada lulusan program pendidikan di \nPolibatam dapat berupa dengan pujian, sangat memuaskan , dan \nmemuaskan. \n(4) Predikat kelulusan dengan pujian diberikan jika IPK> 3.50 untuk program \ndiploma dan sarjana terapan, IPK>3.75 untuk program profesi dan magister \nterapan serta menyelesaikan pendidikannya sesuai dengan waktu tempuh \nkurikulum. Jika menyelesaikan pendidikan lebih dari waktu tempuh \nkurikulum mendapat predikat kelulusan dengan sangat memuaskan. \n(5) Predikat kelulusan dengan sangat memuaskan diberikan jika 3.00 \n≤IPK≤3.50 untuk program diploma dan sarjana terapan, 3.25≤IPK≤3.75 \nuntuk program profesi dan magister terapan. \n(6) Predikat kelulusan dengan memuaskan diberikan jika 2.00≤IPK< 3.00 untuk \nprogram diploma dan sarjana terapan, 3.00≤IPK<3.25 untuk program profesi \ndan magister terapan. \n \nBagian Kelima \nLaporan Kinerja Akademik dan Ijazah \n \nPasal 32 \n \n(1) Kartu Hasil Studi (KHS) adalah laporan tentang nilai mata kuliah yang \ndiperoleh mahasiswa selama satu semester. \n(2) Laporan Kemajuan Akademik (LKA) adalah laporan tentang nilai mata \nkuliah yang diperoleh mahasiswa selama masa studi. \n(3) Transkrip akademik adalah laporan tentang jumlah sks dan nilai terakhir \nseluruh mata kuliah yang memenuhi ketentuan yudisium dan disyaratkan', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(144, 13, '19 \nkurikulum program studi yang diperoleh mahasiswa selama kuliah di \nPolibatam. \n(4) Ijazah untuk program diploma, sarjana terapan, dan magister terapan, atau \nsertifikat untuk program profesi , merupakan tanda bukti secara resmi \nseseorang telah menyelesaikan program pendidikan dan menyandang gelar \natau sebutan sesuai ketentuan perundangan yang berlaku. \n(5) Surat Keterangan Pendamping Ijazah (SKPI) atau Diploma Supplement \nadalah surat pernyataan resmi yang dikeluarkan oleh Polibatam, berisi \ninformasi tentang portofolio pencapaian akademik atau kualifikasi lainnya \nyang relevan. \n(6) Transkrip akademik, ijazah, dan sertifikat sebagaimana pada ayat (3) dan (4) \ndiberikan kepada mahasiswa yang telah memenuhi segala ketentuan \npersyaratan akademik dan administrasi pendidikan. \n(7) Transkrip akademik, ijazah, dan sertifikat sebagaimana pada ayat (3) dan (4) \nakan diterbitkan secara digital. \n(8) Transkrip akademik, ijazah, dan sertifikat sebagaimana pada ayat (3) dan (4) \nakan dicetak sesuai dengan permintaan dari Lulusan. \n(9) SKPI sebagaimana dimaksud dalam ayat (5) dapat diakses oleh setiap \nmahasiswa dan para pemangku kepentingan pada laman https://talent-\nhub.id. \n(10) Pengurusan kehilangan ijazah, legalisir ijazah, dan penerbitan transkrip \nmengacu pada prosedur yang berlaku melalui sistem informasi dan layanan \nmahasiswa pada laman https://sim.polibatam.ac.id. \n(11) Jika terjadi kehilangan Ijazah , Sertifikat, dan Transkrip Akademik yang \ntercetak, Polibatam hanya memfasilitas menerbitkan surat keterangan yang \nmenyatakan sebagai alumni Polibatam dengan menyertakan IPK sesuai yang \ntertera dalam laman s istem informasi akademik Polibatam \nhttp://sid.polibatam.ac.id \n \n \nBAB VII \nSARANA DAN PRASARANA \n \nBagian Kesatu \nPengelolaan Fasilitas Perkuliahan \n \nPasal 33 \n \n(1) Untuk mendukung proses pembelajaran dalam mendukung pencapaian \nCPL, Polibatam menyediakan fasilitas pembelajaran berupa ruang kuliah, \nworkspace, laboratorium , workshop, atau studio beserta perangkat, \nperalatan, mesin yang tersedia di dalamnya untuk digunakan oleh \nmahasiswa secara bertanggung jawab. \n(2) Ruang kuliah dapat digunakan bersama oleh seluruh jurusan dan diatur \nsesuai kebutuhan jadwal kuliah yang berlaku. \n(3) Fasilitas praktek yang meliputi workspace, laboratorium, workshop atau \nstudio, beserta fasilitas pendukungnya dikelola oleh jurusan.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(145, 13, '20 \n(4) Sesuai dengan kompetensi mahasiswa yang akan dicapai, jurusan dapat \nmemanfaatkan sarana, fasilitas dan sumber daya unit kerja lain untuk \nmembantu penyelenggaraan pendidikan. \n \n \nBagian Kedua \nPemanfaatan Workspace, Laboratorium,Workshop, atau Studio \n \nPasal 34 \n \n(1) Penggunaan workspace, laboratorium, workshop, atau studio hanya \ndilayani sesuai dengan jadwal yang telah ditentukan oleh pengelola. \n(2) Pengguna workspace, laboratorium, workshop, atau studio wajib mengikuti \nperaturan yang telah ditetapkan oleh pengelola workshop, laboratorium, \nworkshop, atau studio. \n(3) Pengguna workspace, laboratorium, workshop, atau studio harus menjaga \nketenangan, kerapian, dan kebersihan workspace, laboratorium, workshop, \natau studio. \n(4) Pengguna workspace, laboratorium, workshop, atau studio harus \nmenggunakan peralatan keselamatan kerja sesuai dengan ketentuan \nperundangan yang berlaku. \n(5) Sebelum meninggalkan ruang, pengguna workspace, laboratorium, \nworkshop, atau studio harus membersihkan dan mengembalikan fasilitas-\nfasilitas yang digunakan pada tempat yang telah ditentukan. \n(6) Pelanggaran terhadap tata tertib ini , jurusan akan memberikan sanksi \ndalam bentuk antara lain: \na. teguran oleh pengelola workspace, laboratorium, workshop, atau studio; \nb. surat peringatan; \nc. diberikan suspensi (skorsing), minimal 1 bulan, maksimal 2 semester \n(cuti). Selama masa suspensi, tidak ada penggantian layanan akademik \ndan pembelajaran pada waktu lain; \nd. pencabutan status kemahasiswaannya secara permanen. \n \nBagian Ketiga \nLayanan Sistem Informasi \n \nPasal 35 \n \n(1) Politeknik menyediakan akses terhadap layanan sistem informasi politeknik \nmelalui jaringan intranet dan atau internet untuk digunakan mahasiswa \nsecara bertanggung jawab. \n(2) Pemanfaatan layanan sistem informas i, jaringan intranet dan internet \ndiarahkan pada pemenuhan kebutuhan perkuliahan \n(3) Pengguna layanan sistem informasi dan jaringan dilarang: \na. menggunakan layanan dan jaringan untuk mengakses, menyebarkan \nkonten pornografi atau konten lain sejenis yang melanggar norma \nkesusilaan dan norma hukum; \nb. menggunakan layanan dan jaringan untuk mengakses, menyebarkan \nkonten mengarah pada SARA atau konten lain sejenis yang melanggar \nnorma kesopanan dan norma hukum;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(146, 13, '21 \nc. mengancam, mengganggu, atau merusak jaringan dan sistem informasi \npoliteknik baik disengaja maupun tidak disengaja; \nd. menghambat atau mengganggu pemanfaatan layanan sistem informasi \ndan jaringan oleh pengguna lain; dan \ne. menggunakan akun pengguna dan kata kunci ( password) milik orang \nlain yang bukan haknya atau sebaliknya memberikan akses akun \npengguna dan kata kunci yang dimilikinya kepada orang lain; \n(4) Pelanggaran terhadap tata tertib ini, jurusan atau kelompok kerja akademik \ndan kemahasiswaan akan memberikan sanksi dalam bentuk antara lain: \na. surat peringatan; \nb. suspensi, minimal 1 bulan, maksimal 2 semester (cuti). Selama masa \nsuspensi, tidak ada penggantian layanan akademik dan pembelajaran \npada waktu lain; atau \nc. pencabutan status kemahasiswaannya secara permanen. \n \n \nBagian Keempat \nLayanan Perpustakaan \n \nPasal 36 \n \n(1) Penerima layanan perpustakaan adalah anggota perpustakaan Polibatam, \ndibuktikan dengan kartu identitas yang dikeluarkan oleh Polibatam yang \nmasih berlaku. \n(2) Pengguna perpustakaan harus mematuhi tata tertib perpustakaan \nPolibatam yang berlaku. \n(3) Layanan perpustakaan buka pada hari Senin sampai Jum’at di antara \nrentang waktu pukul 08.00 WIB sampai dengan pukul 22.00 WIB. \n \n \nBagian Kelima \nPemeliharaan Kebersihan dan Kesehatan Lingkungan \n \nPasal 37 \n \n(1) Mahasiswa wajib mendukung pelaksanaan pemeliharaan kebersihan di \nlingkungan kampus. \n(2) Mahasiswa bertanggung jawab terhadap setiap sampah yang dihasilkan \nbaik di dalam kelas maupun di lingkungan kampus dan membuangnya \npada tempat-tempat yang disediakan. \n(3) Pada musim hujan, mahasiswa diharapkan untuk memastikan kebersihan \nsepatu atau alas kaki sebelum memasuki gedung. \n(4) Untuk menjaga kebersihan dan kenyamanan kantin dan area sekitarnya, \nmahasiswa harus mengembalikan peralatan makan dan /atau membuang \nsampah bekas makan atau minum di tempat yang telah disediakan. \n(5) Merokok hanya diperbolehkan pada area yang telah ditetapkan. \n(6) Menumbuhkan kegiatan saling mengingatkan terhadap semua tindakan \nyang bertentangan dengan upaya pemeliharaan kebersihan dan kesehatan. \n(7) Pelanggaran terhadap tata tertib ini, jurusan atau kelompok kerja akademik \ndan kemahasiswaan akan memberikan sanksi dalam bentuk antara lain:', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(147, 13, '22 \nc. Teguran oleh pengaman dalam (pamdal) Polibatam; \nd. surat peringatan; \ne. suspensi (skorsing), minimal 1 bulan, maksimal 2 semester (cuti). \nSelama masa skorsing, tidak ada penggantian layanan akademik dan \npembelajaran pada waktu lain; atau \nf. pencabutan status kemahasiswaannya secara permanen. \n \n \nBagian Keenam \nPenggunaan Fasilitas Umum \n \nPasal 38 \n \n(1) Dalam penggunaan fasilitas umum di kampus, pengguna wajib \nmempromosikan nilai -nilai keamanan, keselamatan, menghormati \npengguna lain, ketertiban, kebermanfaatan, dan saling menjaga. \n(2) Pengguna ruangan wajib memastikan lampu penerangan, penyejuk udara \ndan per alatan elektronika lainnya dalam kondisi mati pada saat \nmeninggalkan ruangan. \n(3) Pengguna ruang toilet wajib memastikan lampu penerangan dalam kondisi \nmati dan kran air dalam kondisi tertutup pada saat meninggalkan ruang \ntoilet \n(4) Penggunaan lift sebaiknya diarahkan mengikuti ketentuan sebagai berikut: \na. tidak melakukan tindakan yang membahayakan lift dan diri sendiri; \nb. digunakan minimal bersama 3 pengguna lainnya dalam rangka \npenghematan energi; \nc. mengantri, menunggu dan memberikan jalan kepada pengguna lift yang \ningin keluar; dan \nd. lebih memilih penggunaan tangga untuk perpindahan 1 lantai. \n(5) Menumbuhkan kegiatan saling mengingatkan terhadap semua tindakan \nyang bertentangan dengan upaya pemeliharaan kebersihan dan hemat \nenergi \n(6) Pengguna fasilitas umum dalam kampus mempraktekkan hidup bersih dan \nmenggalakkan budaya antri. \n \n \nBagian Ketujuh \nPertanggungjawaban terhadap Barang Milik Polibatam \n \nPasal 39 \n \n(1) Setiap mahasiswa, secara perorangan, bertanggung jawab terhadap \nkeberfungsian dan kelengkapan barang milik Poli batam baik berupa buku, \nbahan atau peralatan yang digunakan \n(2) Mahasiswa diharuskan segera melapor kepada dosen, laboran, teknisi, atau \npetugas unit layanan yang bersangkutan jika menerima bahan atau \nperalatan yang rusak atau tidak lengkap. \n(3) Mahasiswa diharuskan segera melapor kepada dosen, laboran, teknisi, atau \npetugas unit layanan yang bersangkutan apabila merusak atau \nmenghilangkan barang milik Polibatam yang digunakannya.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(148, 13, '23 \n(4) Mahasiswa yang merusak atau menghilangkan barang milik Polibatam \nbertanggung jawab untuk memperbaiki atau mengganti sesuai dengan \nketentuan pengelolaan barang milik negara maksimal 1 tahun setelah \nditetapkan. \n(5) Pertanggungjawaban atas kehilangan atau kerusakan yang tidak dapat \ndilakukan secara perseorangan atau kelompok yang terlibat, akan \ndibebankan kepada seluruh mahasiswa dari kelas yang bersangkutan. \n \n \nBAB VIII \nKECURANGAN AKADEMIK DAN SANKSINYA \n \nBagian Kesatu \nKecurangan Akademik \n \nPasal 40 \n \n(1) Lulusan Polibatam yang berbudi luhur hanya dapat dicapai melalui \npendidikan bernorma akademik luhur. \n(2) Mahasiswa dilarang melakukan perbuatan berikut: \na. melakukan atau bekerja sama dengan orang lain dalam bentuk apapun, \nuntuk mencontek dan melakukan kecurangan saat proses dan evalu asi \nhasil pembelajaran, atau penyelesaian tugas akademik lainnya; \nb. mengganti, mengubah, atau memalsukan nilai, transkrip akademik, \nijazah, sertifikat, KTM, atau dokumen lainnya yang dianggap penting oleh \nPolibatam; \nc. menggunakan karya orang lain sebagai karya sendiri dalam suatu \nkegiatan akademik tanpa menyebut acuan yang dipakai; \nd. mempengaruhi atau mencoba mempengaruhi orang lain dengan cara \nmembujuk, memberi hadiah, atau mengancam, bertujuan memperoleh \nkemudahan dalam menyelesaikan ujian, tugas mandiri, lapor an \npraktikum, dan sebagainya; \ne. menyediakan sarana atau prasarana yang dapat menyebabkan terjadinya \nhal yang tidak diperbolehkan dalam kegiatan akademik; dan \nf. melakukan tindakan yang bertentangan dengan hukum dan norma \nakademik lainnya diluar ketentuan yang tersebut di atas. \n \n \nBagian Kedua \nSanksi Kecurangan Akademik \n \nPasal 41 \n \n(1) Sanksi adalah salah satu bagian dalam proses pendidikan, bertujuan \nmenyadarkan mahasiswa atas pelanggaran norma akademik yang telah \ndilakukannya. \n(2) Diberlakukan 5 (lima) peringkat sanksi, yaitu berupa: \na. peringatan tertulis;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(149, 13, '24 \nb. pemberian nilai 0 pada hasil asesmen atau evaluasi lainnya untuk \nmahasiswa yang terlibat; \nc. pemberian nilai akhir E bagi mahasiswa yang terlibat; \nd. skorsing, minimal 1 bulan, maksimal 2 semester (cuti). Selama masa \nskorsing, tidak ada penggantian layanan akademik dan pembelajaran \npada waktu lain; atau \ne. pencabutan status kemahasiswaannya secara permanen. \n(3) Pelaku kecurangan dapat dikenakan sanksi berikut: \nPasal yang dilanggar Sanksi yang dikenakan terhadap \nPelanggaran pertama Pelanggaran kedua Pelanggaran ketiga \nPasal 40.2.a Pasal 41.2.b atau \n41.2.c \nPasal 41.2.b atau \n41.2.c \nPasal 41.2.b atau \n41.2.c \nPasal 40.2.b Pasal 41.2.d atau \n41.2.e \nPasal 41.2.e - \nPasal 40.2.c Pasal 41.2.b Pasal 41.2.c Pasal 41.2.c \nPasal 40.2.d Pasal 41.2.a Pasal 41.2.b atau \n41.2.c \nPasal 41.2.c \nPasal 40.2.e Pasal 41.2.a Pasal 41.2.d atau \n41.2.e \nPasal 41.2.e \nPasal 40.2.f Pasal 41.2.a atau \n41.2.d atau 41.2.e \nPasal 41.2.d atau \n41.2.e \nPasal 41.2.e \n \n(4) Pelaksanaan sanksi akademik tidak akan mengubah batas waktu studi yang \ntelah ditetapkan. \n(5) Semua hasil yang diperoleh dengan kecurangan, tidak diakui. \n(6) Penetapan sanksi dilakukan oleh Wakil Direktur Bidang Akademik, setelah \nmendapat rekomendasi dari Kelompok Kerja Akademik, kem ahasiswaan \ndan/atau Jurusan.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(150, 13, 'DAFTAR ISI \n \nBAB I HAK DAN KEWAJIBAN MAHASISWAN .................................................................. 27 \nBagian Kesatu Hak Mahasiswa ........................................................................................... 27 \nBagian Kedua Kewajiban dan Kode Etik Mahasiswa ................................................... 27 \nBAB II KEGIATAN EKSTRA KURIKULER ......................................................................... 28 \nBagian Kesatu ........................................................................................................................... 28 \nKegiatan Ekstra Kurikuler .................................................................................................... 28 \nBagian Kedua ............................................................................................................................ 28 \nPortofolio Kemahasiswaan .................................................................................................... 28 \nBagian Ketiga ............................................................................................................................. 28 \nKegiatan di Luar Kampus ...................................................................................................... 28 \nBAB III ORGANISASI KEMAHASISWAAN .......................................................................... 29 \nBagian Kesatu Definisi Organisasi Kemahasiswaan .................................................... 29 \nBagian Kedua Tata Laksana Organisasi Kemahasiswaan.......................................... 29 \nBagian Ketiga Pemanfaatan Fasilitas oleh Organisasi Kemahasiswaan ............... 30 \nBAB IV BEASISWA ...................................................................................................................... 30 \nBagian Kesatu Definisi dan sumber Beasiswa ............................................................... 30 \nBagian Kedua Kriteria dan Persyaratan Beasiswa ........................................................ 31 \nBagian Ketiga Jangka Waktu Beasiswa ............................................................................ 31 \nBagian Keempat Penetapan Penerima Beasiswa ........................................................... 31 \nBAB V ASRAMA MAHASISWA ................................................................................................ 32 \nBagian Kesatu Asrama Mahasiswa .................................................................................... 32', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(151, 13, 'BAB V ASRAMA MAHASISWA ................................................................................................ 32 \nBagian Kesatu Asrama Mahasiswa .................................................................................... 32 \nBagian Kedua Penghuni Asrama ........................................................................................ 32 \nBagian Ketiga Tarif dan Mekanisme Pembayaran Asrama ........................................ 32 \nBAB VI PELAYANAN MAHASISWA ....................................................................................... 33 \nBagian Kesatu Pelayanan Mahasiswa ............................................................................... 33 \nBAB VII PENGHARGAAN .......................................................................................................... 33 \nBagian Kesatu Penghargaan ................................................................................................. 33 \nBagian Kedua Pengakuan Prestasi, Karya, dan Aktivitas Mahasiswa di Luar \nProgram Studi ........................................................................................................................... 34 \nBAB VIII KONDITE DAN NORMA KEMAHASISWAAN .................................................. 34 \nBagian Kesatu Kondite dan Norma Kemahasiswaan ................................................... 34 \nBagian Kedua Sanksi Pelanggaran Kondite dan Norma Organisasi \nKemahasiswaan ........................................................................................................................ 35 \nBAB IX. MAHASISWA SEBAGAI ANGGOTA MASYARAKAT ...................................... 35 \nBagian Kesatu Perilaku dalam Kehidupan Kampus .................................................... 35 \nBagian Kedua Sanksi bagi Perilaku Yang Melanggar .................................................. 36', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(152, 13, 'BAB I \nHAK DAN KEWAJIBAN MAHASISWAN \n \nBagian Kesatu \nHak Mahasiswa \n \nPasal 1 \n \n1) Menggunakan kebebasan akademik secara bertanggung jawab untuk \nmengkaji ilmu pengetahuan sesuai dengan norma dan etika akademik; \n2) Memperoleh pengajaran dan layanan bidang akademik dan administratif \ndengan sebaik -baiknya, sesuai dengan bakat, minat, kegemaran dan \nkemampuan; \n3) Mendapat bimbingan dari dosen yang bertanggung jawab atas program \nstudi yang diikutinya dalam penyelesaian studi; \n4) Memperoleh layanan informasi tentang kegiatan kemahasiswaan; \n5) Menyelesaikan studi lebih awal dari jadwal yang ditetapkan sesuai \ndengan peraturan yang berlaku; \n6) Memperoleh layanan kesejahteraan dan kesehatan sesuai dengan \nketentuan yang berlaku; \n7) Memanfaatkan sarana dan prasarana yang ada di Politeknik Negeri \nBatam, jurusan, program studi atau bagian, baik secara pribadi maupun \nmelalui perwakilan atau organisasi kemahasiswaan, untuk kepentingan \npembelajaran; \n8) Ikut serta dalam kegiatan organisasi kemahasiswaan di tingkat \nPoliteknik Negeri Batam , jurusan/ program studi atau bagian sesuai \ndengan ketentuan yang berlaku; \n \nBagian Kedua \nKewajiban dan Kode Etik Mahasiswa \n \nPasal 2 \n \n1) Belajar dengan tekun dan sungguh -sungguh agar memperoleh prestasi \ntinggi; \n2) Ikut memelihara sarana dan prasarana serta kebersihan, ketertiban dan \nkeamanan dalam lingkungan kampus; \n3) Menghargai kaedah ilmu pengetahuan, teknologi, dan atau kesenian; \n4) Ikut menjaga suasana akademik yang kondusif; \n5) Terlibat aktif dalam kegiatan kemahasiswaan; \n6) Menjaga nama baik, citra, dan martabat Perguruan Tinggi \n7) Ikut menanggung biaya penyelenggaraan pendidikan, kecuali bagi \nmahasiswa yang dibebaskan dari kewajiban tersebut sesuai dengan \nperaturan yang berlaku; \n8) Berpakaian dan berpenampilan rapi, sopan, dan patut; \n9) Menjunjung tinggi adat istiadat, sopan santun serta etika yang berlaku; \n10) Ikut Menjaga serta mencegah kampus dari kegiatan politik praktis; \n11) Menaati kewajiban-kewajiban yang dibebankan sesuai dengan peraturan \nperundang- undangan yang berlaku.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(153, 13, 'BAB II \nKEGIATAN EKSTRA KURIKULER \n \nBagian Kesatu \nKegiatan Ekstra Kurikuler \n \nPasal 3 \n \n(1) Kegiatan ekstra kurikuler adalah kegiatan kemahasiswaan yang meliputi \npenalaran dan keilmuan, minat, bakat dan kegemaran serta upaya \nperbaikan kesejahteraan mahasiswa Politeknik Negeri Batam. \n(2) Kegiatan ekstra kurikuler bidang penalaran dan keilmuan dilaksanakan \noleh organisasi mahasiswa tingkat jurusan, organisasi mahasiswa \ntingkat pusat di bawah pembinaan jurusan bersama koordinasi Bidang \nKemahasiswaan. \n(3) Kegiatan ekstra kurikuler bidang minat dan kegemaran serta upaya \nperbaikan kesejahteraan mahasiswa, dilaksanakan oleh organisasi \nkemahasiswaan di bawah pembinaan dan koordinasi Bidang \nKemahasiswaan. \n(2) Kegiatan ekstra kurikuler mempunyai wadah dalam bentuk organisa si \nkemahasiswaan yang diselenggarakan oleh, dari, dan untuk mahasiswa. \n(3) Setiap mahasiswa berhakmemilihlebih dari satu kegiatan ekstra \nkurikuler \n \nBagian Kedua \nPortofolio Kemahasiswaan \n \nPasal 4 \n \n(1) Dalam rangka penguatan soft skill mahasiswa, Politeknik Negeri Batam \nmenerapkan Portofolio Kemahasiswaan yang bertujuan untuk \nmendokumentasikan aktivitas, prestasi, karya, penelitian, dan \npengalaman mahasiswa selama masa perkuliahan \n(2) Penyusunan dan penilaian Porfolio Kemahasiswaan mencakup: Prestasi \nPenalaran, Minat, Bakat, Organisasi, Sosial Kemasyarakatan; \n(3) Pengisian Portofolio Kemahasiswaan melalui platform Talent Hub dan \nwajib diperbaharui setiap semester. \n(4) Penerapan, penilaian dan penetapan Portofolio Kemahasiswaan dikelola \ndan diatur oleh bidang kemahasiswaan dan disahkan oleh Direktur \nmelalui Pembantu Direktur yang menangani bidang kemahasiswaan. \n \nBagian Ketiga \nKegiatan di Luar Kampus \n \nPasal 5 \n \n(1) Kegiatan luar kampus adalah kegiatan yang dijalani mahasiswa \nPoliteknik Negeri Batam selama berada di luar lingkungan kampus yang', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(154, 13, 'berhubungan dengan kegiatan akademik maupun kegiatan ekstra \nkurikuler. \n(2) Semua kegiatan mahasiswa di luar kampus yang mengatasna makan \nPoliteknik Negeri Batam harus mendapat persetujuan Pembantu Direktur \nIII Bidang Kemahasiswaan, Kerjasama dan Alumni. \n \n \nBAB III \nORGANISASI KEMAHASISWAAN \n \nBagian Kesatu \nDefinisi Organisasi Kemahasiswaan \n \nPasal 6 \n \n(1) Organisasi kemahasiswaan di Politeknik Negeri Batam adalah wahana \ndan sarana pengembangan karakter diri mahasiswa ke arah perluasan \nwawasan dan peningkatan kecendikiawanan serta integritas kepribadian \ndan penguatan kebangsaan untuk mencapai tujuan pendidikan dan \nmerupakan kelengkapan non struktural Politeknik Negeri Batam serta \nberkedudukan di Politeknik Negeri Batam. \n(2) Bentuk organisasi kemahasiswaan diPoliteknik Negeri Batam terdiri dari \nBadan Eksekutif Mahasiswa (BEM), Dewan Legislatif Mahasiswa (DLM), \nHimpunan Mahasiswa Jurusan (HMJ ), dan Unit Kegiatan Mahasiswa \n(UKM), yang telah mendapat pengesahan pendiriannya dari Politeknik \nNegeri Batam melalui Pembantu Direktur Bidang Kemahasiswaan \n(3) Organisasi kemahasiswaan ekstra kampus selain yang disebut ayat 2, \ndapat beraktifitas di lingkunga n kampus dengan terlebih dahulu \nmengajukan dan mendapatkan ijin dari pembantu Direktur Bidang \nKemahasiwaan serta mematuhi ketentuan dan aturan yang berlaku di \nPoliteknik Negeri Batam \n \nBagian Kedua \nTata Laksana Organisasi Kemahasiswaan \n \nPasal 7 \n \n(1) Organisasi kemahasiswaan dipimpin oleh seorang ketua. \n(2) Untuk keperluan pembinaan dan pemantauan, organisasi \nkemahasiswaan diwajibkan untuk melakukan registrasi setiap tahun \ndengan menyertakan: \na. susunan pengurus dan dosen pembina; \nb. laporan kegiatan pada tahun sebelumnya; \nc. rencana program kerja tahun berikutnya \n(3) Pengurus ditetapkan melalui pemilihan dengan tata cara dan mekanisme \nyang dipilih oleh mahasiswa.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(155, 13, '(4) Untuk kepentingan kaderisasi, mahasiswa yang pernah menjabat sebagai \nketua tidak dapat dipilih kembali sebagai ketua pada periode \nkepengurusan berikutnya pada organisasi kemahasiswaan yang sama \n(5) Kegiatan yang dilaksanakan oleh organisasi kemahasiswaan di d alam \natau di luar kampus yang melibatkan pihak -pihak dari luar kampus, \nharus seijin Direktur melalui Pembantu Direktur Bidang Kemahasiswaan \ndan pihak-pihak terkait sesuai prosedur yang berlaku. \n(6) Organisasi kemahasiswaan dilarang berafiliasi dengan organisas i politik \natau organisasi lain yang berbau SARA, radikal, provokatif, dan \nmenyebarluaskan kebencian \n(7) Bagi organisasi kemahasiswaan yang tidak melaksanakan ketentuan \nayat (1) s.d. (6) akan mendapat sanksi sesuai peraturan yang berlaku. \n \n \nBagian Ketiga \nPemanfaatan Fasilitas oleh Organisasi Kemahasiswaan \n \nPasal 8 \n \n(1) Setiap kegiatan kemahasiswaan dapat dilaksanakan apabila telah \nmendapatkan persetujuan Bidang Kemahasiswaan. \n(2) Sarana dan prasarana Politeknik Negeri Batam dapat dimanfaatkan \nuntuk melaksanakan kegiatan kemahasiswaan. \n(3) Setiap pengajuan penggunaan fasilitas Politeknik Negeri Batam harus \ndilakukan melalui sistem informasi dan layanan mahasiswa (SILAM). \n(4) Ketua pelaksana kegiatan kemahasiswaan bertanggungjawab terhadap \nkeamanan, keutuhan, dan kebersihan fasilitas yang digunakan. \n \n \nBAB IV \nBEASISWA \n \nBagian Kesatu \nDefinisi dan sumber Beasiswa \n \nPasal 9 \n \n(1) Beasiswa adalah bantuan yang sifatnya tidak mengikat dan atau \nmengikat, diberikan kepada mahasiswa yang memenuhi kriteria dan \nbertujuan untuk mendorong prestasi studi, membantu biaya studi, dan \nmenumbuhkan kepedulian terhadap almamater. \n(2) Sumber dana beasiswa dapat berasal Polibatam, instansi/lembaga \npemerintah, swasta maupun asing, yayasan, perorangan, dan lembaga \nlainnya', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(156, 13, 'Bagian Kedua \nKriteria dan Persyaratan Beasiswa \n \nPasal 10 \n \n(1) Mahasiswa yang berhak mengajukan beasiswa adalah yang mempunyai \nsatu atau lebih kriteria berikut ini: \na. berprestasi akademik tinggi; \nb. tidak ditunjang oleh keadaan ekonomi yang memadai; \nc. aktif dalam kegiatan kemahasiswaan; \nd. kriteria lain yang diberikan oleh pemberi beasiswa. \n(2) Persyaratan administratif untuk mahasiswa yang mengajukan \npermohonan beasiswa adalah: \na. terdaftar sebagai mahasiswa aktif pada semester berjalan dan \nmenunjukkan Kartu Tanda Mahasiswa (KTM) yang berlaku; \nb. memiliki IPK yang memenuhi syarat yang ditetapkan untuk setiap \njenis beasiswa; \nc. tidak sedang atau mengambil cuti akademik; \nd. tidak terkena kasus atau sanksi akademik dan/atau administratif; \n(3) Permohonan untuk mendapatkan beasiswa dapat dilaksanakan sesuai \nprosedur dan ketentuan yang berlaku melalui sistem informasi dan \nlayanan mahasiswa (SILAM). \n \nBagian Ketiga \nJangka Waktu Beasiswa \n \nPasal 11 \n \n(1) Jangka waktu pemberian beasiswa tergantung pada pemberi beasiswa. \n(2) Setelah berakhirnya periode pemberian beasiswa, penerima beasiswa \ndapat mengajukan permohonan perpanjangan beasiswa untuk periode \nberikutnya selama memenuhi kriteria dan persyaratan yang ditetapkan \n(3) Beasiswa dapat dihentikan apabila: \na. penerima beasiswa melanggar ketentuan atau peraturan/tata tertib \nyang berlaku di Republik Indonesia dan Politeknik Negeri Batam; \nb. penerima beasiswa tidak terdaftar sebagai mahasiswa aktif pada \nsemester berikutnya atau permanen; \nc. terbukti data permohonan beasiswa tidak diisi secara benar; \nd. prestasi akademik penerima beasiswa menurun; \n \nBagian Keempat \nPenetapan Penerima Beasiswa \n \nPasal 12 \n \n(1) Pemilihan dan seleksi calon penerima beasiswa dilakukan oleh tim yang \nditetapkan oleh Direktur. \n(2) Pemohon beasiswa yang telah terpilih sebagai penerima beasiswa akan \ndisahkan dengan surat keputusan Direktur.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(157, 13, '(3) Mahasiswa penerima beasiswa harus bersedia mengikuti berbagai \nkegiatan Politeknik Negeri Batam. \n \nBAB V \nASRAMA MAHASISWA \n \nBagian Kesatu \nAsrama Mahasiswa \n \nPasal 13 \n \n(1) Asrama Mahasiswa diprioritaskan bagi implementasi program \npenempatan mahasiswa yang ditetapkan Direktur Politeknik Negeri \nBatam \n(2) Bagi mahasiswa yang mengajukan penggunaan asrama di luar ayat 1, \nakan dipertimbangkan berdasarkan keterse diaan kapasitas dan \nkebijakan Politeknik Negeri Batam melalui Pembantu Direktur Bidang \nKemahasiwaan \n(3) Ijin tinggal penghuni asrama untuk program penempatan mahasiwa akan \ndievaluasi setiap tahun. \n(4) Perpanjangan ijin tinggal dapat dilakukan penghuni melalui pros es \nregistrasi ulang setiap semester yang jadwalnya akan diumumkan \n(5) Permohonan untuk mendapatkan atau memperpanjang ijin tinggal dapat \ndilaksanakan sesuai prosedur dan ketentuan yang berlaku melalui \nsistem informasi dan layanan mahasiswa (SILAM). \n \nBagian Kedua \nPenghuni Asrama \n \nPasal 14 \n \n(1) Penghuni asrama wajib mengikuti program pembinaan yang telah \nditetapkan Politeknik Negeri Batam. \n(2) Penghuni asrama wajib mematuhi tata tertib asrama mahasiswa yang \ntelah ditetapkan Politeknik Negeri Batam. \n(3) Penghuni yang mengabaikan kewajiban di atas dapat mengakibatkan \nhilangnya status sebagai penghuni asrama mahasiswa. \n \nBagian Ketiga \nTarif dan Mekanisme Pembayaran Asrama \n \nPasal 15 \n \n(1) Besaran tarif asrama yang berlaku berdasarkan surat keputusan (SK) \nTarif Layanan yang ditetapkan Direktur. \n(2) Pembayaran biaya asrama dilakukan oleh penghuni melalui koordinator \nprogram penempatan', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(158, 13, 'BAB VI \nPELAYANAN MAHASISWA \n \nBagian Kesatu \nPelayanan Mahasiswa \n \nPasal 16 \n \n(1) Bidang pelayanan mahasiswa dimaksudkan untuk melayani \nkepentingan-kepentingan mahasiswa dalam persoalan kesehatan, \nbimbingan konseling, bursa kerja, pencegahan dan penanganan \nkekerasan seksual , intoleransi , diskriminasi serta perundungan \n(bullying) dan penanggulangan penyalahgunaan obat-obatan terlarang. \n(2) Pelayanan tersebut dilakukan oleh unit tertentu yang ditetapkan oleh \nDirektur. \n \nBAB VII \nPENGHARGAAN \n \nBagian Kesatu \nPenghargaan \n \nPasal 17 \n \n(1) Penghargaan diberikan kepada mahasiswa berprestasi di setiap Program \nStudi pada setiap wisuda \n(2) Penghargaan diberikan kepada mahasiswa yang meraih Indeks Prestasi \nKumulatif (IPK) tertinggi di Progam Studi pada setiap angkatan dan \nberkelakuan baik. \n(5) Penghargaan juga dapat diberikan kepada mahasiswa yang meraih \nprestasi terbaik dalam bidang ekstra kurikuler. \n(6) Bentuk penghargaan yang diberikan Politeknik Negeri Batam kepada \nmahasiswa, meliputi: \na. piagam penghargaan, plakat, vandel atau bentuk cendera mata \nlainnya. \nb. bantuan kesejahteraan berupa beasiswa atau ker inganan dalam \npembayaran sumbangan pembinaan pendidikan. \nc. keikutsertaan dalam kegiatan sosial peserta kehormatan baik \nditingkat Politeknik Negeri Batam maupun kegiatan nasional lainnya. \nd. bentuk lain yang diatur oleh Ketetapan Direktur.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(159, 13, 'Bagian Kedua \nPengakuan Prestasi, Karya, dan Aktivitas Mahasiswa \ndi Luar Program Studi \n \nPasal 18 \n \n(1) Tujuan pengakuan adalah untuk memberikan apresiasi terhadap karya \ndan prestasi, serta aktivitas lain sebagai hak mahasiswa untuk \nmengambil mata kuliah di luar program studi ke dalam SKS \n(2) Pengakuan dapat dilakukan terhadap : \na. Prestasi yang diperoleh mahasiswa \nb. Karya yang dihasilkan oleh mahasiswa \nc. Aktivitas mahasiswa di luar program studi yang meliputi: \n1. Magang/praktik industri \n2. Proyek di desa/daerah tertinggal \n3. Pertukaran mahasiswa \n4. Penelitian \n5. Wirausaha \n6. Studi/Proyek independen \n7. Proyek kemanusiaan \n8. Mengajar di sekolah \n9. Aktivitas lain yang disetujui oleh jurusan atau program studi \n(3) Ketentuan tentang pengakuan prestasi, karya, dan aktivitas mahasiswa \ndi luar program studi akan diatur oleh ketetepan difrektur \n \nBAB VIII \nKONDITE DAN NORMA KEMAHASISWAAN \n \nBagian Kesatu \nKondite dan Norma Kemahasiswaan \n \nPasal 19 \n \nMahasiswa atau organisasi kemahasiswaan tidak dibenarkan melakukan \nhal-hal sebagai berikut: \na. mengancam atau mengganggu secara substansial usaha -usaha untuk \nmenjaga pelaksanaan tata tertib dan disiplin di Politeknik Negeri Batam; \nb. melakukan tindakan yang membahayakan atau mengancam kesehatan \natau keamanan sivitas akademika Politeknik Negeri Batam maupun \nindividu lain di dalam dan di luar kampus Politeknik Negeri Batam. \nc. membantu orang lain untuk ikut dalam suatu kegiatan yang mengganggu \natau merusak; \nd. mencuri atau merusak setiap fasilitas yang dikelola atau dikendalikan \noleh Politeknik Negeri Batam; \ne. berpartisipasi dalam suatu kegiatan yang mengganggu pelaksanaan \nfungsi dan tugas Politeknik Negeri Batam; \nf. melakukan tindakan yang merendahkan harkat dan martabat sivitas \nakademika dan staf administrasi Politeknik Negeri Batam;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(160, 13, 'g. melakukan tindakan yang mengarah pada aktivitas politik praktis secara \nlangsung maupun tidak langsung. \n \n \nBagian Kedua \nSanksi Pelanggaran Kondite dan Norma Organisasi Kemahasiswaan \n \nPasal 20 \n \nMahasiswa atau organisasi kemahasiswaan yang melakukan tindakan yang \ntidak dibenarkan dapat dikenakan sanksi berupa: \na. dilarang menggunakan fasilitas yang dikelola oleh Politeknik Negeri \nBatam; \nb. diharuskan membayar ganti rugi; \nc. dikeluarkan dari kegiatan kelas (kuliah), laboratorium, bengkel, ataupun \nstudio; \nd. dikenakan skorsing (dicabut status sebagai mahasiswa untuk sementara) \ndari Politeknik Negeri Batam; \ne. Pencabutan status kemahasiswaannya secara permanen \nf. pembekuan kegiatan organisasi kemahasiswaan. \n \n \nBAB IX. \nMAHASISWA SEBAGAI ANGGOTA MASYARAKAT \n \nBagian Kesatu \nPerilaku dalam Kehidupan Kampus \n \nPasal 21 \n \n(1) Mahasiswa, sebagai individu yang merupakan anggota komunitas \nkampus, agar berperilaku sesuai dengan norma, etika dan sopan santun \nsecara umum yang berlaku. \n(2) Mahasiswa agar ikut memelihara, menjaga keutuhan, dan kebersihan \nfasilitas umum serta ruang publik dalam kampus. \n(3) Mahasiswa agar mempunyai kepedulian dan kepekaan terhadap \nkehidupan sivitas akademika Politeknik Negeri Batam. \n(4) Mahasiswa wajib menaati tata tertib kampus yang ditentukan oleh \nPoliteknik Negeri Batam. \n(5) Mahasiswa dilarang menggunakan fasilitas kampus untuk kegiatan yang \ntidak sesuai dengan peruntukan atau fungsinya. \n(6) Mahasiswa harus berpakaian sopan sesuai norma susila dan etika, rapi, \ndan bersih dalam mengikuti semua kegiatan di dalam kampus. \n(7) Mahasiswa dilarang membuang sampah sembarangan, merokok di area \nlarangan merokok, dan merusak fasilitas kampus. \n(8) Mahasiswa dilarang membawa, menyebarluaskan, dan mengkonsumsi \nnarkoba, dan obat psikotropika lainnya;', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(161, 13, '(9) Mahasiswa dilarang melakukan tindakan asusila, mencuri, dan tindakan \nkriminalitas lain yang melanggar hukum, norma dan etika \n \n \n \nBagian Kedua \nSanksi bagi Perilaku Yang Melanggar \n \nPasal 22 \n \n(1) Diberlakukan 4 (empat) peringkat sanksi, yaitu berupa: \na. Surat peringatan; \nb. skorsing, minimal 1 bulan, maksimal 2 semester. Selama masa \nskorsing, tidak ada penggantian layanan akademik dan pembelajaran \npada waktu lain. \nc. status kemahasiswaannya dicabut permanen. \nd. diproses kepada yang berwajib sesuai ketentuan hukum yang berlaku \n \n(2) Pelaku yang melanggar ketentuan pasal 21 dapat dikenakan sanksi \nberikut: \n \nPasal yang \ndilanggar \nSanksi yang dikenakan terhadap \nPelanggaran pertama Pelanggaran kedua Pelanggaran \nketiga \nPasal 21.4 Pasal 22.1.a Pasal 22.1.b Pasal 22.1.c \nPasal 21.5 Pasal 22.1.a Pasal 22.1.b Pasal 22.1.c \nPasal 21.6 Pasal 22.1.a Pasal 22.1.b Pasal 22.1.c \nPasal 21.7 Pasal 22.1.a Pasal 22.1.b Pasal 22.1.c \nPasal 21.8 Pasal 22.1.b Pasal 22.1.c atau d \nPasal 21.9 Pasal 22.1.b Pasal 22.1.c atau d \n \n(3) Penetapan sanksi dilakukan oleh Pembantu Direktur Bidang \nKemahasiswaan, Kerjasama dan Alumni, setelah mendapat rekomendasi \ndari Subbagian Akademik dan Kemahasiswaan dan atau Jurusan \n \n \nDitetapkan di Batam', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(162, 13, 'Lampiran \nTATA TERTIB PERPUSTAKAAN \n \n1. Pelayanan perpustakaan dibuka setiap hari kerja, dengan perincian \nsebagai berikut: \n• Senin – Kamis: pukul 08.00–22.00 WIB, Istirahat 17.00–18.30 \nWIB \n• Khusus Jum’at: pukul 09.00–22.00 WIB, Istirahat 11.30–13.30 \n& 17.00–18.30 WIB \nKetentuan tersebut berlaku sepanjang tahun akademik kecuali ada \nketentuan lain yang diumumkan melalui pengumuman tertulis \nmelalui web perpustakaan atau melalui email. \n2. Yang berha k mendapat pelayanan perpustakaan adalah anggota \nperpustakaan Politeknik Negeri Batam, dibuktikan dengan kartu \nidentitas yang masih berlaku baik Kartu Tanda Mahasiswa atau \nKartu Tanda Penduduk dan pengguna perpustakaan yang berasal \ndari luar civitas akademika Politeknik Negeri Batam. \n3. Pengunjung perpustakaan dari luar Politeknik Negeri Batam (umum) \nhanya diijinkan untuk membaca koleksi perpustakaan di tempat \ndengan memberikan kartu identitas yang masih berlaku. \n4. Pengguna jasa perpustakaan Politeknik Negeri Ba tam diharapkan \nberpakaian sopan, rapi dan tidak menggunakan sandal selama \nberada di dalam perpustakaan Politeknik Negeri Batam. \n5. Pengguna jasa perpustakaan Politeknik Negeri Batam diharapkan \ntidak makan, minum, tidur dan wajib menjaga ketenangan selama \nberada di Perpustakaan Politeknik Negeri Batam. \n6. Pengguna jasa perpustakaan Politeknik Negeri Batam tidak \ndiperkenankan membawa tas, jaket atau helm ke dalam ruangan \nperpustakaan. Semua barang tersebut harus diletakkan di tempat \nyang telah disediakan. \n7. Ketentuan jumlah buku yang dapat dipinjam dan lama peminjaman \nadalah sebagai berikut: \na) Bagi mahasiswa: \nUntuk seluruh mahasiswa, jumlah buku yang dapat dipinjam \nadalah maksimal 2 (dua) buah buku dengan masa peminjaman \nadalah 1 (satu) minggu dengan masa perpanjangan adalah 1 (satu) \nminggu. Untuk masa perpanjangan maksimal 1 (kali). \nb) Bagi Tenaga Pendidik dan Tenaga Kependidikan: \ni. Tenaga Pendidik Tetap: \na. Untuk buku yang digunakan dalam mata kuliah yang \ndiampu/diajar, jumlah buku yang dapat dipinjam \nmaksimal adalah sesuai dengan jumlah matakuliah yang \ndiampu/diajarkan dengan masa peminjaman adalah 1 \n(satu) semester dan peminjaman berakhir setelah 2 (dua) \nminggu masa Asesmen Akhir Semester (AAS).', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(163, 13, 'b. Untuk buku selain yang digunakan dalam mata kuliah \nyang diampu/diajar, j umlah buku yang dapat dipinjam \nmaksimal adalah 2 (dua) buah buku dengan masa \npeminjaman 1 (satu) minggu dengan masa perpanjangan \nadalah 1 minggu, maksimal perpanjangan pinjaman adalah \n1 (satu) kali. \nii. Tenaga Pendidik Tidak Tetap: \na. Untuk buku yang digunakan da lam mata kuliah yang \ndiajarkan, jumlah buku yang dipinjam maksimal 2 (dua) \nbuah buku dengan masa peminjaman adalah 1 (satu) \nsemester dengan persyaratan peminjaman atas nama \nDosen Pengampu; \nb. Untuk buku selain yang digunakan untuk mengajar, \njumlah buku yang dapat dipinjam maksimal adalah 2 (dua) \nbuah buku dengan masa perpanjangan adalah 1 minggu, \nmaksimal perpanjangan adalah 1 (satu) kali. \niii. Tenaga Kependidikan: \na. Jumlah buku yang dapat dipinjam adalah maksimal 2 (dua) \nbuah buku dengan masa peminjaman adalah 1 (sa tu) \nminggu dengan masa perpanjangan adalah 1 minggu, \nmasa perpanjangan adalah 1 (satu) kali. \n8. Pengguna jasa perpustakaan umum, tidak diperbolehkan melakukan \npeminjaman buku kecuali untuk difotocopy dan melalui petugas \nperpustakaan dengan jaminan kartu identitas. \n9. Masa Aktif Anggota Perpustakaan Politeknik Negeri Batam: \nMasa aktif anggota adalah selama aktif menjadi civitas akademika \nPoliteknik Negeri Batam. Anggota wajib mengembalikan buku yang \ndipinjam dari Perpustakaan Politeknik Negeri Batam 1 (satu) bula n \nmenjelang masa berakhir menjadi mahasiswa atau tenaga kerja di \nPoliteknik Negeri Batam. \n10. Pembayaran denda atas keterlambatan pengembalian pinjaman: \n11. Bagi mahasiswa, tenaga pendidik dan tenaga kependidikan akan \ndikenakan denda per buku sebesar Rp.1000,- per hari/buku. \n12. Informasi mengenai denda dan keterlambatan akan dikirimkan \nmelalui e-mail atau dapat dilihat melalui web perpustakaan. \n13. Jenis koleksi yang terdapat di Perpustakaan dengan ketentuan \nsebagai berikut: \na) Koleksi Teks, dapat dipinjam oleh anggota perpustakaan \nb) Koleksi Tandon, diberikan label merah dengan ketentuan hanya \ndapat dipinjam oleh dosen \nc) Koleksi Referensi, hanya dapat dibaca di perpustakaan \nd) Koleksi Restricted, hanya dapat dipinjam oleh dosen \ne) Karya Ilmiah Politeknik Negeri Batam, hanya dapat dibaca di \nperpustakaan \nf) Modul kuliah, hanya dapat dibaca di perpustakaan \ng) Majalah dan Surat Kabar, hanya dapat dibaca di perpustakaan \nh) Koleksi Multimedia, hanya dapat dipergunakan di perpustakaan \n14. Buku harus dikembalikan dalam keadaan utuh, tidak boleh robek, \ndicoret-coret atau menghilangkan halaman buku.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL),
(164, 13, '15. Jika pengguna menghilangkan buku, wajib membayar denda dan \nmengganti buku. Denda yang dibayar sesuai dengan denda yang \ndikenakan dan penggantian buku sesuai ketentuan sebagai berikut: \na) Buku dengan judul sama, dan atau dengan; \nb) Buku dengan edisi terbaru \n16. Peminjaman dan pengembalian buku wajib disertai dengan kartu \nidentitas yang dikeluarkan oleh Politeknik Negeri Batam yang masih \nberlaku. \n17. Pelanggaran terhadap peraturan ini akan dikenai sanksi berupa: \na) Teguran secara lisan; \nb) Surat peringatan secara tertulis; \nc) Pencabutan hak sebagai pengguna jasa perpustakaan Politeknik \nNegeri Batam.', '2026-06-04 04:26:42', '2026-06-04 04:26:42', NULL);

